# Infer the deployment directory when this file is sourced.
# This lets fit_hier_mmm() find hier_mmm.stan without requiring the user to pass stan_file.
get_hier_mmm_script_dir <- function() {
  frames <- sys.frames()
  ofiles <- vapply(frames, function(f) {
    if (!is.null(f$ofile)) as.character(f$ofile)[1] else NA_character_
  }, character(1))
  ofiles <- ofiles[!is.na(ofiles) & nzchar(ofiles)]
  if (length(ofiles)) return(dirname(normalizePath(ofiles[length(ofiles)], mustWork = FALSE)))
  getwd()
}

.hier_mmm_deploy_dir <- get_hier_mmm_script_dir()

resolve_hier_mmm_stan_file <- function(stan_file = NULL) {
  if (!is.null(stan_file) && nzchar(stan_file)) {
    stan_file <- path.expand(stan_file)
    if (!file.exists(stan_file)) stop("Stan file does not exist: ", stan_file)
    return(normalizePath(stan_file, mustWork = TRUE))
  }

  package_stan <- tryCatch({
    if (exists("econimap_stan_path", mode = "function")) {
      econimap_stan_path("hier_mmm.stan", must_work = FALSE)
    } else {
      character(0)
    }
  }, error = function(e) character(0))

  candidates <- unique(c(
    package_stan,
    file.path(.hier_mmm_deploy_dir, "hier_mmm.stan"),
    file.path(.hier_mmm_deploy_dir, "hier_mmm_v17_fourier_default.stan"),
    file.path(getwd(), "hier_mmm.stan"),
    file.path(getwd(), "hier_mmm_v17_fourier_default.stan")
  ))
  hit <- candidates[file.exists(candidates)]
  if (length(hit)) return(normalizePath(hit[1], mustWork = TRUE))

  stop(
    "Could not find a matching Stan file. Put hier_mmm.R and hier_mmm.stan in the same folder, ",
    "or pass stan_file explicitly. Checked: ", paste(candidates, collapse = "; ")
  )
}


read_input_table <- function(x) {
  if (is.null(x)) stop("Input table is NULL.")
  if (inherits(x, "data.table")) return(copy(x))
  if (is.data.frame(x)) return(as.data.table(copy(x)))

  if (is.character(x) && length(x) == 1L) {
    path <- path.expand(x)
    if (!file.exists(path)) stop("Input file does not exist: ", path)
    ext <- tolower(tools::file_ext(path))
    if (ext %in% c("csv", "txt", "tsv")) return(fread(path))
    if (ext == "rds") return(as.data.table(readRDS(path)))
    if (ext %in% c("xlsx", "xls")) {
      if (!requireNamespace("readxl", quietly = TRUE)) {
        stop("Reading Excel inputs requires the readxl package. Use CSV or install readxl.")
      }
      return(as.data.table(readxl::read_excel(path)))
    }
    stop("Unsupported input file type: .", ext)
  }

  stop("Input must be a file path, data.table, or data.frame.")
}

finite_or_stop <- function(x, label) {
  bad <- is.na(x) | !is.finite(x)
  if (any(bad)) stop(label, " contains NA/NaN/Inf values. Bad rows: ", paste(which(bad)[seq_len(min(sum(bad), 10L))], collapse = ", "))
  invisible(TRUE)
}

log_hier_mmm_checkpoint <- function(stage,
                                    status = "OK",
                                    detail = "",
                                    checkpoint_file = NULL,
                                    verbose = TRUE) {
  status <- toupper(trimws(as.character(status %||% "OK")))
  stage <- trimws(as.character(stage %||% ""))
  detail <- trimws(as.character(detail %||% ""))
  ts <- format(Sys.time(), "%Y-%m-%d %H:%M:%S")
  msg <- if (nzchar(detail)) {
    sprintf("[%s] %-7s | %s | %s", ts, status, stage, detail)
  } else {
    sprintf("[%s] %-7s | %s", ts, status, stage)
  }
  if (isTRUE(verbose)) message(msg)
  if (!is.null(checkpoint_file) && nzchar(checkpoint_file)) {
    dir.create(dirname(checkpoint_file), recursive = TRUE, showWarnings = FALSE)
    cat(paste0(msg, "\n"), file = checkpoint_file, append = TRUE)
  }
  invisible(msg)
}

validate_numeric_input_cols <- function(dt,
                                        cols,
                                        label = "model input",
                                        stop_on_zero_variance = TRUE) {
  cols <- unique(cols[cols %in% names(dt)])
  if (!length(cols)) return(invisible(TRUE))

  for (cc in cols) {
    suppressWarnings(dt[, (cc) := as.numeric(get(cc))])
    finite_or_stop(dt[[cc]], paste0(label, " column '", cc, "'"))
    s <- safe_sd(dt[[cc]])
    if (isTRUE(stop_on_zero_variance) && s <= 1e-8) {
      stop(label, " column '", cc, "' has zero/nearly-zero variance across all rows.")
    }
  }
  invisible(TRUE)
}

smooth_vector <- function(x, window = 7L) {
  x <- as.numeric(x)
  n <- length(x)
  window <- as.integer(window %||% 7L)
  if (n <= 2L || window <= 1L) return(x)
  window <- min(window, n)
  if (window %% 2L == 0L) window <- max(1L, window - 1L)
  if (window <= 1L) return(x)

  y <- as.numeric(stats::filter(x, rep(1 / window, window), sides = 2))
  good <- which(is.finite(y))
  if (!length(good)) return(rep(mean(x, na.rm = TRUE), n))
  if (length(good) < n) {
    y <- stats::approx(x = good, y = y[good], xout = seq_len(n), rule = 2)$y
  }
  y
}

clip_numeric <- function(x, lower, upper) pmin(pmax(x, lower), upper)


safe_sd <- function(x, floor = 1e-8) {
  s <- stats::sd(x, na.rm = TRUE)
  if (!is.finite(s) || is.na(s) || s < floor) floor else s
}

finite_min_or_na <- function(x) {
  x <- as.numeric(x)
  x <- x[is.finite(x)]
  if (length(x)) min(x) else NA_real_
}

finite_max_or_na <- function(x) {
  x <- as.numeric(x)
  x <- x[is.finite(x)]
  if (length(x)) max(x) else NA_real_
}

normalize_curve_type_hier_mmm <- function(x) {
  out <- tolower(trimws(as.character(x %||% "hill")))
  out[is.na(out) | !nzchar(out)] <- "hill"
  out[out %in% c("weibull_cdf", "exponential", "exp")] <- "weibull"
  out[out %in% c("hill_function", "hill_curve", "logistic_saturation")] <- "hill"
  bad <- setdiff(unique(out), c("weibull", "hill"))
  if (length(bad)) stop("Unsupported curve_type values: ", paste(bad, collapse = ", "), ". Use 'weibull' or 'hill'.")
  out
}

saturate_media_hier_mmm <- function(x, cvalue, dvalue = 1, curve_type = "hill") {
  z <- pmax(suppressWarnings(as.numeric(x)), 1e-12) * suppressWarnings(as.numeric(cvalue)[1])
  dvalue <- suppressWarnings(as.numeric(dvalue)[1])
  if (!is.finite(dvalue) || dvalue <= 0) dvalue <- 1
  curve_type <- normalize_curve_type_hier_mmm(curve_type)[1]
  pow_z <- z ^ dvalue
  if (identical(curve_type, "hill")) {
    pow_z / (1 + pow_z)
  } else {
    1 - exp(-pow_z)
  }
}

normalize_curve_normalization_scope_hier_mmm <- function(x) {
  out <- tolower(trimws(as.character(x %||% "active_train")[1]))
  if (is.na(out) || !nzchar(out)) out <- "active_train"
  out <- gsub("-", "_", out)
  out <- switch(out,
    active = "active_train",
    active_only = "active_train",
    nonzero = "active_train",
    non_zero = "active_train",
    nonzero_train = "active_train",
    active_train = "active_train",
    all = "all_train",
    train = "all_train",
    all_train = "all_train",
    stop("curve_normalization_scope must be 'active_train' or 'all_train'.", call. = FALSE)
  )
  out
}

curve_normalization_mask_hier_mmm <- function(x_ref, train_mask, scope = "active_train") {
  scope <- normalize_curve_normalization_scope_hier_mmm(scope)
  train_mask <- as.logical(train_mask)
  train_mask[is.na(train_mask)] <- FALSE
  if (!any(train_mask)) train_mask <- rep(TRUE, length(x_ref))
  if (identical(scope, "all_train")) return(train_mask)
  active <- train_mask & is.finite(x_ref) & x_ref > 0
  if (any(active)) active else train_mask
}

curve_rate_from_anchor_hier_mmm <- function(x,
                                            rrate,
                                            dvalue = 1,
                                            anchor_saturation = 0.50,
                                            curve_type = "hill",
                                            train_mask = NULL,
                                            normalize_curve_x = TRUE,
                                            curve_normalization_scope = "active_train") {
  x_ref <- pmax(suppressWarnings(as.numeric(x)), 0)
  x_ref[!is.finite(x_ref)] <- 0
  n <- length(x_ref)
  if (is.null(train_mask)) train_mask <- rep(TRUE, n)
  train_mask <- rep(as.logical(train_mask), length.out = n)
  train_mask[is.na(train_mask)] <- FALSE
  if (!any(train_mask)) train_mask <- rep(TRUE, n)
  rrate <- min(max(suppressWarnings(as.numeric(rrate)[1]), 0), 0.999)
  dvalue <- suppressWarnings(as.numeric(dvalue)[1])
  if (!is.finite(dvalue) || dvalue <= 0) dvalue <- 1
  anchor_saturation <- clip_numeric(suppressWarnings(as.numeric(anchor_saturation)[1]), 0.01, 0.99)
  if (!is.finite(anchor_saturation)) return(NA_real_)

  carry <- numeric(n)
  carry_state <- 0
  for (ii in seq_along(x_ref)) {
    carry_state <- x_ref[ii] + rrate * carry_state
    carry[ii] <- carry_state
  }
  carry_scale <- 1
  if (isTRUE(normalize_curve_x)) {
    norm_mask <- curve_normalization_mask_hier_mmm(x_ref, train_mask, curve_normalization_scope)
    carry_scale <- mean(carry[norm_mask], na.rm = TRUE)
    if (!is.finite(carry_scale) || is.na(carry_scale) || abs(carry_scale) <= 1e-8) carry_scale <- 1
  }
  z <- carry / carry_scale
  active <- train_mask & is.finite(z) & z > 0 & is.finite(x_ref) & x_ref > 0
  anchor_x <- stats::median(z[active], na.rm = TRUE)
  if (!is.finite(anchor_x) || anchor_x <= 0) return(NA_real_)

  curve_type <- normalize_curve_type_hier_mmm(curve_type)[1]
  if (identical(curve_type, "hill")) {
    (anchor_saturation / (1 - anchor_saturation)) ^ (1 / dvalue) / anchor_x
  } else {
    (-log(1 - anchor_saturation)) ^ (1 / dvalue) / anchor_x
  }
}

# Backward-compatible aliases. The returned value is the Stan internal
# saturation inverse-scale/rate, not a Hill EC/EC50 location parameter.
cvalue_from_anchor_hier_mmm <- curve_rate_from_anchor_hier_mmm
curve_location_from_anchor_hier_mmm <- curve_rate_from_anchor_hier_mmm

# 011-hier_mmm-time-holidays.R
# Generated by behavior-preserving split of hier_mmm.R.

mean_index_by_group <- function(dt, cols, by, eps = 1e-8, train_col = NULL) {
  dt <- copy(as.data.table(dt))
  cols <- unique(cols[cols %in% names(dt)])
  if (!length(cols)) return(dt)

  if (!is.null(train_col) && train_col %in% names(dt)) {
    den <- dt[get(train_col) == TRUE | get(train_col) == 1L, lapply(.SD, function(x) {
      m <- mean(x[is.finite(x)], na.rm = TRUE)
      if (!is.finite(m) || is.na(m) || abs(m) <= eps) 1 else m
    }), by = by, .SDcols = cols]
  } else {
    den <- dt[, lapply(.SD, function(x) {
      m <- mean(x[is.finite(x)], na.rm = TRUE)
      if (!is.finite(m) || is.na(m) || abs(m) <= eps) 1 else m
    }), by = by, .SDcols = cols]
  }

  den_cols <- paste0(cols, "__mi_denom")
  setnames(den, cols, den_cols)
  dt <- den[dt, on = by]

  for (i in seq_along(cols)) {
    cc <- cols[i]
    dd <- den_cols[i]
    dt[, (cc) := fifelse(abs(get(dd)) <= eps, get(cc), get(cc) / get(dd))]
    dt[, (dd) := NULL]
  }
  dt[]
}

mean_index_global_cols <- function(dt, cols, eps = 1e-8, train_col = NULL) {
  dt <- copy(as.data.table(dt))
  cols <- unique(cols[cols %in% names(dt)])
  if (!length(cols)) return(dt)
  train_mask <- rep(TRUE, nrow(dt))
  if (!is.null(train_col) && train_col %in% names(dt)) {
    train_mask <- dt[[train_col]] == TRUE | dt[[train_col]] == 1L
    train_mask[is.na(train_mask)] <- FALSE
  }
  for (cc in cols) {
    x <- dt[[cc]]
    m <- mean(x[train_mask & is.finite(x)], na.rm = TRUE)
    if (!is.finite(m) || is.na(m) || abs(m) <= eps) m <- 1
    dt[, (cc) := get(cc) / m]
  }
  dt[]
}

zscore_global_cols_hier_mmm <- function(dt, cols, eps = 1e-8, train_col = NULL) {
  dt <- copy(as.data.table(dt))
  cols <- unique(cols[cols %in% names(dt)])
  if (!length(cols)) return(list(data = dt, audit = data.table()))
  train_mask <- rep(TRUE, nrow(dt))
  if (!is.null(train_col) && train_col %in% names(dt)) {
    train_mask <- dt[[train_col]] == TRUE | dt[[train_col]] == 1L
    train_mask[is.na(train_mask)] <- FALSE
  }
  audit <- rbindlist(lapply(cols, function(cc) {
    x <- suppressWarnings(as.numeric(dt[[cc]]))
    usable <- train_mask & is.finite(x)
    center <- mean(x[usable], na.rm = TRUE)
    scale <- stats::sd(x[usable], na.rm = TRUE)
    if (!is.finite(center) || is.na(center)) center <- 0
    if (!is.finite(scale) || is.na(scale) || scale <= eps) scale <- 1
    dt[, (cc) := (suppressWarnings(as.numeric(get(cc))) - center) / scale]
    data.table(variable = cc, x_scale_center = center, x_scale_sd = scale, x_scaling = "zscore_train_global")
  }), use.names = TRUE, fill = TRUE)
  list(data = dt[], audit = audit[])
}

resolve_reference_value_hier_mmm <- function(x, spec, train_mask = NULL, label = "reference") {
  x <- suppressWarnings(as.numeric(x))
  if (is.null(train_mask)) train_mask <- rep(TRUE, length(x))
  train_mask <- rep(as.logical(train_mask), length.out = length(x))
  train_mask[is.na(train_mask)] <- FALSE
  usable <- x[train_mask & is.finite(x)]
  if (!length(usable)) stop(label, " cannot be resolved because no finite training values are available.")
  raw <- tolower(trimws(as.character(spec %||% ""))[1])
  raw <- ifelse(raw %in% c("average", "avg"), "mean", raw)
  numeric_value <- suppressWarnings(as.numeric(raw))
  if (is.finite(numeric_value)) return(list(value = numeric_value, source = "custom_numeric"))
  value <- switch(
    raw,
    min = min(usable, na.rm = TRUE),
    max = max(usable, na.rm = TRUE),
    mean = mean(usable, na.rm = TRUE),
    median = stats::median(usable, na.rm = TRUE),
    zero = 0,
    stop(label, " must be min, max, mean, median, zero, or a custom numeric value.")
  )
  list(value = as.numeric(value), source = raw)
}

build_fourier_matrix <- function(time_vec, period = 52L, harmonics = 2L) {
  n <- length(time_vec)
  period <- as.integer(period %||% 52L)
  harmonics <- as.integer(harmonics %||% 0L)
  if (n <= 0L || harmonics <= 0L || period <= 1L) return(matrix(0, n, 0))

  ord_levels <- sort(unique(time_vec))
  tt <- match(time_vec, ord_levels)
  mats <- vector("list", harmonics)
  coln <- character(2L * harmonics)

  for (k in seq_len(harmonics)) {
    ang <- 2 * pi * k * tt / period
    mats[[k]] <- cbind(sin(ang), cos(ang))
    coln[(2L * k - 1L):(2L * k)] <- c(sprintf("season_sin_%02d", k), sprintf("season_cos_%02d", k))
  }

  out <- do.call(cbind, mats)
  colnames(out) <- coln
  storage.mode(out) <- "double"
  out
}

parse_hier_mmm_dates <- function(x, label = "date") {
  if (inherits(x, "Date")) return(as.Date(x))
  if (inherits(x, "IDate")) return(as.Date(x))
  if (inherits(x, "POSIXt")) return(as.Date(x))
  if (is.numeric(x)) {
    if (all(is.na(x))) return(as.Date(rep(NA, length(x))))
    med <- stats::median(x, na.rm = TRUE)
    if (is.finite(med) && med > 30000) return(as.Date(x, origin = "1899-12-30"))
    if (is.finite(med) && med > 10000) return(as.Date(x, origin = "1970-01-01"))
  }
  out <- suppressWarnings(as.Date(x))
  if (all(is.na(out)) && length(x)) {
    stop("Could not parse ", label, " as dates for holiday control generation.", call. = FALSE)
  }
  out
}

hier_mmm_nth_weekday <- function(year, month, weekday, n) {
  d0 <- as.Date(sprintf("%04d-%02d-01", as.integer(year), as.integer(month)))
  w0 <- as.POSIXlt(d0)$wday
  d <- d0 + ((weekday - w0) %% 7L) + 7L * (as.integer(n) - 1L)
  as.Date(d)
}

hier_mmm_last_weekday <- function(year, month, weekday) {
  first_next <- if (as.integer(month) == 12L) {
    as.Date(sprintf("%04d-01-01", as.integer(year) + 1L))
  } else {
    as.Date(sprintf("%04d-%02d-01", as.integer(year), as.integer(month) + 1L))
  }
  d0 <- first_next - 1L
  w0 <- as.POSIXlt(d0)$wday
  as.Date(d0 - ((w0 - weekday) %% 7L))
}

hier_mmm_easter_date <- function(year) {
  y <- as.integer(year)
  a <- y %% 19L
  b <- y %/% 100L
  c <- y %% 100L
  d <- b %/% 4L
  e <- b %% 4L
  f <- (b + 8L) %/% 25L
  g <- (b - f + 1L) %/% 3L
  h <- (19L * a + b - d - g + 15L) %% 30L
  i <- c %/% 4L
  k <- c %% 4L
  l <- (32L + 2L * e + 2L * i - h - k) %% 7L
  m <- (a + 11L * h + 22L * l) %/% 451L
  month <- (h + l - 7L * m + 114L) %/% 31L
  day <- ((h + l - 7L * m + 114L) %% 31L) + 1L
  as.Date(sprintf("%04d-%02d-%02d", y, month, day))
}

hier_mmm_holiday_catalog <- function(calendars, years) {
  calendars <- tolower(trimws(as.character(calendars %||% "us_major")))
  calendars[is.na(calendars) | !nzchar(calendars)] <- "us_major"
  calendars[calendars %in% c("us", "usa", "united_states", "us-major")] <- "us_major"
  calendars[calendars %in% c("eu", "europe", "eu-major")] <- "eu_major"
  calendars[calendars %in% c("global", "global-major", "major")] <- "global_major"
  years <- sort(unique(as.integer(years[is.finite(years)])))
  rows <- list()
  for (cal in unique(calendars)) {
    for (yy in years) {
      if (identical(cal, "us_major")) {
        rows[[length(rows) + 1L]] <- data.table(
          calendar = cal,
          holiday_name = c(
            "new_years_day", "martin_luther_king_day", "memorial_day",
            "independence_day", "labor_day", "thanksgiving_day", "christmas_day"
          ),
          holiday_date = as.Date(c(
            sprintf("%04d-01-01", yy),
            as.character(hier_mmm_nth_weekday(yy, 1L, 1L, 3L)),
            as.character(hier_mmm_last_weekday(yy, 5L, 1L)),
            sprintf("%04d-07-04", yy),
            as.character(hier_mmm_nth_weekday(yy, 9L, 1L, 1L)),
            as.character(hier_mmm_nth_weekday(yy, 11L, 4L, 4L)),
            sprintf("%04d-12-25", yy)
          ))
        )
      } else if (identical(cal, "eu_major")) {
        easter <- hier_mmm_easter_date(yy)
        rows[[length(rows) + 1L]] <- data.table(
          calendar = cal,
          holiday_name = c("new_years_day", "easter_monday", "may_day", "christmas_day", "boxing_day"),
          holiday_date = as.Date(c(
            sprintf("%04d-01-01", yy),
            as.character(easter + 1L),
            sprintf("%04d-05-01", yy),
            sprintf("%04d-12-25", yy),
            sprintf("%04d-12-26", yy)
          ))
        )
      } else if (identical(cal, "global_major")) {
        rows[[length(rows) + 1L]] <- data.table(
          calendar = cal,
          holiday_name = c("new_years_day", "christmas_day"),
          holiday_date = as.Date(c(sprintf("%04d-01-01", yy), sprintf("%04d-12-25", yy)))
        )
      } else {
        stop("Unsupported built-in holiday calendar: ", cal,
             ". Use 'US_major', 'EU_major', 'global_major', or pass custom_holidays.", call. = FALSE)
      }
    }
  }
  if (!length(rows)) return(data.table(calendar = character(), holiday_name = character(), holiday_date = as.Date(character())))
  unique(rbindlist(rows, fill = TRUE))
}

hier_mmm_custom_holidays <- function(custom_holidays = NULL) {
  if (is.null(custom_holidays)) {
    return(data.table(calendar = character(), holiday_name = character(), holiday_date = as.Date(character())))
  }
  if (inherits(custom_holidays, "Date") || is.character(custom_holidays) || is.numeric(custom_holidays)) {
    dates <- parse_hier_mmm_dates(custom_holidays, label = "custom_holidays")
    names_in <- names(custom_holidays)
    return(data.table(
      calendar = "custom",
      holiday_name = if (!is.null(names_in) && length(names_in) == length(dates)) make.names(names_in) else paste0("custom_", seq_along(dates)),
      holiday_date = dates
    ))
  }
  ch <- as.data.table(copy(custom_holidays))
  dcol <- intersect(c("holiday_date", "date", "period", "week", "ds"), names(ch))[1]
  if (is.na(dcol)) stop("custom_holidays must include holiday_date/date/period/week/ds.", call. = FALSE)
  ncol <- intersect(c("holiday_name", "holiday", "name", "event"), names(ch))[1]
  ccol <- intersect(c("calendar", "region", "country"), names(ch))[1]
  out <- data.table(
    calendar = if (!is.na(ccol)) as.character(ch[[ccol]]) else "custom",
    holiday_name = if (!is.na(ncol)) as.character(ch[[ncol]]) else paste0("custom_", seq_len(nrow(ch))),
    holiday_date = parse_hier_mmm_dates(ch[[dcol]], label = "custom_holidays")
  )
  out[is.na(calendar) | !nzchar(calendar), calendar := "custom"]
  out[is.na(holiday_name) | !nzchar(holiday_name), holiday_name := paste0("custom_", .I)]
  unique(out[!is.na(holiday_date)])
}

normalize_holiday_config_hier_mmm <- function(holiday_config = NULL) {
  if (is.null(holiday_config) || identical(holiday_config, FALSE)) {
    return(list(enabled = FALSE))
  }
  if (identical(holiday_config, TRUE)) holiday_config <- list()
  if (!is.list(holiday_config)) stop("holiday_config must be TRUE/FALSE or a list.", call. = FALSE)
  calendars <- holiday_config$calendars %||% holiday_config$calendar %||% "US_major"
  windows <- tolower(trimws(as.character(holiday_config$windows %||% holiday_config$window %||% "week_of")))
  windows[windows %in% c("holiday", "current", "during", "week", "weekof", "same_week")] <- "week_of"
  windows[windows %in% c("before", "pre", "lead", "previous", "prior", "week-before")] <- "week_before"
  windows[windows %in% c("after", "post", "lag", "following", "next", "week-after")] <- "week_after"
  bad <- setdiff(unique(windows), c("week_before", "week_of", "week_after"))
  if (length(bad)) stop("Unsupported holiday windows: ", paste(bad, collapse = ", "),
                        ". Use week_before, week_of, and/or week_after.", call. = FALSE)
  mode <- tolower(trimws(as.character(holiday_config$mode %||% "aggregate")))[1]
  if (!mode %in% c("aggregate", "separate")) stop("holiday_config$mode must be 'aggregate' or 'separate'.", call. = FALSE)
  period_days <- suppressWarnings(as.integer(holiday_config$period_days %||% NA_integer_))[1]
  if (!is.na(period_days) && (!is.finite(period_days) || period_days <= 0L)) stop("holiday_config$period_days must be a positive integer.", call. = FALSE)
  list(
    enabled = TRUE,
    calendars = calendars,
    custom_holidays = holiday_config$custom_holidays,
    windows = unique(windows),
    mode = mode,
    prefix = as.character(holiday_config$prefix %||% "holiday")[1],
    period_days = period_days,
    include_built_in = isTRUE(holiday_config$include_built_in %||% TRUE)
  )
}

add_holiday_controls_hier_mmm <- function(data, time_col, holiday_config = NULL, existing_extra_cols = NULL) {
  cfg <- normalize_holiday_config_hier_mmm(holiday_config)
  dt <- as.data.table(copy(data))
  if (!isTRUE(cfg$enabled)) {
    return(list(data = dt, extra_control_cols = existing_extra_cols %||% character(), audit = data.table()))
  }
  if (!(time_col %in% names(dt))) stop("time_col not found for holiday controls: ", time_col, call. = FALSE)
  period_start <- parse_hier_mmm_dates(dt[[time_col]], label = time_col)
  if (anyNA(period_start)) stop("time_col contains unparseable dates for holiday controls.", call. = FALSE)
  unique_dates <- sort(unique(period_start))
  inferred_days <- if (length(unique_dates) >= 2L) {
    diffs <- as.integer(diff(unique_dates))
    diffs <- diffs[is.finite(diffs) & diffs > 0L]
    if (length(diffs)) as.integer(stats::median(diffs)) else 7L
  } else {
    7L
  }
  period_days <- cfg$period_days
  if (!is.finite(period_days) || is.na(period_days) || period_days <= 0L) period_days <- inferred_days
  period_end <- period_start + period_days - 1L
  years <- seq(
    as.integer(format(min(period_start, na.rm = TRUE) - period_days * 2L, "%Y")),
    as.integer(format(max(period_end, na.rm = TRUE) + period_days * 2L, "%Y"))
  )
  holidays <- data.table()
  if (isTRUE(cfg$include_built_in)) holidays <- hier_mmm_holiday_catalog(cfg$calendars, years)
  holidays <- rbindlist(list(holidays, hier_mmm_custom_holidays(cfg$custom_holidays)), fill = TRUE)
  holidays <- unique(holidays[!is.na(holiday_date)])
  if (!nrow(holidays)) {
    return(list(data = dt, extra_control_cols = existing_extra_cols %||% character(), audit = data.table()))
  }
  window_offsets <- c(week_before = -1L, week_of = 0L, week_after = 1L)
  make_col <- function(parts) {
    nm <- paste(parts[nzchar(parts)], collapse = "_")
    nm <- gsub("[^A-Za-z0-9_]+", "_", nm)
    nm <- gsub("_+", "_", nm)
    nm <- gsub("^_|_$", "", nm)
    if (!nzchar(nm)) nm <- "holiday_control"
    nm
  }
  add_col_safe <- function(base) {
    col <- base
    ii <- 1L
    while (col %in% names(dt)) {
      ii <- ii + 1L
      col <- paste0(base, "_", ii)
    }
    col
  }
  audit_rows <- list()
  generated_cols <- character()
  for (ww in cfg$windows) {
    offset <- window_offsets[[ww]]
    if (identical(cfg$mode, "aggregate")) {
      col <- add_col_safe(make_col(c(cfg$prefix, ww)))
      dt[, (col) := 0]
      target_dates <- holidays$holiday_date + offset * period_days
      flag <- vapply(seq_along(period_start), function(i) any(target_dates >= period_start[i] & target_dates <= period_end[i]), logical(1))
      dt[, (col) := as.numeric(flag)]
      generated_cols <- c(generated_cols, col)
      audit_rows[[length(audit_rows) + 1L]] <- data.table(
        generated_col = col,
        mode = cfg$mode,
        window = ww,
        calendar = paste(sort(unique(holidays$calendar)), collapse = "|"),
        holiday_name = "all",
        holiday_count = length(unique(holidays$holiday_date)),
        active_rows = sum(flag, na.rm = TRUE),
        period_days = period_days
      )
    } else {
      for (hh in seq_len(nrow(holidays))) {
        hname <- tolower(make.names(holidays$holiday_name[hh]))
        col <- add_col_safe(make_col(c(cfg$prefix, hname, ww)))
        target_date <- holidays$holiday_date[hh] + offset * period_days
        flag <- target_date >= period_start & target_date <= period_end
        dt[, (col) := as.numeric(flag)]
        generated_cols <- c(generated_cols, col)
        audit_rows[[length(audit_rows) + 1L]] <- data.table(
          generated_col = col,
          mode = cfg$mode,
          window = ww,
          calendar = holidays$calendar[hh],
          holiday_name = holidays$holiday_name[hh],
          holiday_count = 1L,
          active_rows = sum(flag, na.rm = TRUE),
          period_days = period_days
        )
      }
    }
  }
  audit <- rbindlist(audit_rows, fill = TRUE)
  list(
    data = dt,
    extra_control_cols = unique(c(existing_extra_cols %||% character(), generated_cols)),
    audit = audit
  )
}


parse_model_intercept <- function(intercept_type = "fourier", ucm_spec = NULL) {
  itype <- tolower(trimws(as.character(intercept_type %||% "fourier")))
  if (itype %in% c("", "na", "n/a")) itype <- "fourier"
  if (itype %in% c("seasonal", "seasonality", "fourier_season", "fourier-season", "fourier_only", "fourier-only")) itype <- "fourier"

  if (itype == "none") {
    return(list(
      label = "none",
      intercept_mode = 0L,
      use_level = 0L,
      use_season = 0L,
      use_cycle = 0L,
      season_period = NA_integer_,
      season_harmonics = 0L,
      cycle_period = NA_integer_,
      cycle_harmonics = 0L
    ))
  }

  if (itype == "flat") {
    return(list(
      label = "flat",
      intercept_mode = 1L,
      use_level = 0L,
      use_season = 0L,
      use_cycle = 0L,
      season_period = NA_integer_,
      season_harmonics = 0L,
      cycle_period = NA_integer_,
      cycle_harmonics = 0L
    ))
  }

  if (!itype %in% c("fourier", "ucm")) {
    stop("intercept_type must be one of: 'none', 'flat', 'fourier', 'ucm'.")
  }

  default_spec <- if (itype == "fourier") {
    list(
      level = FALSE,
      season = TRUE,
      cycle = FALSE,
      season_period = 52L,
      season_harmonics = 2L,
      cycle_period = 104L,
      cycle_harmonics = 1L
    )
  } else {
    list(
      level = TRUE,
      season = TRUE,
      cycle = FALSE,
      season_period = 52L,
      season_harmonics = 2L,
      cycle_period = 104L,
      cycle_harmonics = 1L
    )
  }
  spec <- modifyList(default_spec, ucm_spec %||% list())

  use_level <- isTRUE(spec$level)
  use_season <- isTRUE(spec$season)
  use_cycle <- isTRUE(spec$cycle)

  if (itype == "ucm" && !use_level) {
    stop("When intercept_type = 'ucm', ucm_spec$level must be TRUE. Use intercept_type = 'fourier' for a no-level Fourier baseline.")
  }
  if (itype == "fourier" && use_level) {
    stop("When intercept_type = 'fourier', ucm_spec$level must be FALSE. Use intercept_type = 'ucm' for a stochastic level baseline.")
  }
  if (itype == "fourier" && !use_season && !use_cycle) {
    stop("intercept_type = 'fourier' requires season = TRUE and/or cycle = TRUE.")
  }

  season_period <- as.integer(spec$season_period %||% 52L)
  season_harmonics <- as.integer(spec$season_harmonics %||% 2L)
  cycle_period <- as.integer(spec$cycle_period %||% 104L)
  cycle_harmonics <- as.integer(spec$cycle_harmonics %||% 1L)

  if (use_season) {
    if (!is.finite(season_period) || is.na(season_period) || season_period <= 1L) {
      stop("ucm_spec$season_period must be > 1 when season = TRUE.")
    }
    if (!is.finite(season_harmonics) || is.na(season_harmonics) || season_harmonics < 1L) {
      stop("ucm_spec$season_harmonics must be >= 1 when season = TRUE.")
    }
  } else {
    season_period <- NA_integer_
    season_harmonics <- 0L
  }

  if (use_cycle) {
    if (!is.finite(cycle_period) || is.na(cycle_period) || cycle_period <= 1L) {
      stop("ucm_spec$cycle_period must be > 1 when cycle = TRUE.")
    }
    if (!is.finite(cycle_harmonics) || is.na(cycle_harmonics) || cycle_harmonics < 1L) {
      stop("ucm_spec$cycle_harmonics must be >= 1 when cycle = TRUE.")
    }
  } else {
    cycle_period <- NA_integer_
    cycle_harmonics <- 0L
  }

  if (use_level) {
    label <- "level"
    if (use_season && use_cycle) {
      label <- "level+season+cycle"
    } else if (use_season) {
      label <- "level+season"
    } else if (use_cycle) {
      label <- "level+cycle"
    }
  } else {
    label <- if (use_season && use_cycle) {
      "fourier+cycle"
    } else if (use_season) {
      "fourier"
    } else {
      "cycle"
    }
  }

  list(
    label = label,
    intercept_mode = 2L,
    use_level = as.integer(use_level),
    use_season = as.integer(use_season),
    use_cycle = as.integer(use_cycle),
    season_period = season_period,
    season_harmonics = season_harmonics,
    cycle_period = cycle_period,
    cycle_harmonics = cycle_harmonics
  )
}


# 012-hier_mmm-metadata-context.R
# Generated by behavior-preserving split of hier_mmm.R.

parse_boolish <- function(x, default = FALSE) {
  if (length(x) == 0L || is.null(x) || all(is.na(x))) return(default)
  z <- tolower(trimws(as.character(x[1])))
  if (is.na(z) || !nzchar(z)) return(default)
  if (z %in% c("true", "t", "yes", "y", "1", "on")) return(TRUE)
  if (z %in% c("false", "f", "no", "n", "0", "off")) return(FALSE)
  default
}

standardize_role <- function(x) {
  x <- tolower(trimws(as.character(x)))
  x[is.na(x) | !nzchar(x)] <- "other"
  x[x %in% c("competitor", "competition", "cmp")] <- "comp"
  x[x %in% c("dist", "distro", "distribution_acv")] <- "distribution"
  x[x %in% c("consumer_promo", "promotion")] <- "promo"
  x[x %in% c("reach_frequency", "reach_freq", "rf", "reach/frequency")] <- "reach_frequency"
  x[x %in% c("control", "fixed_effect", "fixed")] <- "control"
  x[x %in% c("organic_media", "organic")] <- "organic_media"
  x[x %in% c("organic_reach_frequency", "organic_rf", "organic_reach_freq")] <- "organic_reach_frequency"
  x[x %in% c("non_media_treatment", "non_media_treatments", "nonmedia_treatment", "nonmedia_treatments")] <- "non_media_treatment"
  x
}

auto_coef_hierarchy_roles_hier_mmm <- function() {
  c("media", "reach_frequency")
}

standardize_row_type_legacy <- function(x) {
  x <- tolower(trimws(as.character(x)))
  x[is.na(x) | !nzchar(x)] <- "variable"
  x[x %in% c("x", "model_variable", "model var", "model-var", "var")] <- "variable"
  x[x %in% c("baseline", "intercept", "state", "ucm_component")] <- "ucm"
  x
}

prepare_metadata_shell <- function(raw) {
  raw <- copy(as.data.table(raw))
  if (!("variable" %in% names(raw))) return(raw)
  raw[, variable := trimws(as.character(variable))]

  if (!("row_type_legacy" %in% names(raw))) raw[, row_type_legacy := "variable"]
  raw[, row_type_legacy := standardize_row_type_legacy(row_type_legacy)]

  # User-facing metadata should use effect_type. Legacy role/variable_type/category are still accepted.
  if ("effect_type" %in% names(raw)) {
    raw[, role := effect_type]
  } else if (!("role" %in% names(raw))) {
    if ("variable_role" %in% names(raw)) {
      raw[, role := variable_role]
    } else if ("variable_type" %in% names(raw)) {
      raw[, role := variable_type]
    } else if ("category" %in% names(raw)) {
      raw[, role := category]
    } else {
      raw[, role := "other"]
    }
  }
  raw[, role := standardize_role(role)]
  raw[, effect_type := role]

  v <- tolower(trimws(as.character(raw$variable)))
  v[is.na(v)] <- ""
  legacy_ucm <- grepl("^_?ucm", v) | grepl("^__ucm", v)
  if ("role" %in% names(raw)) {
    legacy_role <- tolower(trimws(as.character(raw$role)))
    legacy_role[is.na(legacy_role)] <- ""
    legacy_ucm <- legacy_ucm | legacy_role == "ucm"
  }
  raw[legacy_ucm, row_type_legacy := "ucm"]
  raw[]
}

is_ucm_metadata_row <- function(dt) {
  if (!("variable" %in% names(dt))) return(rep(FALSE, nrow(dt)))
  shell <- prepare_metadata_shell(dt)
  role_is_ucm <- if ("role" %in% names(shell)) tolower(trimws(as.character(shell$role))) == "ucm" else rep(FALSE, nrow(shell))
  row_is_ucm <- if ("row_type_legacy" %in% names(shell)) shell$row_type_legacy == "ucm" else rep(FALSE, nrow(shell))
  role_is_ucm | row_is_ucm
}

parse_coef_bound_cell <- function(x, label = "bound", allow_pos_neg = TRUE) {
  x <- trimws(as.character(x %||% ""))
  x[is.na(x)] <- ""
  out <- data.table(
    raw_bound = x,
    lower = rep(-Inf, length(x)),
    upper = rep(Inf, length(x)),
    bound_type = rep("free", length(x))
  )

  lx <- tolower(x)
  pos <- allow_pos_neg & lx == "pos"
  neg <- allow_pos_neg & lx == "neg"
  free <- lx %in% c("", "free", "none", "na", "n/a")

  out[pos, `:=`(lower = 0, upper = Inf, bound_type = "pos")]
  out[neg, `:=`(lower = -Inf, upper = 0, bound_type = "neg")]
  out[free, `:=`(lower = -Inf, upper = Inf, bound_type = "free")]

  paren <- grepl("^\\(.*\\)$", x)
  if (any(paren)) {
    inner <- sub("^\\((.*)\\)$", "\\1", x[paren])
    parts <- strsplit(inner, ",", fixed = TRUE)

    lower <- vapply(parts, function(z) {
      z1 <- trimws(z[1])
      if (identical(z1, "") || is.na(z1)) -Inf else suppressWarnings(as.numeric(z1))
    }, numeric(1))

    upper <- vapply(parts, function(z) {
      z2 <- if (length(z) >= 2) trimws(z[2]) else ""
      if (identical(z2, "") || is.na(z2)) Inf else suppressWarnings(as.numeric(z2))
    }, numeric(1))

    bad <- is.na(lower) | is.na(upper)
    if (any(bad)) stop("Unable to parse one or more ", label, " cells.")

    bt <- ifelse(is.finite(lower) & is.finite(upper), "bounded",
                 ifelse(is.finite(lower) & !is.finite(upper), "lower",
                        ifelse(!is.finite(lower) & is.finite(upper), "upper", "free")))

    out[paren, `:=`(lower = lower, upper = upper, bound_type = bt)]
  }

  unknown <- !(free | pos | neg | paren)
  if (any(unknown)) {
    stop("Unsupported ", label, " value(s): ", paste(unique(x[unknown]), collapse = ", "),
         ". Use blank/free, pos, neg, (lower,upper), (lower,), or (,upper).")
  }

  bad_coef_bound <- out$lower > out$upper
  if (any(bad_coef_bound, na.rm = TRUE)) stop("Some ", label, " cells have lower > upper.")
  out[]
}

parse_curve_bound_cell <- function(x,
                                   default_lower,
                                   default_upper,
                                   label = "curve_bound") {
  b <- parse_coef_bound_cell(x, label = label, allow_pos_neg = TRUE)
  lower <- ifelse(is.finite(b$lower), b$lower, default_lower)
  upper <- ifelse(is.finite(b$upper), b$upper, default_upper)
  bad <- !is.finite(lower) | !is.finite(upper) | lower >= upper
  if (any(bad)) {
    stop(label, " must resolve to finite lower < upper for curve parameters.")
  }
  data.table(lower = lower, upper = upper, bound_type = b$bound_type, raw_bound = b$raw_bound)
}

extract_ucm_config_from_metadata <- function(meta_input,
                                             intercept_type = "fourier",
                                             ucm_spec = NULL,
                                             alpha_mu_prior_mean = 1,
                                             alpha_mu_prior_sd = 0.5,
                                             alpha_sd_prior_sd = 0.25,
                                             level0_mu_prior_mean = 1,
                                             level0_mu_prior_sd = 0.35,
                                             level0_sd_prior_sd = 0.15,
                                             sigma_level_prior_sd = 0.03,
                                             season_sd_prior_sd = 0.10,
                                             cycle_sd_prior_sd = 0.08,
                                             gamma_prior_sd = 0.25,
                                             sigma_y_prior_sd = 0.25) {
  raw <- read_input_table(meta_input)
  raw <- prepare_metadata_shell(raw)
  if (!("variable" %in% names(raw))) {
    return(list(
      intercept_type = intercept_type,
      ucm_spec = ucm_spec,
      alpha_mu_prior_mean = alpha_mu_prior_mean,
      alpha_mu_prior_sd = alpha_mu_prior_sd,
      alpha_sd_prior_sd = alpha_sd_prior_sd,
      level0_mu_prior_mean = level0_mu_prior_mean,
      level0_mu_prior_sd = level0_mu_prior_sd,
      level0_sd_prior_sd = level0_sd_prior_sd,
      sigma_level_prior_sd = sigma_level_prior_sd,
      season_sd_prior_sd = season_sd_prior_sd,
      cycle_sd_prior_sd = cycle_sd_prior_sd,
      gamma_prior_sd = gamma_prior_sd,
      sigma_y_prior_sd = sigma_y_prior_sd,
      ucm_metadata = data.table()
    ))
  }

  u <- copy(raw[is_ucm_metadata_row(raw)])
  if (!nrow(u)) {
    return(list(
      intercept_type = intercept_type,
      ucm_spec = ucm_spec,
      alpha_mu_prior_mean = alpha_mu_prior_mean,
      alpha_mu_prior_sd = alpha_mu_prior_sd,
      alpha_sd_prior_sd = alpha_sd_prior_sd,
      level0_mu_prior_mean = level0_mu_prior_mean,
      level0_mu_prior_sd = level0_mu_prior_sd,
      level0_sd_prior_sd = level0_sd_prior_sd,
      sigma_level_prior_sd = sigma_level_prior_sd,
      season_sd_prior_sd = season_sd_prior_sd,
      cycle_sd_prior_sd = cycle_sd_prior_sd,
      gamma_prior_sd = gamma_prior_sd,
      sigma_y_prior_sd = sigma_y_prior_sd,
      ucm_metadata = data.table()
    ))
  }

  u[, variable := tolower(trimws(as.character(variable)))]
  if (!("enabled" %in% names(u))) u[, enabled := NA]
  if (!("prior" %in% names(u))) u[, prior := NA_real_]
  if (!("precision" %in% names(u))) u[, precision := NA_real_]
  if (!("prior_sd" %in% names(u))) u[, prior_sd := NA_real_]
  if (!("period" %in% names(u))) u[, period := NA_integer_]
  if (!("harmonics" %in% names(u))) u[, harmonics := NA_integer_]

  u[, prior := suppressWarnings(as.numeric(prior))]
  u[, precision := suppressWarnings(as.numeric(precision))]
  u[, prior_sd := suppressWarnings(as.numeric(prior_sd))]
  u[, period := suppressWarnings(as.integer(period))]
  u[, harmonics := suppressWarnings(as.integer(harmonics))]

  get_row <- function(pattern) {
    idx <- grep(pattern, u$variable)
    if (length(idx)) u[idx[1]] else u[0]
  }
  get_bool <- function(pattern, default) {
    row <- get_row(pattern)
    if (!nrow(row)) return(default)
    candidates <- intersect(c("enabled", "use", "include", "value"), names(row))
    for (cc in candidates) {
      val <- row[[cc]][1]
      if (!is.na(val) && nzchar(trimws(as.character(val)))) return(parse_boolish(val, default))
    }
    default
  }
  get_num <- function(pattern, col, default) {
    row <- get_row(pattern)
    if (!nrow(row) || !(col %in% names(row))) return(default)
    val <- suppressWarnings(as.numeric(row[[col]][1]))
    if (is.finite(val) && !is.na(val)) val else default
  }
  get_prior_center <- function(pattern, default) {
    row <- get_row(pattern)
    if (!nrow(row)) return(default)
    val <- suppressWarnings(as.numeric(row$prior[1]))
    if (is.finite(val) && !is.na(val)) val else default
  }
  get_prior_sd <- function(pattern, default) {
    row <- get_row(pattern)
    if (!nrow(row)) return(default)
    val <- suppressWarnings(as.numeric(row$precision[1]))
    if (is.finite(val) && !is.na(val) && val > 0) return(1 / sqrt(val))
    val <- suppressWarnings(as.numeric(row$prior_sd[1]))
    if (is.finite(val) && !is.na(val) && val > 0) return(val)
    default
  }
  get_prior_scale <- function(pattern, default) {
    row <- get_row(pattern)
    if (!nrow(row)) return(default)
    val <- suppressWarnings(as.numeric(row$prior[1]))
    if (is.finite(val) && !is.na(val) && val > 0) return(val)
    val <- suppressWarnings(as.numeric(row$precision[1]))
    if (is.finite(val) && !is.na(val) && val > 0) return(1 / sqrt(val))
    val <- suppressWarnings(as.numeric(row$prior_sd[1]))
    if (is.finite(val) && !is.na(val) && val > 0) return(val)
    default
  }

  default_spec <- modifyList(list(
    level = TRUE,
    season = TRUE,
    cycle = FALSE,
    season_period = 52L,
    season_harmonics = 2L,
    cycle_period = 104L,
    cycle_harmonics = 1L
  ), ucm_spec %||% list())

  default_spec$level <- get_bool("^ucm_level$|^level$|level_innov|level_sigma|sigma_level", isTRUE(default_spec$level))
  default_spec$season <- get_bool("^ucm_season$|^season$|season", isTRUE(default_spec$season))
  default_spec$cycle <- get_bool("^ucm_cycle$|^cycle$|cycle", isTRUE(default_spec$cycle))
  default_spec$season_period <- as.integer(get_num("^ucm_season$|^season$|season", "period", default_spec$season_period %||% 52L))
  default_spec$season_harmonics <- as.integer(get_num("^ucm_season$|^season$|season", "harmonics", default_spec$season_harmonics %||% 2L))
  default_spec$cycle_period <- as.integer(get_num("^ucm_cycle$|^cycle$|cycle", "period", default_spec$cycle_period %||% 104L))
  default_spec$cycle_harmonics <- as.integer(get_num("^ucm_cycle$|^cycle$|cycle", "harmonics", default_spec$cycle_harmonics %||% 1L))

  level0_mu_prior_mean <- get_prior_center("^ucm_level0$|^level0$|initial", level0_mu_prior_mean)
  level0_mu_prior_sd <- get_prior_sd("^ucm_level0$|^level0$|initial", level0_mu_prior_sd)
  level0_sd_prior_sd <- get_prior_scale("^ucm_group_level$|^group_level$|level_group|level_sd|level0_sd", level0_sd_prior_sd)
  sigma_level_prior_sd <- get_prior_scale("^ucm_level$|^level$|level_innov|level_sigma|sigma_level", sigma_level_prior_sd)

  season_sd_prior_sd <- get_prior_scale("^ucm_season$|^season$|season", season_sd_prior_sd)
  cycle_sd_prior_sd <- get_prior_scale("^ucm_cycle$|^cycle$|cycle", cycle_sd_prior_sd)

  alpha_mu_prior_mean <- get_prior_center("^ucm_flat$|^flat$|alpha", alpha_mu_prior_mean)
  alpha_mu_prior_sd <- get_prior_sd("^ucm_flat$|^flat$|alpha", alpha_mu_prior_sd)
  alpha_sd_prior_sd <- get_prior_scale("^ucm_alpha_group$|alpha_group|flat_group", alpha_sd_prior_sd)

  sigma_y_prior_sd <- get_prior_scale("^ucm_noise$|^noise$|sigma_y|residual", sigma_y_prior_sd)
  gamma_prior_sd <- get_prior_scale("^ucm_gamma$|gamma|extra_control", gamma_prior_sd)

  list(
    intercept_type = "ucm",
    ucm_spec = default_spec,
    alpha_mu_prior_mean = alpha_mu_prior_mean,
    alpha_mu_prior_sd = alpha_mu_prior_sd,
    alpha_sd_prior_sd = alpha_sd_prior_sd,
    level0_mu_prior_mean = level0_mu_prior_mean,
    level0_mu_prior_sd = level0_mu_prior_sd,
    level0_sd_prior_sd = level0_sd_prior_sd,
    sigma_level_prior_sd = sigma_level_prior_sd,
    season_sd_prior_sd = season_sd_prior_sd,
    cycle_sd_prior_sd = cycle_sd_prior_sd,
    gamma_prior_sd = gamma_prior_sd,
    sigma_y_prior_sd = sigma_y_prior_sd,
    ucm_metadata = u
  )
}
normalize_source_entity <- function(x) {
  x <- trimws(as.character(x))
  x[is.na(x)] <- ""
  lx <- tolower(x)
  global_like <- lx %in% c("", "na", "n/a", "0", "global", "globale")
  x[global_like] <- "GLOBAL"
  x
}

normalize_coef_hierarchy_scope <- function(x) {
  x <- trimws(tolower(as.character(x)))
  x[is.na(x) | !nzchar(x)] <- "auto"
  x <- gsub("-", "_", x)
  x <- gsub("\\s+", "_", x)
  out <- x
  out[x %in% c("default", "automatic", "auto_global", "auto_all")] <- "auto"
  out[x %in% c("all", "global", "across_all", "all_groups", "shared")] <- "global"
  out[x %in% c("none", "no", "false", "fixed", "local", "within_group", "no_hierarchy", "off")] <- "none"
  out[x %in% c("key", "keyed", "family", "pooling_key", "hier_key", "within_key", "within_family")] <- "keyed"
  bad <- setdiff(unique(out), c("auto", "global", "none", "keyed"))
  if (length(bad)) {
    stop("Unsupported coef_hierarchy_scope values: ", paste(bad, collapse = ", "),
         ". Use auto, global, none, or keyed.", call. = FALSE)
  }
  out
}

normalize_hierarchy_key <- function(x) {
  x <- trimws(as.character(x))
  x[is.na(x) | !nzchar(x) | tolower(x) %in% c("na", "n/a", "none", "0")] <- NA_character_
  x
}

parse_hierarchy_part_indices <- function(x, index_base = c("one", "zero")) {
  index_base <- match.arg(index_base)
  raw <- trimws(as.character(x %||% ""))
  if (is.na(raw) || !nzchar(raw)) return(integer())
  toks <- unlist(strsplit(raw, "[,;| ]+", perl = TRUE), use.names = FALSE)
  toks <- trimws(toks)
  toks <- toks[nzchar(toks)]
  idx <- suppressWarnings(as.integer(toks))
  if (!length(idx) || anyNA(idx)) {
    stop("hierarchy_part_indices must be integer positions such as '3' or '1,3'. ",
         "Use R-style one-based positions by default, e.g. 1 = first part, 2 = second part, 3 = third part.",
         call. = FALSE)
  }
  if (any(idx < 0L)) stop("hierarchy_part_indices cannot contain negative positions.", call. = FALSE)
  if (identical(index_base, "zero")) idx <- idx + 1L
  if (identical(index_base, "one") && any(idx < 1L)) {
    stop("hierarchy_part_indices must be >= 1 when hierarchy index base is 'one'.", call. = FALSE)
  }
  unique(idx)
}

split_model_id_parts_hier_mmm <- function(x) {
  x <- trimws(as.character(x %||% ""))
  if (is.na(x) || !nzchar(x)) return(character())
  parts <- unlist(strsplit(x, "[_|/:;]+", perl = TRUE), use.names = FALSE)
  parts <- trimws(parts)
  parts[nzchar(parts)]
}

build_coef_hierarchy_key_map <- function(group_lookup,
                                         variable_lookup,
                                         hierarchy_part_indices = NULL,
                                         hierarchy_index_base = c("one", "zero")) {
  hierarchy_index_base <- match.arg(hierarchy_index_base)
  n_g <- nrow(group_lookup)
  n_j <- nrow(variable_lookup)
  key_lookup <- data.table(coef_hierarchy_key_id = 1L, coef_hierarchy_key_value = "GLOBAL")
  group_key_id <- matrix(1L, nrow = n_g, ncol = n_j)
  variable_key_audit <- data.table(
    variable = as.character(variable_lookup$variable),
    keyed_family_count = NA_integer_,
    hierarchy_part_indices_effective = NA_character_,
    keyed_single_family = FALSE
  )
  keyed <- variable_lookup[coef_hierarchy_scope == "keyed" & coef_hierarchy_scale > 0]
  if (!nrow(keyed)) {
    return(list(
      key_lookup = key_lookup[],
      group_key_id = group_key_id,
      group_lookup = copy(group_lookup),
      variable_key_audit = variable_key_audit[],
      active = FALSE,
      note = "No active keyed coefficient hierarchy requested."
    ))
  }
  default_idx_value <- if (!is.null(hierarchy_part_indices) && length(hierarchy_part_indices)) {
    paste(as.character(hierarchy_part_indices), collapse = ",")
  } else {
    NA_character_
  }
  group_values <- as.character(group_lookup$group_value)
  for (ii in seq_len(nrow(keyed))) {
    v <- keyed$variable[ii]
    j <- match(v, variable_lookup$variable)
    idx_value <- trimws(as.character(keyed$hierarchy_part_indices[ii] %||% ""))
    if (is.na(idx_value) || !nzchar(idx_value)) idx_value <- default_idx_value
    if (is.na(idx_value) || !nzchar(idx_value)) {
      stop("coef_hierarchy_scope = 'keyed' for variable '", v,
           "' requires one-time coef_hierarchy_part_indices or metadata hierarchy_part_indices. ",
           "Example with one-based indexing: coef_hierarchy_part_indices = 3 pools groups sharing the third group/model-id part.",
           call. = FALSE)
    }
    part_idx <- parse_hierarchy_part_indices(idx_value, index_base = hierarchy_index_base)
    labels <- vapply(group_values, function(gv) {
      parts <- split_model_id_parts_hier_mmm(gv)
      if (!length(parts) || max(part_idx) > length(parts)) {
        stop("Could not derive keyed hierarchy family for variable '", v,
             "' from group value '", gv,
             "' using hierarchy_part_indices = '", idx_value,
             "'. Group IDs must contain enough separator-delimited parts, e.g. product_dma_retailer.",
             call. = FALSE)
      }
      paste(parts[part_idx], collapse = "|")
    }, character(1))
    fam <- unique(labels)
    variable_key_audit[variable == v, `:=`(
      keyed_family_count = length(fam),
      hierarchy_part_indices_effective = idx_value,
      keyed_single_family = length(fam) <= 1L
    )]
    if (length(fam) <= 1L) next
    missing_labels <- setdiff(fam, key_lookup$coef_hierarchy_key_value)
    if (length(missing_labels)) {
      add <- data.table(coef_hierarchy_key_value = missing_labels)
      key_lookup <- rbind(key_lookup, add, fill = TRUE)
      key_lookup[, coef_hierarchy_key_id := .I]
      setcolorder(key_lookup, c("coef_hierarchy_key_id", "coef_hierarchy_key_value"))
    }
    group_key_id[, j] <- match(labels, key_lookup$coef_hierarchy_key_value)
  }
  list(
    key_lookup = key_lookup[],
    group_key_id = group_key_id,
    group_lookup = copy(group_lookup),
    variable_key_audit = variable_key_audit[],
    active = TRUE,
    note = paste0(
      "Active keyed coefficient hierarchy using ",
      hierarchy_index_base,
      "-based group/model-id part index(es), with metadata overrides allowed per variable."
    )
  )
}

inv_logit_bounded <- function(x, lower, upper, eps = 1e-6) {
  p <- (x - lower) / (upper - lower)
  p <- pmin(pmax(p, eps), 1 - eps)
  qlogis(p)
}

raw_sd_from_original_sd <- function(mu, sd, lower, upper, floor = 0.15, cap = 2.5) {
  width <- pmax(upper - lower, 1e-6)
  p <- pmin(pmax((mu - lower) / width, 1e-4), 1 - 1e-4)
  deriv <- width * p * (1 - p)
  out <- sd / deriv
  out[!is.finite(out) | is.na(out)] <- floor
  pmin(pmax(out, floor), cap)
}

lognormal_from_mean_sd <- function(mean_abs, sd_abs, eps = 1e-6) {
  m <- pmax(abs(mean_abs), eps)
  s <- pmax(sd_abs, eps)
  sigma2 <- log1p((s^2) / (m^2))
  sdlog <- sqrt(sigma2)
  meanlog <- log(m) - 0.5 * sigma2
  list(meanlog = meanlog, sdlog = sdlog)
}

softplus <- function(x) ifelse(x > 30, x, log1p(exp(x)))

softplus_inv <- function(y, eps = 1e-8) {
  y <- pmax(as.numeric(y), eps)
  ifelse(y > 30, y, log(expm1(y)))
}

softplus_from_mean_sd <- function(mean_abs, sd_abs, floor = 0.05, cap = 2.5, eps = 1e-6) {
  m <- pmax(abs(mean_abs), eps)
  s <- pmax(as.numeric(sd_abs), eps)
  raw_mu <- softplus_inv(m, eps = eps)
  deriv <- plogis(raw_mu)
  raw_sd <- s / pmax(deriv, 1e-4)
  raw_sd[!is.finite(raw_sd) | is.na(raw_sd)] <- floor
  list(raw_mu = raw_mu, raw_sd = pmin(pmax(raw_sd, floor), cap))
}

clip_to_open_interval <- function(x, lower, upper, eps_frac = 1e-4) {
  width <- pmax(upper - lower, 1e-8)
  eps <- width * eps_frac
  pmin(pmax(x, lower + eps), upper - eps)
}

pick_first_existing_col <- function(dt, candidates) {
  hit <- intersect(candidates, names(dt))
  if (length(hit)) hit[1] else NA_character_
}

summarize_fit_vars <- function(fit, variables = NULL) {
  require_hier_mmm_pkg("posterior", "summarizing Stan posterior draws")
  out <- tryCatch(
    as.data.table(fit$summary(variables = variables)),
    error = function(e) as.data.table(fit$summary())
  )
  out[]
}

validate_prior_scales <- function(stan_data, verbose = TRUE) {
  all_sds <- c(
    stan_data$coef_sd_pos_log, stan_data$coef_sd_neg_log,
    stan_data$coef_sd_lower_log, stan_data$coef_sd_upper_log,
    stan_data$coef_raw_sd_bounded, stan_data$coef_sd_free,
    stan_data$rrate_raw_sd, stan_data$cvalue_raw_sd, stan_data$observed_cvalue_raw_sd,
    stan_data$dvalue_raw_sd
  )
  all_sds <- all_sds[is.finite(all_sds)]
  if (length(all_sds) && any(all_sds < 1e-4) && isTRUE(verbose)) {
    warning("One or more prior SDs are < 1e-4. Check coef_precision / curve precision values in metadata.")
  }
  if (length(all_sds) && any(all_sds > 50) && isTRUE(verbose)) {
    warning("One or more prior SDs are > 50. Priors may be effectively uninformative; check metadata.")
  }
  invisible(TRUE)
}

safe_cor <- function(x, y) {
  ok <- is.finite(x) & is.finite(y)
  if (sum(ok) < 3L) return(NA_real_)
  sx <- safe_sd(x[ok])
  sy <- safe_sd(y[ok])
  if (sx <= 1e-8 || sy <= 1e-8) return(NA_real_)
  suppressWarnings(stats::cor(x[ok], y[ok]))
}


clean_metadata <- function(meta_input,
                           bound_one_sided_coef_defaults = TRUE,
                           default_positive_coef_upper = 3,
                           default_negative_coef_lower = -3,
                           default_one_sided_coef_span = 6,
                           curve_type_default = c("hill", "weibull")) {
  curve_type_default <- match.arg(curve_type_default)
  raw <- read_input_table(meta_input)
  if (!("variable" %in% names(raw))) stop("Metadata is missing required column: variable")
  raw <- prepare_metadata_shell(raw)

  dt <- copy(raw[!is_ucm_metadata_row(raw)])
  if (!nrow(dt)) stop("Metadata contains no model variable rows after removing UCM configuration rows.")

  if (!("source_entity" %in% names(dt))) dt[, source_entity := "GLOBAL"]
  # Accept handoff aliases from the semi-univariate prior builder. `cvalue` is
  # Stan's internal generic inverse-scale/rate parameter for either Weibull or
  # Hill. Do not map EC50/curve-location columns directly to it; those are
  # locations on the curve-input scale and need an explicit conversion.
  alias_map <- list(
    coef = c("coef_prior_final", "coef_prior"),
    coef_precision = c("coef_precision_final"),
    cvalue = c("curve_rate", "saturation_rate", "curve_inverse_scale", "saturation_inverse_scale"),
    rrate_precision = c("rrate_precision_final"),
    cvalue_precision = c("cvalue_precision_final", "curve_rate_precision", "saturation_rate_precision", "curve_inverse_scale_precision", "saturation_inverse_scale_precision"),
    dvalue_precision = c("dvalue_precision_final")
  )
  for (target_nm in names(alias_map)) {
    if (!(target_nm %in% names(dt))) {
      hit <- alias_map[[target_nm]][alias_map[[target_nm]] %in% names(dt)]
      if (length(hit)) dt[, (target_nm) := get(hit[1])]
    }
  }
  supplied_rrate__ <- "rrate" %in% names(dt)
  supplied_rrate_precision__ <- "rrate_precision" %in% names(dt)
  supplied_cvalue__ <- "cvalue" %in% names(dt)
  supplied_cvalue_precision__ <- "cvalue_precision" %in% names(dt)
  supplied_dvalue__ <- "dvalue" %in% names(dt)
  supplied_dvalue_precision__ <- "dvalue_precision" %in% names(dt)
  if (!("coef_bound" %in% names(dt))) {
    if ("bounds" %in% names(dt)) dt[, coef_bound := bounds] else dt[, coef_bound := ""]
  }
  if (!("curve_bound" %in% names(dt))) dt[, curve_bound := ""]
  if (!("curve_type" %in% names(dt))) dt[, curve_type := curve_type_default]
  dt[is.na(curve_type) | !nzchar(trimws(as.character(curve_type))), curve_type := curve_type_default]
  dt[, curve_type := normalize_curve_type_hier_mmm(curve_type)]
  if (!"cvalue_bound" %in% names(dt)) {
    hit <- intersect(c("curve_rate_bound", "saturation_rate_bound", "curve_inverse_scale_bound", "saturation_inverse_scale_bound"), names(dt))
    if (length(hit)) dt[, cvalue_bound := get(hit[1])]
  }
  for (nm in c("rrate_bound", "cvalue_bound", "dvalue_bound")) {
    if (!(nm %in% names(dt))) dt[, (nm) := ""]
  }
  anchor_aliases <- c(
    "anchor_saturation_handoff", "anchor_saturation", "median_anchor_saturation",
    "median_anchor", "saturation_at_median", "saturation_at_anchor"
  )
  if (!"anchor_saturation" %in% names(dt)) dt[, anchor_saturation := NA_real_]
  for (aa in anchor_aliases) {
    if (aa %in% names(dt)) {
      z <- suppressWarnings(as.numeric(dt[[aa]]))
      hit <- is.finite(z) & (!is.finite(suppressWarnings(as.numeric(dt$anchor_saturation))) | is.na(suppressWarnings(as.numeric(dt$anchor_saturation))))
      dt[hit, anchor_saturation := z[hit]]
    }
  }
  dt[, anchor_saturation := suppressWarnings(as.numeric(anchor_saturation))]
  dt[is.finite(anchor_saturation), anchor_saturation := clip_numeric(anchor_saturation, 0.01, 0.99)]
  if (!"anchor_saturation_sd" %in% names(dt)) dt[, anchor_saturation_sd := NA_real_]
  if (!"anchor_saturation_precision" %in% names(dt)) dt[, anchor_saturation_precision := NA_real_]
  dt[, `:=`(
    anchor_saturation_sd = suppressWarnings(as.numeric(anchor_saturation_sd)),
    anchor_saturation_precision = suppressWarnings(as.numeric(anchor_saturation_precision))
  )]
  dt[(!is.finite(anchor_saturation_sd) | anchor_saturation_sd <= 0) &
       is.finite(anchor_saturation_precision) & anchor_saturation_precision > 0,
     anchor_saturation_sd := 1 / sqrt(anchor_saturation_precision)]
  dt[is.finite(anchor_saturation_sd) & anchor_saturation_sd > 0,
     anchor_saturation_precision := 1 / anchor_saturation_sd^2]
  supplied_anchor_row__ <- is.finite(dt$anchor_saturation)
  if (!"anchor_source" %in% names(dt)) dt[, anchor_source := NA_character_]
  if (!"cvalue_from_anchor" %in% names(dt)) dt[, cvalue_from_anchor := FALSE]
  explicit_no_curve__ <- if ("has_curve" %in% names(dt)) {
    suppressWarnings(as.integer(dt$has_curve)) == 0L
  } else {
    rep(FALSE, nrow(dt))
  }
  default_anchor_rows__ <- dt$role %in% c("media", "reach_frequency", "organic_reach_frequency") &
    !supplied_anchor_row__ &
    !isTRUE(supplied_cvalue__) &
    !explicit_no_curve__
  if (any(default_anchor_rows__, na.rm = TRUE)) {
    dt[default_anchor_rows__, `:=`(
      anchor_saturation = 0.50,
      anchor_source = fifelse(is.na(anchor_source) | !nzchar(anchor_source), "default_median_active_50_saturation", anchor_source)
    )]
  }
  has_anchor__ <- is.finite(dt$anchor_saturation)
  if (!"rrate" %in% names(dt)) dt[, rrate := 0]
  if (!"rrate_precision" %in% names(dt)) dt[, rrate_precision := 1]
  if (!"cvalue" %in% names(dt)) dt[, cvalue := fifelse(has_anchor__, NA_real_, 0)]
  if (!"cvalue_precision" %in% names(dt)) dt[, cvalue_precision := 1]
  cvalue_numeric__ <- suppressWarnings(as.numeric(dt$cvalue))
  if (!"dvalue" %in% names(dt)) dt[, dvalue := fifelse(has_anchor__ | (is.finite(cvalue_numeric__) & cvalue_numeric__ > 0), 1, 0)]
  if (!"dvalue_precision" %in% names(dt)) dt[, dvalue_precision := 1]
  dt[, `:=`(
    rrate_defaulted = !isTRUE(supplied_rrate__),
    rrate_precision_defaulted = !isTRUE(supplied_rrate_precision__),
    cvalue_defaulted_from_anchor = has_anchor__ & !isTRUE(supplied_cvalue__),
    cvalue_precision_defaulted = !isTRUE(supplied_cvalue_precision__),
    dvalue_defaulted = !isTRUE(supplied_dvalue__),
    dvalue_precision_defaulted = !isTRUE(supplied_dvalue_precision__)
  )]

  req <- c(
    "variable", "source_entity",
    "rrate", "rrate_precision",
    "cvalue", "cvalue_precision",
    "dvalue", "dvalue_precision",
    "coef", "coef_precision",
    "coef_bound"
  )
  miss <- setdiff(req, names(dt))
  if (length(miss)) stop("Metadata is missing required model-variable columns: ", paste(miss, collapse = ", "))

  if (any(!nzchar(dt$variable))) stop("Metadata contains blank model variable names.")
  if (anyDuplicated(dt$variable)) stop("Metadata must have exactly one model row per variable. Duplicates found.")

  dt[, source_entity := normalize_source_entity(source_entity)]
  dt[, role := standardize_role(role)]
  dt[, effect_type := role]
  if (!"non_media_baseline_values" %in% names(dt)) {
    baseline_col <- pick_first_existing_col(dt, c("non_media_baseline_value", "non_media_baseline", "counterfactual_reference", "counterfactual_value"))
    dt[, non_media_baseline_values := if (!is.na(baseline_col)) as.character(get(baseline_col)) else NA_character_]
  }
  if (!"control_reference_values" %in% names(dt)) {
    control_ref_col <- pick_first_existing_col(dt, c("control_reference_value", "control_reference", "reporting_reference"))
    dt[, control_reference_values := if (!is.na(control_ref_col)) as.character(get(control_ref_col)) else NA_character_]
  }
  dt[, `:=`(
    non_media_baseline_values = trimws(as.character(non_media_baseline_values)),
    control_reference_values = trimws(as.character(control_reference_values))
  )]
  dt[role == "non_media_treatment" & (is.na(non_media_baseline_values) | !nzchar(non_media_baseline_values)), non_media_baseline_values := "min"]
  dt[role == "control" & (is.na(control_reference_values) | !nzchar(control_reference_values)), control_reference_values := "mean"]
  dt[, reference_value_spec := fifelse(
    role == "non_media_treatment", non_media_baseline_values,
    fifelse(role == "control", control_reference_values, NA_character_)
  )]
  valid_reference <- function(z) {
    if (is.na(z) || !nzchar(z)) return(TRUE)
    key <- tolower(trimws(z))
    key %in% c("min", "max", "mean", "average", "avg", "median", "zero") || is.finite(suppressWarnings(as.numeric(key)))
  }
  bad_reference <- !vapply(dt$reference_value_spec, valid_reference, logical(1))
  if (any(bad_reference)) {
    stop("Invalid non-media/control reference value(s) for: ", paste(dt$variable[bad_reference], collapse = ", "),
         ". Use min, max, mean, median, zero, or a custom numeric value.")
  }
  rf_aliases <- list(
    reach_col = c("reach_column", "unique_reach_col", "rf_reach_col"),
    frequency_col = c("frequency_column", "avg_frequency_col", "average_frequency_col", "rf_frequency_col"),
    population_col = c("population_column", "market_size_col", "rf_population_col"),
    rf_spend_col = c("reach_frequency_spend_col", "cost_col", "spend_col")
  )
  for (target_nm in names(rf_aliases)) {
    if (!(target_nm %in% names(dt))) {
      hit <- rf_aliases[[target_nm]][rf_aliases[[target_nm]] %in% names(dt)]
      dt[, (target_nm) := if (length(hit)) as.character(get(hit[1])) else NA_character_]
    }
    dt[, (target_nm) := trimws(as.character(get(target_nm)))]
    dt[is.na(get(target_nm)) | !nzchar(get(target_nm)), (target_nm) := NA_character_]
  }
  rf_role__ <- dt$role %in% c("reach_frequency", "organic_reach_frequency")
  dt[rf_role__ & is.na(reach_col), reach_col := variable]
  if (dt[rf_role__, any(is.na(frequency_col))]) {
    bad_rf <- dt[rf_role__ & is.na(frequency_col), variable]
    stop("reach_frequency metadata rows must provide frequency_col. Missing for: ", paste(bad_rf, collapse = ", "))
  }
  # Reach/frequency uses a Hill response over average frequency. Reach remains
  # linear before the effective-media signal is adstocked.
  dt[rf_role__, curve_type := "hill"]
  if (!"coef_hierarchy_scope" %in% names(dt)) {
    scope_col <- pick_first_existing_col(dt, c("hierarchy_scope", "hier_scope", "pooling_scope", "coef_pooling_scope"))
    if (!is.na(scope_col)) dt[, coef_hierarchy_scope := get(scope_col)] else dt[, coef_hierarchy_scope := "auto"]
  }
  if (!"hierarchy_key" %in% names(dt)) {
    key_col <- pick_first_existing_col(dt, c("hier_key", "pooling_key", "hierarchy_family", "pooling_family", "coef_hierarchy_key"))
    if (!is.na(key_col)) dt[, hierarchy_key := get(key_col)] else dt[, hierarchy_key := NA_character_]
  }
  if (!"model_id_parts" %in% names(dt)) dt[, model_id_parts := NA_character_]
  if (!"hierarchy_part_indices" %in% names(dt)) {
    idx_col <- pick_first_existing_col(dt, c("hier_part_indices", "pooling_part_indices", "hierarchy_parts", "pooling_parts"))
    if (!is.na(idx_col)) dt[, hierarchy_part_indices := get(idx_col)] else dt[, hierarchy_part_indices := NA_character_]
  }
  dt[, `:=`(
    coef_hierarchy_scope = normalize_coef_hierarchy_scope(coef_hierarchy_scope),
    hierarchy_key = normalize_hierarchy_key(hierarchy_key),
    model_id_parts = as.character(model_id_parts),
    hierarchy_part_indices = as.character(hierarchy_part_indices)
  )]
  dt[is.na(model_id_parts) | !nzchar(model_id_parts), model_id_parts := NA_character_]
  dt[is.na(hierarchy_part_indices) | !nzchar(hierarchy_part_indices), hierarchy_part_indices := NA_character_]

  num_cols <- c(
    "rrate", "rrate_precision",
    "cvalue", "cvalue_precision",
    "dvalue", "dvalue_precision",
    "coef", "coef_precision"
  )
  legacy_num_cols <- intersect(
    c("rrate_lower", "rrate_upper", "cvalue_lower", "cvalue_upper", "dvalue_lower", "dvalue_upper"),
    names(dt)
  )
  for (nm in c(num_cols, legacy_num_cols)) dt[, (nm) := suppressWarnings(as.numeric(get(nm)))]
  cvalue_missing <- (!is.finite(dt$cvalue) | is.na(dt$cvalue) | dt$cvalue <= 0) & is.finite(dt$anchor_saturation)
  if (any(cvalue_missing)) {
    dt[cvalue_missing, `:=`(
      cvalue = 1,
      cvalue_from_anchor = TRUE,
      anchor_source = fifelse(is.na(anchor_source) | !nzchar(anchor_source), "direct_metadata_anchor", anchor_source)
    )]
  }
  if (anyNA(dt[, ..num_cols])) stop("Metadata contains NA/non-numeric values in required numeric model-variable columns.")
  if (!"coef_hierarchy_scale" %in% names(dt)) dt[, coef_hierarchy_scale := 1]
  dt[, coef_hierarchy_scale := suppressWarnings(as.numeric(coef_hierarchy_scale))]
  dt[!is.finite(coef_hierarchy_scale) | is.na(coef_hierarchy_scale) | coef_hierarchy_scale < 0, coef_hierarchy_scale := 1]
  dt[, coef_hierarchy_scale := clip_numeric(coef_hierarchy_scale, 0, 5)]
  dt[coef_hierarchy_scope == "none", coef_hierarchy_scale := 0]
  dt[, hierarchy_note := data.table::fifelse(
    coef_hierarchy_scope == "keyed",
    "Eligible for single-level keyed coefficient pooling when hierarchy_part_indices can map group/model IDs to pooling families.",
    data.table::fifelse(
      coef_hierarchy_scope == "none",
      "Group coefficient hierarchy disabled for this variable.",
      "Eligible for the current global group coefficient hierarchy subject to sample_coef_hierarchy and geo-variation gates."
    )
  )]

  dt[, has_curve := as.integer(!(rrate == 0 & cvalue == 0 & dvalue == 0))]

  cb <- parse_coef_bound_cell(dt$coef_bound, label = "coef_bound", allow_pos_neg = TRUE)
  dt[, `:=`(
    bound_type = cb$bound_type,
    coef_lower = cb$lower,
    coef_upper = cb$upper
  )]

  dt[coef_precision <= 0 | !is.finite(coef_precision), coef_precision := 1]
  dt[rrate_precision <= 0 | !is.finite(rrate_precision), rrate_precision := 1]
  dt[cvalue_precision <= 0 | !is.finite(cvalue_precision), cvalue_precision := 1]
  dt[dvalue_precision <= 0 | !is.finite(dvalue_precision), dvalue_precision := 1]

  default_positive_coef_upper <- as.numeric(default_positive_coef_upper)[1]
  default_negative_coef_lower <- as.numeric(default_negative_coef_lower)[1]
  default_one_sided_coef_span <- as.numeric(default_one_sided_coef_span)[1]
  if (!is.finite(default_positive_coef_upper) || default_positive_coef_upper <= 0) default_positive_coef_upper <- 3
  if (!is.finite(default_negative_coef_lower) || default_negative_coef_lower >= 0) default_negative_coef_lower <- -3
  if (!is.finite(default_one_sided_coef_span) || default_one_sided_coef_span <= 0) default_one_sided_coef_span <- 6
  dt[, coef_default_bound_applied := FALSE]
  if (isTRUE(bound_one_sided_coef_defaults)) {
    coef_nominal_sd__ <- sqrt(1 / pmax(dt$coef_precision, 1e-8))
    pos_hit <- dt$bound_type == "pos" & !is.finite(dt$coef_upper)
    if (any(pos_hit)) {
      upper <- pmax(default_positive_coef_upper, dt$coef[pos_hit] + 6 * coef_nominal_sd__[pos_hit], abs(dt$coef[pos_hit]) * 4)
      dt[pos_hit, `:=`(bound_type = "bounded", coef_lower = 0, coef_upper = upper, coef_default_bound_applied = TRUE)]
    }
    neg_hit <- dt$bound_type == "neg" & !is.finite(dt$coef_lower)
    if (any(neg_hit)) {
      lower <- pmin(default_negative_coef_lower, dt$coef[neg_hit] - 6 * coef_nominal_sd__[neg_hit], -abs(dt$coef[neg_hit]) * 4)
      dt[neg_hit, `:=`(bound_type = "bounded", coef_lower = lower, coef_upper = 0, coef_default_bound_applied = TRUE)]
    }
    lower_hit <- dt$bound_type == "lower" & !is.finite(dt$coef_upper)
    if (any(lower_hit)) {
      upper <- pmax(dt$coef_lower[lower_hit] + default_one_sided_coef_span, dt$coef[lower_hit] + 6 * coef_nominal_sd__[lower_hit])
      dt[lower_hit, `:=`(bound_type = "bounded", coef_upper = upper, coef_default_bound_applied = TRUE)]
    }
    upper_hit <- dt$bound_type == "upper" & !is.finite(dt$coef_lower)
    if (any(upper_hit)) {
      lower <- pmin(dt$coef_upper[upper_hit] - default_one_sided_coef_span, dt$coef[upper_hit] - 6 * coef_nominal_sd__[upper_hit])
      dt[upper_hit, `:=`(bound_type = "bounded", coef_lower = lower, coef_default_bound_applied = TRUE)]
    }
  }

  n <- nrow(dt)
  get_default <- function(lower_col, upper_col, lower_default, upper_default) {
    lo <- rep(lower_default, n)
    hi <- rep(upper_default, n)
    if (lower_col %in% names(dt)) {
      z <- suppressWarnings(as.numeric(dt[[lower_col]]))
      lo[is.finite(z)] <- z[is.finite(z)]
    }
    if (upper_col %in% names(dt)) {
      z <- suppressWarnings(as.numeric(dt[[upper_col]]))
      hi[is.finite(z)] <- z[is.finite(z)]
    }
    list(lower = lo, upper = hi)
  }

  choose_bound <- function(specific_col) {
    spec <- trimws(as.character(dt[[specific_col]]))
    gen <- trimws(as.character(dt[["curve_bound"]]))
    spec[is.na(spec)] <- ""
    gen[is.na(gen)] <- ""
    ifelse(nzchar(spec), spec, gen)
  }

  rb_def <- get_default("rrate_lower", "rrate_upper", 0.00, 0.90)
  cb_def <- get_default("cvalue_lower", "cvalue_upper", 0.05, 8.00)
  db_def <- get_default("dvalue_lower", "dvalue_upper", 0.50, 2.00)

  rb <- parse_curve_bound_cell(choose_bound("rrate_bound"), rb_def$lower, rb_def$upper, label = "rrate_bound")
  cvb <- parse_curve_bound_cell(choose_bound("cvalue_bound"), cb_def$lower, cb_def$upper, label = "cvalue_bound")
  db <- parse_curve_bound_cell(choose_bound("dvalue_bound"), db_def$lower, db_def$upper, label = "dvalue_bound")

  dt[, `:=`(
    rrate_lower = rb$lower,
    rrate_upper = rb$upper,
    cvalue_lower = cvb$lower,
    cvalue_upper = cvb$upper,
    dvalue_lower = db$lower,
    dvalue_upper = db$upper
  )]

  dt[has_curve == 0L, `:=`(
    rrate_lower = 0.00,
    rrate_upper = 1e-4,
    cvalue_lower = 0.00,
    cvalue_upper = 1e-4,
    dvalue_lower = 0.00,
    dvalue_upper = 1e-4
  )]

  if (dt[has_curve == 1L, any(rrate_lower >= rrate_upper | cvalue_lower >= cvalue_upper | dvalue_lower >= dvalue_upper)]) {
    stop("Curve bounds must resolve to lower < upper for all curved variables.")
  }

  dt[has_curve == 1L, rrate := clip_to_open_interval(rrate, rrate_lower, rrate_upper)]
  dt[has_curve == 1L, cvalue := clip_to_open_interval(cvalue, cvalue_lower, cvalue_upper)]
  dt[has_curve == 1L, dvalue := clip_to_open_interval(dvalue, dvalue_lower, dvalue_upper)]

  dt[bound_type == "bounded", coef := clip_to_open_interval(coef, coef_lower, coef_upper)]

  if (dt[bound_type == "pos", any(coef <= 0)]) {
    stop("Positive-bounded variables must have positive coefficient prior centers.")
  }
  if (dt[bound_type == "neg", any(coef >= 0)]) {
    stop("Negative-bounded variables must have negative coefficient prior centers.")
  }
  if (dt[bound_type == "lower", any(coef <= coef_lower)]) {
    stop("Lower-bounded variables must have coef > lower bound.")
  }
  if (dt[bound_type == "upper", any(coef >= coef_upper)]) {
    stop("Upper-bounded variables must have coef < upper bound.")
  }

  if ("row_type_legacy" %in% names(dt)) dt[, row_type_legacy := NULL]
  if ("variable_role" %in% names(dt)) dt[, variable_role := NULL]

  setcolorder(dt, c(
    "variable", "effect_type", "source_entity", "role", "has_curve",
    "non_media_baseline_values", "control_reference_values", "reference_value_spec",
    "reach_col", "frequency_col", "population_col", "rf_spend_col",
    "curve_type", "rrate", "rrate_precision", "cvalue", "cvalue_precision", "dvalue", "dvalue_precision",
    "coef", "coef_precision", "coef_hierarchy_scale", "coef_hierarchy_scope", "hierarchy_key",
    "model_id_parts", "hierarchy_part_indices", "hierarchy_note",
    "coef_bound", "bound_type", "coef_lower", "coef_upper",
    "coef_default_bound_applied",
    "curve_bound", "rrate_bound", "cvalue_bound", "dvalue_bound",
    "rrate_lower", "rrate_upper", "cvalue_lower", "cvalue_upper", "dvalue_lower", "dvalue_upper"
  ))
  dt[]
}

normalize_context_sign_hier_mmm <- function(x) {
  z <- tolower(trimws(as.character(x %||% "+-")))
  z[is.na(z) | !nzchar(z)] <- "+-"
  out <- rep("free", length(z))
  out[z %in% c("+", "pos", "positive", "nonnegative", "non-negative", "up")] <- "positive"
  out[z %in% c("-", "neg", "negative", "nonpositive", "non-positive", "down")] <- "negative"
  out[z %in% c("+-", "-+", "free", "both", "any", "unbounded", "two_sided", "two-sided")] <- "free"
  bad <- !(z %in% c("+", "pos", "positive", "nonnegative", "non-negative", "up",
                    "-", "neg", "negative", "nonpositive", "non-positive", "down",
                    "+-", "-+", "free", "both", "any", "unbounded", "two_sided", "two-sided"))
  if (any(bad)) stop("Unknown context sign value(s): ", paste(unique(z[bad]), collapse = ", "))
  out
}

parse_context_effect_cell_hier_mmm <- function(cell, variable) {
  raw <- trimws(as.character(cell %||% ""))
  if (is.na(raw) || !nzchar(raw)) return(data.table())
  pieces <- regmatches(raw, gregexpr("\\([^()]+\\)", raw, perl = TRUE))[[1]]
  if (!length(pieces)) pieces <- unlist(strsplit(raw, ";", fixed = TRUE), use.names = FALSE)
  pieces <- trimws(pieces)
  pieces <- pieces[nzchar(pieces)]
  if (!length(pieces)) return(data.table())

  rows <- lapply(pieces, function(piece) {
    inner <- trimws(gsub("^\\(|\\)$", "", piece))
    toks <- trimws(strsplit(inner, ",", fixed = TRUE)[[1]])
    toks <- toks[nzchar(toks)]
    if (!length(toks)) return(NULL)
    num_at <- function(i, default = NA_real_) {
      if (length(toks) < i) return(default)
      z <- suppressWarnings(as.numeric(toks[i]))
      if (is.finite(z)) z else default
    }
    sign_raw <- "+-"
    if (length(toks) >= 8L) {
      sign_raw <- toks[8L]
    } else if (length(toks) >= 4L && grepl("^(\\+|-|\\+-|-\\+|pos|positive|neg|negative|free|both|any)$", tolower(toks[4L]))) {
      sign_raw <- toks[4L]
    }
    context_key <- toks[1L]
    data.table(
      variable = as.character(variable),
      context_key = as.character(context_key),
      context_coef_mean = num_at(2L, 0),
      context_coef_sd = num_at(3L, if (tolower(context_key) == "time") 0.10 else 0.05),
      context_change_mean = if (length(toks) >= 5L) num_at(4L, NA_real_) else NA_real_,
      context_change_sd = if (length(toks) >= 5L) num_at(5L, NA_real_) else NA_real_,
      context_rho_mean = if (length(toks) >= 7L) num_at(6L, NA_real_) else NA_real_,
      context_rho_sd = if (length(toks) >= 7L) num_at(7L, NA_real_) else NA_real_,
      context_sign = normalize_context_sign_hier_mmm(sign_raw),
      raw_context_spec = piece
    )
  })
  rbindlist(rows[!vapply(rows, is.null, logical(1))], use.names = TRUE, fill = TRUE)
}

clean_context_effects_hier_mmm <- function(context_effects = NULL,
                                           metadata = NULL,
                                           allow_time_context = FALSE) {
  rows <- list()
  if (!is.null(metadata)) {
    md <- as.data.table(copy(metadata))
    context_col <- pick_first_existing_col(
      md,
      c("context", "context_effects", "context_modifiers", "effect_modifiers", "effect_context", "context_multiplier")
    )
    if (!is.na(context_col)) {
      parsed <- rbindlist(lapply(seq_len(nrow(md)), function(i) {
        parse_context_effect_cell_hier_mmm(md[[context_col]][i], md$variable[i])
      }), use.names = TRUE, fill = TRUE)
      if (nrow(parsed)) rows[[length(rows) + 1L]] <- parsed[, source := paste0("metadata.", context_col)][]
    }
  }

  if (!is.null(context_effects)) {
    ce <- read_input_table(context_effects)
    ce <- as.data.table(copy(ce))
    if (nrow(ce)) {
      if (!"variable" %in% names(ce)) stop("context_effects must include variable.")
      ce[, variable := as.character(variable)]
      cell_col <- pick_first_existing_col(
        ce,
        c("context", "context_effects", "context_modifiers", "effect_modifiers", "effect_context", "context_multiplier")
      )
      key_col <- pick_first_existing_col(ce, c("context_key", "context_col", "context_variable", "context_driver", "driver", "context_name"))
      if (!is.na(cell_col) && is.na(key_col)) {
        parsed <- rbindlist(lapply(seq_len(nrow(ce)), function(i) {
          parse_context_effect_cell_hier_mmm(ce[[cell_col]][i], ce$variable[i])
        }), use.names = TRUE, fill = TRUE)
        if (nrow(parsed)) rows[[length(rows) + 1L]] <- parsed[, source := "context_effects.cell"][]
      } else {
        if (is.na(key_col)) stop("context_effects must include context_key/context_col or a context tuple column.")
        mean_col <- pick_first_existing_col(ce, c("context_coef_mean", "gamma_prior", "gamma_mean", "coef_mean", "mean"))
        sd_col <- pick_first_existing_col(ce, c("context_coef_sd", "gamma_sd", "coef_sd", "sd"))
        sign_col <- pick_first_existing_col(ce, c("context_sign", "sign", "direction"))
        out <- data.table(
          variable = ce$variable,
          context_key = as.character(ce[[key_col]]),
          context_coef_mean = if (!is.na(mean_col)) suppressWarnings(as.numeric(ce[[mean_col]])) else 0,
          context_coef_sd = if (!is.na(sd_col)) suppressWarnings(as.numeric(ce[[sd_col]])) else NA_real_,
          context_change_mean = NA_real_,
          context_change_sd = NA_real_,
          context_rho_mean = NA_real_,
          context_rho_sd = NA_real_,
          context_sign = normalize_context_sign_hier_mmm(if (!is.na(sign_col)) ce[[sign_col]] else "+-"),
          raw_context_spec = NA_character_,
          source = "context_effects.table"
        )
        rows[[length(rows) + 1L]] <- out
      }
    }
  }

  out <- rbindlist(rows, use.names = TRUE, fill = TRUE)
  if (!nrow(out)) return(data.table())
  out[, `:=`(
    variable = trimws(as.character(variable)),
    context_key = trimws(as.character(context_key)),
    context_key_normalized = tolower(trimws(as.character(context_key))),
    context_coef_mean = suppressWarnings(as.numeric(context_coef_mean)),
    context_coef_sd = suppressWarnings(as.numeric(context_coef_sd))
  )]
  out <- out[nzchar(variable) & nzchar(context_key)]
  if (!nrow(out)) return(data.table())
  out[!is.finite(context_coef_mean) | is.na(context_coef_mean), context_coef_mean := 0]
  out[!is.finite(context_coef_sd) | is.na(context_coef_sd) | context_coef_sd <= 0,
      context_coef_sd := 0.05]
  out[, context_coef_sd := pmax(context_coef_sd, 1e-4)]
  if (out[context_sign == "positive" & context_coef_mean < 0, .N] > 0L) {
    stop("Positive context effects cannot have negative context_coef_mean/gamma_prior.")
  }
  if (out[context_sign == "negative" & context_coef_mean > 0, .N] > 0L) {
    stop("Negative context effects cannot have positive context_coef_mean/gamma_prior.")
  }
  if (out[context_key_normalized == "time", .N] > 0L) {
    if (!isTRUE(allow_time_context)) {
      stop("context key 'time' is disabled by default because it can behave like a free drift term. ",
           "Use an explicit real context column, or set allow_time_context = TRUE only for a deliberate advanced drift sensitivity test.")
    }
    out[context_key_normalized == "time", context_key := "time"]
  }
  self_context <- out[tolower(variable) == context_key_normalized]
  if (nrow(self_context)) {
    stop("A variable cannot use itself as a context modifier because that confounds response shape with effectiveness drift: ",
         paste(unique(paste0(self_context$variable, ":", self_context$context_key)), collapse = ", "))
  }
  if (anyDuplicated(out[, .(variable, context_key_normalized)])) {
    dup <- out[duplicated(out[, .(variable, context_key_normalized)]) | duplicated(out[, .(variable, context_key_normalized)], fromLast = TRUE),
               paste0(variable, ":", context_key)]
    stop("Duplicate context effect definitions are not allowed: ", paste(unique(dup), collapse = ", "))
  }
  out[, context_idx := .I]
  out[, context_type := fifelse(context_key_normalized == "time", "time", "column")]
  out[, context_sign_code := fifelse(context_sign == "positive", 1L, fifelse(context_sign == "negative", -1L, 0L))]
  setcolorder(out, c(
    "context_idx", "variable", "context_key", "context_type", "context_sign", "context_sign_code",
    "context_coef_mean", "context_coef_sd", "context_change_mean", "context_change_sd",
    "context_rho_mean", "context_rho_sd", "source", "raw_context_spec"
  ))
  out[]
}

context_effect_multiplier_hier_mmm <- function(stan_data,
                                               variable_idx,
                                               row_idx = NULL,
                                               context_coef = NULL) {
  k_context <- as.integer(stan_data$K_context %||% 0L)
  if (!k_context) {
    n <- if (is.null(row_idx)) stan_data$N else length(row_idx)
    return(rep(1, n))
  }
  if (is.null(row_idx)) row_idx <- seq_len(stan_data$N)
  row_idx <- as.integer(row_idx)
  context_coef <- context_coef %||% stan_data$context_coef_mu
  context_coef <- as.numeric(context_coef)
  hit <- which(as.integer(stan_data$context_variable_idx) == as.integer(variable_idx)[1])
  if (!length(hit)) return(rep(1, length(row_idx)))
  x <- stan_data$X_context[row_idx, hit, drop = FALSE]
  log_mult <- as.numeric(x %*% context_coef[hit])
  bound <- as.numeric(stan_data$context_log_multiplier_bound %||% 2)[1]
  if (is.finite(bound) && bound > 0) log_mult <- clip_numeric(log_mult, -bound, bound)
  exp(log_mult)
}

# 013-hier_mmm-priors-data.R
# Generated by behavior-preserving split of hier_mmm.R.

build_curve_priors <- function(meta, estimate_dvalue = FALSE, curve_prior_relax = 2, min_sd_frac = 0.08) {
  md <- copy(meta)
  first_num_col <- function(dt, cols, default = NA_real_) {
    out <- rep(default, nrow(dt))
    for (cc in cols) {
      if (cc %in% names(dt)) {
        z <- suppressWarnings(as.numeric(dt[[cc]]))
        hit <- is.finite(z) & z > 0 & (!is.finite(out) | out <= 0)
        out[hit] <- z[hit]
      }
    }
    out
  }
  if (!"stan_observed_cvalue_reliability" %in% names(md)) md[, stan_observed_cvalue_reliability := NA_real_]
  if (!"stan_observed_cvalue_source" %in% names(md)) md[, stan_observed_cvalue_source := NA_character_]
  md[, observed_cvalue_mu__ := first_num_col(.SD, c("stan_observed_cvalue", "pooled_ramp_cvalue", "cvalue_data_driven", "observed_slope_cvalue"))]
  md[, observed_cvalue_reliability__ := suppressWarnings(as.numeric(stan_observed_cvalue_reliability))]
  if ("pooled_ramp_reliability" %in% names(md)) {
    z <- suppressWarnings(as.numeric(md$pooled_ramp_reliability))
    md[!is.finite(observed_cvalue_reliability__) & is.finite(z), observed_cvalue_reliability__ := z]
  }
  if ("cvalue_data_improvement" %in% names(md)) {
    z <- suppressWarnings(as.numeric(md$cvalue_data_improvement))
    md[!is.finite(observed_cvalue_reliability__) & is.finite(z) & z > 0, observed_cvalue_reliability__ := pmin(0.60, pmax(0.10, z * 3))]
  }
  md[!is.finite(observed_cvalue_reliability__) | observed_cvalue_reliability__ < 0, observed_cvalue_reliability__ := 0]
  md[, observed_cvalue_reliability__ := clip_numeric(observed_cvalue_reliability__, 0, 1)]

  out <- md[, .(
    variable, has_curve,
    rrate_mu = rrate,
    cvalue_mu = cvalue,
    dvalue_mu = dvalue,
    rrate_sd = pmax(sqrt(1 / pmax(rrate_precision, 1e-8)) * curve_prior_relax,
                    min_sd_frac * (rrate_upper - rrate_lower)),
    cvalue_sd = pmax(sqrt(1 / pmax(cvalue_precision, 1e-8)) * curve_prior_relax,
                     min_sd_frac * (cvalue_upper - cvalue_lower)),
    dvalue_sd = pmax(sqrt(1 / pmax(dvalue_precision, 1e-8)) * curve_prior_relax,
                     min_sd_frac * (dvalue_upper - dvalue_lower)),
    observed_cvalue_mu = observed_cvalue_mu__,
    observed_cvalue_reliability = observed_cvalue_reliability__,
    observed_cvalue_source = as.character(stan_observed_cvalue_source),
    rrate_lower, rrate_upper,
    cvalue_lower, cvalue_upper,
    dvalue_lower = if (estimate_dvalue) dvalue_lower else dvalue,
    dvalue_upper = if (estimate_dvalue) dvalue_upper else (dvalue + 1e-4)
  )]

  out[has_curve == 1L, `:=`(
    rrate_raw_mu = inv_logit_bounded(rrate_mu, rrate_lower, rrate_upper),
    cvalue_raw_mu = inv_logit_bounded(cvalue_mu, cvalue_lower, cvalue_upper),
    dvalue_raw_mu = inv_logit_bounded(dvalue_mu, dvalue_lower, dvalue_upper),
    rrate_raw_sd = raw_sd_from_original_sd(rrate_mu, rrate_sd, rrate_lower, rrate_upper),
    cvalue_raw_sd = raw_sd_from_original_sd(cvalue_mu, cvalue_sd, cvalue_lower, cvalue_upper),
    dvalue_raw_sd = raw_sd_from_original_sd(dvalue_mu, dvalue_sd, dvalue_lower, dvalue_upper),
    use_observed_cvalue_prior = as.integer(is.finite(observed_cvalue_mu) & observed_cvalue_mu > cvalue_lower & observed_cvalue_mu < cvalue_upper & observed_cvalue_reliability >= 0.10),
    observed_cvalue_raw_mu = inv_logit_bounded(clip_to_open_interval(observed_cvalue_mu, cvalue_lower, cvalue_upper), cvalue_lower, cvalue_upper),
    observed_cvalue_raw_sd = raw_sd_from_original_sd(
      clip_to_open_interval(observed_cvalue_mu, cvalue_lower, cvalue_upper),
      pmax((0.40 - 0.25 * observed_cvalue_reliability) * pmax(observed_cvalue_mu, 1e-6), min_sd_frac * (cvalue_upper - cvalue_lower)),
      cvalue_lower,
      cvalue_upper,
      floor = 0.20,
      cap = 3.0
    )
  )]

  out[has_curve == 0L, `:=`(
    rrate_raw_mu = 0, rrate_raw_sd = 0.05,
    cvalue_raw_mu = 0, cvalue_raw_sd = 0.05,
    dvalue_raw_mu = 0, dvalue_raw_sd = 0.05,
    use_observed_cvalue_prior = 0L,
    observed_cvalue_raw_mu = 0,
    observed_cvalue_raw_sd = 1
  )]
  out[!is.finite(observed_cvalue_raw_mu), observed_cvalue_raw_mu := 0]
  out[!is.finite(observed_cvalue_raw_sd) | observed_cvalue_raw_sd <= 0, observed_cvalue_raw_sd := 1]
  out[]
}

build_coef_prior_components <- function(meta,
                                        coef_prior_relax = 1.5,
                                        min_coef_sd_abs = 0.001,
                                        min_coef_sd_frac = 0.05,
                                        hard_prior_precision_threshold = 1e6,
                                        min_tau_scale = 0.05) {
  dt <- copy(meta)
  dt[, prior_sd_nominal__ := sqrt(1 / pmax(coef_precision, 1e-8)) * coef_prior_relax]
  dt[, prior_sd_floor__ := min_coef_sd_frac * abs(coef) + min_coef_sd_abs]
  dt[, coef_sd := fifelse(
    is.finite(coef_precision) & coef_precision >= hard_prior_precision_threshold,
    pmax(prior_sd_nominal__, 1e-8),
    pmax(prior_sd_nominal__, prior_sd_floor__)
  )]

  pos <- dt[bound_type == "pos"]
  neg <- dt[bound_type == "neg"]
  lower <- dt[bound_type == "lower"]
  upper <- dt[bound_type == "upper"]
  bounded <- dt[bound_type == "bounded"]
  free <- dt[bound_type == "free"]

  pos_conv <- if (nrow(pos)) softplus_from_mean_sd(pos$coef, pos$coef_sd) else list(raw_mu = numeric(), raw_sd = numeric())
  neg_conv <- if (nrow(neg)) softplus_from_mean_sd(abs(neg$coef), neg$coef_sd) else list(raw_mu = numeric(), raw_sd = numeric())
  lower_conv <- if (nrow(lower)) softplus_from_mean_sd(lower$coef - lower$coef_lower, lower$coef_sd) else list(raw_mu = numeric(), raw_sd = numeric())
  upper_conv <- if (nrow(upper)) softplus_from_mean_sd(upper$coef_upper - upper$coef, upper$coef_sd) else list(raw_mu = numeric(), raw_sd = numeric())

  bounded_raw_mu <- if (nrow(bounded)) inv_logit_bounded(bounded$coef, bounded$coef_lower, bounded$coef_upper) else numeric()
  bounded_raw_sd <- if (nrow(bounded)) raw_sd_from_original_sd(
    bounded$coef, bounded$coef_sd, bounded$coef_lower, bounded$coef_upper,
    floor = 0.10, cap = 2.0
  ) else numeric()
  tau_scale_for <- function(base, scale) {
    scale <- as.numeric(scale)
    scale[!is.finite(scale) | is.na(scale) | scale < 0] <- 1
    pmax(base * scale, min_tau_scale * pmin(scale, 1), 1e-6)
  }

  list(
    pos = list(dt = pos, meanlog = pos_conv$raw_mu, sdlog = pos_conv$raw_sd,
               tau_scale = tau_scale_for(pos_conv$raw_sd * 0.50, pos$coef_hierarchy_scale)),
    neg = list(dt = neg, meanlog = neg_conv$raw_mu, sdlog = neg_conv$raw_sd,
               tau_scale = tau_scale_for(neg_conv$raw_sd * 0.50, neg$coef_hierarchy_scale)),
    lower = list(dt = lower, meanlog = lower_conv$raw_mu, sdlog = lower_conv$raw_sd,
                 tau_scale = tau_scale_for(lower_conv$raw_sd * 0.50, lower$coef_hierarchy_scale)),
    upper = list(dt = upper, meanlog = upper_conv$raw_mu, sdlog = upper_conv$raw_sd,
                 tau_scale = tau_scale_for(upper_conv$raw_sd * 0.50, upper$coef_hierarchy_scale)),
    bounded = list(dt = bounded, raw_mu = bounded_raw_mu, raw_sd = bounded_raw_sd,
                   tau_scale = tau_scale_for(bounded_raw_sd * 0.75, bounded$coef_hierarchy_scale)),
    free = list(dt = free, mean = free$coef, sd = free$coef_sd,
                tau_scale = tau_scale_for(free$coef_sd * 0.75, free$coef_hierarchy_scale))
  )
}

assess_group_exposure_variation <- function(dt,
                                            variables,
                                            group_col,
                                            time_col,
                                            cv_threshold = 0.02,
                                            range_threshold = 0.05,
                                            min_mean_abs = 1e-8) {
  if (!length(variables)) {
    return(data.table(
      variable = character(),
      geo_variation_week_share = numeric(),
      geo_variation_median_cv = numeric()
    ))
  }
  out <- vector("list", length(variables))
  for (i in seq_along(variables)) {
    vv <- variables[i]
    by_time <- dt[, {
      x <- suppressWarnings(as.numeric(get(vv)))
      x <- x[is.finite(x)]
      if (length(x) <= 1L) {
        .(n_group = length(x), mean_abs = mean(abs(x)), sd_x = 0, range_x = 0)
      } else {
        .(
          n_group = length(x),
          mean_abs = mean(abs(x)),
          sd_x = stats::sd(x),
          range_x = max(x) - min(x)
        )
      }
    }, by = time_col]
    by_time[, denom := pmax(mean_abs, min_mean_abs)]
    by_time[, cv := fifelse(is.finite(sd_x), sd_x / denom, 0)]
    by_time[, range_rel := fifelse(is.finite(range_x), range_x / denom, 0)]
    usable <- by_time[n_group > 1L & is.finite(denom)]
    out[[i]] <- data.table(
      variable = vv,
      geo_variation_week_share = if (nrow(usable)) mean(usable$cv >= cv_threshold | usable$range_rel >= range_threshold, na.rm = TRUE) else 0,
      geo_variation_median_cv = if (nrow(usable)) stats::median(usable$cv, na.rm = TRUE) else 0
    )
  }
  rbindlist(out, fill = TRUE)
}


clean_coef_override_input <- function(coef_override_input,
                                      group_col,
                                      metadata,
                                      group_lookup) {
  if (is.null(coef_override_input)) {
    G <- nrow(group_lookup); J <- nrow(metadata)
    return(list(
      use = 0L,
      mu = matrix(0, nrow = G, ncol = J),
      sd = matrix(0, nrow = G, ncol = J),
      long = data.table()
    ))
  }

  ov <- read_input_table(coef_override_input)
  req <- c(group_col, "variable", "coef", "coef_precision")
  miss <- setdiff(req, names(ov))
  if (length(miss)) stop("coef_override_input is missing required columns: ", paste(miss, collapse = ", "))

  ov <- copy(ov)
  ov[, variable := trimws(as.character(variable))]
  ov[, coef := suppressWarnings(as.numeric(coef))]
  ov[, coef_precision := suppressWarnings(as.numeric(coef_precision))]
  ov <- ov[is.finite(coef) & is.finite(coef_precision) & coef_precision > 0]

  if (!nrow(ov)) {
    G <- nrow(group_lookup); J <- nrow(metadata)
    return(list(
      use = 0L,
      mu = matrix(0, nrow = G, ncol = J),
      sd = matrix(0, nrow = G, ncol = J),
      long = data.table()
    ))
  }

  setnames(ov, group_col, "group_value")
  ov[, group_value := as.character(group_value)]
  ov <- unique(ov, by = c("group_value", "variable"))

  md_clip <- metadata[, .(variable, bound_type, coef_lower, coef_upper)]
  ov <- md_clip[ov, on = "variable", nomatch = 0L]
  gl <- copy(group_lookup)[, .(group_value = as.character(group_value), group_idx)]
  ov <- gl[ov, on = "group_value", nomatch = 0L]

  eps <- 1e-6
  ov[bound_type == "pos", coef := pmax(coef, eps)]
  ov[bound_type == "neg", coef := pmin(coef, -eps)]
  ov[bound_type == "lower", coef := pmax(coef, coef_lower + eps)]
  ov[bound_type == "upper", coef := pmin(coef, coef_upper - eps)]
  ov[bound_type == "bounded", coef := pmin(pmax(coef, coef_lower + eps), coef_upper - eps)]

  ov[, coef_sd := 1 / sqrt(pmax(coef_precision, 1e-8))]

  G <- nrow(group_lookup)
  J <- nrow(metadata)
  mu <- matrix(0, nrow = G, ncol = J)
  sd <- matrix(0, nrow = G, ncol = J)

  var_map <- metadata[, .(variable, variable_idx = .I)]
  ov <- var_map[ov, on = "variable", nomatch = 0L]

  for (i in seq_len(nrow(ov))) {
    g <- ov$group_idx[i]
    j <- ov$variable_idx[i]
    mu[g, j] <- ov$coef[i]
    sd[g, j] <- ov$coef_sd[i]
  }

  list(
    use = as.integer(nrow(ov) > 0),
    mu = mu,
    sd = sd,
    long = ov[, .(group_value, variable, coef, coef_precision, coef_sd)]
  )
}

build_experiment_calibration_hier_mmm <- function(calibration_input,
                                                  data,
                                                  variable_lookup,
                                                  group_col,
                                                  time_col) {
  n <- nrow(data)
  if (is.null(calibration_input)) {
    return(list(
      audit = data.table(),
      variable_idx = integer(),
      weight = matrix(0, nrow = n, ncol = 0L),
      observed_lift = numeric(),
      observed_sd = numeric()
    ))
  }
  cal <- read_input_table(calibration_input)
  cal <- as.data.table(copy(cal))
  if (!nrow(cal)) return(build_experiment_calibration_hier_mmm(NULL, data, variable_lookup, group_col, time_col))
  if (!"variable" %in% names(cal)) stop("calibration_input must include variable.")
  if (anyDuplicated(cal$calibration_id %||% seq_len(nrow(cal)))) stop("calibration_input calibration_id values must be unique.")
  if (!"calibration_id" %in% names(cal)) cal[, calibration_id := paste0("calibration_", .I)]
  cal[, variable := as.character(variable)]
  unknown <- setdiff(unique(cal$variable), variable_lookup$variable)
  if (length(unknown)) stop("calibration_input references unknown modeled variable(s): ", paste(unknown, collapse = ", "))

  first_numeric <- function(row, candidates) {
    hit <- candidates[candidates %in% names(row)]
    if (!length(hit)) return(NA_real_)
    vals <- suppressWarnings(as.numeric(unlist(as.list(row)[hit], use.names = FALSE)))
    vals <- vals[is.finite(vals)]
    if (length(vals)) vals[1] else NA_real_
  }
  coerce_bound <- function(value, reference) {
    if (inherits(reference, "Date")) return(as.Date(value))
    if (inherits(reference, "POSIXct")) return(as.POSIXct(value, tz = attr(reference, "tzone") %||% "UTC"))
    if (is.numeric(reference)) return(suppressWarnings(as.numeric(value)))
    as.character(value)
  }

  weights <- matrix(0, nrow = n, ncol = nrow(cal))
  audits <- vector("list", nrow(cal))
  observed <- observed_sd <- numeric(nrow(cal))
  variable_idx <- integer(nrow(cal))
  for (cc in seq_len(nrow(cal))) {
    row <- cal[cc]
    variable_idx[cc] <- variable_lookup[variable == row$variable, variable_idx][1]
    mask <- rep(TRUE, n)
    if (group_col %in% names(cal) && !is.na(row[[group_col]][1]) && nzchar(as.character(row[[group_col]][1]))) {
      mask <- mask & as.character(data[[group_col]]) == as.character(row[[group_col]][1])
    }
    if ("start_period" %in% names(cal) && !is.na(row$start_period[1]) && nzchar(as.character(row$start_period[1]))) {
      mask <- mask & data[[time_col]] >= coerce_bound(row$start_period[1], data[[time_col]])
    }
    if ("end_period" %in% names(cal) && !is.na(row$end_period[1]) && nzchar(as.character(row$end_period[1]))) {
      mask <- mask & data[[time_col]] <= coerce_bound(row$end_period[1], data[[time_col]])
    }
    if (!any(mask)) stop("calibration_input row '", row$calibration_id, "' selects no model rows.")

    lift <- first_numeric(row, c("observed_lift", "incremental_outcome", "incremental_kpi"))
    lift_sd <- first_numeric(row, c("observed_lift_sd", "incremental_outcome_sd", "incremental_kpi_sd"))
    precision <- first_numeric(row, c("observed_lift_precision", "incremental_outcome_precision", "incremental_kpi_precision"))
    spend <- first_numeric(row, c("incremental_spend", "experiment_spend", "spend"))
    roi <- first_numeric(row, c("observed_roi", "incremental_roi"))
    roi_sd <- first_numeric(row, c("observed_roi_sd", "incremental_roi_sd"))
    cpkpi <- first_numeric(row, c("observed_cost_per_outcome", "observed_cpkpi", "cost_per_kpi"))
    cpkpi_sd <- first_numeric(row, c("observed_cost_per_outcome_sd", "observed_cpkpi_sd", "cost_per_kpi_sd"))
    basis <- "observed_lift"
    if (!is.finite(lift) && is.finite(roi) && is.finite(spend)) {
      lift <- roi * spend
      if (is.finite(roi_sd)) lift_sd <- abs(spend) * roi_sd
      basis <- "roi_x_incremental_spend"
    }
    if (!is.finite(lift) && is.finite(cpkpi) && cpkpi > 0 && is.finite(spend)) {
      lift <- spend / cpkpi
      if (is.finite(cpkpi_sd)) lift_sd <- abs(spend / (cpkpi^2)) * cpkpi_sd
      basis <- "incremental_spend_divided_by_cost_per_kpi"
    }
    if ((!is.finite(lift_sd) || lift_sd <= 0) && is.finite(precision) && precision > 0) lift_sd <- 1 / sqrt(precision)
    if (!is.finite(lift)) stop("calibration_input row '", row$calibration_id, "' needs observed_lift, ROI + incremental_spend, or cost-per-KPI + incremental_spend.")
    if (!is.finite(lift_sd) || lift_sd <= 0) stop("calibration_input row '", row$calibration_id, "' must provide a positive SD or precision on its supplied evidence scale.")

    weights[mask, cc] <- as.numeric(data$rescale_factor__[mask])
    observed[cc] <- lift
    observed_sd[cc] <- lift_sd
    audits[[cc]] <- data.table(
      calibration_id = as.character(row$calibration_id),
      variable = as.character(row$variable),
      variable_idx = variable_idx[cc],
      selected_row_n = sum(mask),
      observed_lift_raw_scale = lift,
      observed_lift_sd_raw_scale = lift_sd,
      observed_lift_precision_raw_scale = 1 / lift_sd^2,
      evidence_basis = basis,
      calibration_likelihood = "normal",
      calibration_note = "Joint likelihood on raw-scale incremental KPI; row weights convert model-scale contribution using training-only outcome scaling."
    )
  }
  storage.mode(weights) <- "double"
  list(
    audit = rbindlist(audits, use.names = TRUE, fill = TRUE),
    variable_idx = as.integer(variable_idx),
    weight = weights,
    observed_lift = as.numeric(observed),
    observed_sd = as.numeric(observed_sd)
  )
}

build_sequential_transfer_hier_mmm <- function(transfer_input,
                                               data,
                                               variable_lookup) {
  n <- nrow(data)
  empty <- function() list(
    effectiveness = list(
      audit = data.table(), parent_audit = data.table(), child_n = 0L, parent_n = 0L,
      variable_idx = integer(), parent_idx = integer(), weight = matrix(0, n, 0L),
      reference_spend = numeric(), child_noise_sd = numeric(), child_share = matrix(0, 0L, 0L),
      parent_mu = numeric(), parent_sd = numeric(), tau_prior_mean = 0,
      tau_prior_sd = 1, aggregate_sd = numeric()
    ),
    adstock = list(
      audit = data.table(), parent_audit = data.table(), child_n = 0L, parent_n = 0L,
      curve_idx = integer(), parent_idx = integer(), parent_mu_logit = numeric(),
      parent_sd_logit = numeric(), tau_prior_mean_logit = 0,
      tau_prior_sd_logit = 1, child_noise_sd_logit = numeric()
    )
  )
  out <- empty()
  if (is.null(transfer_input)) return(out)
  if (!is.list(transfer_input)) stop("sequential_transfer_input must be a list with effectiveness and/or adstock tables.")

  read_component <- function(name) {
    x <- transfer_input[[name]]
    if (is.null(x)) return(data.table())
    data.table::as.data.table(data.table::copy(read_input_table(x)))
  }
  validate_parent_constants <- function(x, parent_cols, label) {
    for (cc in parent_cols) {
      bad <- x[, .(value_n = data.table::uniqueN(round(as.numeric(get(cc)), 12))), by = parent_id][value_n > 1L]
      if (nrow(bad)) stop(label, " has inconsistent ", cc, " values within parent_id: ", paste(bad$parent_id, collapse = ", "))
    }
  }

  eff <- read_component("effectiveness")
  if (nrow(eff)) {
    required <- c(
      "variable", "parent_id", "parent_mean", "parent_sd", "reference_spend",
      "tau_prior_mean", "tau_prior_sd", "aggregate_sd", "child_noise_sd"
    )
    missing <- setdiff(required, names(eff))
    if (length(missing)) stop("sequential_transfer_input$effectiveness is missing: ", paste(missing, collapse = ", "))
    eff[, `:=`(variable = as.character(variable), parent_id = as.character(parent_id))]
    if (anyDuplicated(eff$variable)) stop("Sequential effectiveness transfer has duplicate child variables.")
    unknown <- setdiff(eff$variable, variable_lookup$variable)
    if (length(unknown)) stop("Sequential effectiveness transfer references unknown variable(s): ", paste(unknown, collapse = ", "))
    numeric_cols <- setdiff(required, c("variable", "parent_id"))
    for (cc in numeric_cols) eff[, (cc) := suppressWarnings(as.numeric(get(cc)))]
    if (any(!is.finite(eff$reference_spend) | eff$reference_spend <= 0)) stop("Sequential effectiveness reference_spend must be positive.")
    positive_cols <- c("parent_sd", "tau_prior_sd", "aggregate_sd", "child_noise_sd")
    if (any(vapply(positive_cols, function(cc) any(!is.finite(eff[[cc]]) | eff[[cc]] <= 0), logical(1)))) {
      stop("Sequential effectiveness parent_sd, tau_prior_sd, aggregate_sd, and child_noise_sd must be positive.")
    }
    if (any(!is.finite(eff$parent_mean)) || any(!is.finite(eff$tau_prior_mean) | eff$tau_prior_mean < 0)) {
      stop("Sequential effectiveness parent_mean must be finite and tau_prior_mean must be finite and nonnegative.")
    }
    validate_parent_constants(
      eff, c("parent_mean", "parent_sd", "aggregate_sd"),
      "Sequential effectiveness transfer"
    )
    if (data.table::uniqueN(round(eff$tau_prior_mean, 12)) > 1L ||
        data.table::uniqueN(round(eff$tau_prior_sd, 12)) > 1L) {
      stop("Sequential effectiveness tau_prior_mean and tau_prior_sd must be shared across the layer.")
    }
    parents <- unique(eff[, .(parent_id, parent_mean, parent_sd, aggregate_sd)], by = "parent_id")
    parents[, parent_idx := .I]
    eff[parents, on = "parent_id", parent_idx := i.parent_idx]
    eff[variable_lookup[, .(variable, variable_idx)], on = "variable", variable_idx := i.variable_idx]
    weight <- matrix(0, nrow = n, ncol = nrow(eff))
    train_mask <- if ("is_holdout__" %in% names(data)) !as.logical(data$is_holdout__) else rep(TRUE, n)
    scale <- as.numeric(data$rescale_factor__ %||% rep(1, n))
    for (ss in seq_len(nrow(eff))) weight[train_mask, ss] <- scale[train_mask]
    share <- matrix(0, nrow = nrow(parents), ncol = nrow(eff))
    for (pp in seq_len(nrow(parents))) {
      idx <- which(eff$parent_idx == pp)
      share[pp, idx] <- eff$reference_spend[idx] / sum(eff$reference_spend[idx])
    }
    out$effectiveness <- list(
      audit = eff[], parent_audit = parents[], child_n = nrow(eff), parent_n = nrow(parents),
      variable_idx = as.integer(eff$variable_idx), parent_idx = as.integer(eff$parent_idx),
      weight = weight, reference_spend = eff$reference_spend,
      child_noise_sd = eff$child_noise_sd, child_share = share,
      parent_mu = parents$parent_mean, parent_sd = parents$parent_sd,
      tau_prior_mean = eff$tau_prior_mean[1], tau_prior_sd = eff$tau_prior_sd[1],
      aggregate_sd = parents$aggregate_sd
    )
  }

  ad <- read_component("adstock")
  if (nrow(ad)) {
    required <- c(
      "variable", "parent_id", "parent_mean", "parent_sd", "tau_prior_mean",
      "tau_prior_sd", "child_noise_sd"
    )
    missing <- setdiff(required, names(ad))
    if (length(missing)) stop("sequential_transfer_input$adstock is missing: ", paste(missing, collapse = ", "))
    ad[, `:=`(variable = as.character(variable), parent_id = as.character(parent_id))]
    if (anyDuplicated(ad$variable)) stop("Sequential adstock transfer has duplicate child variables.")
    curve_lookup <- variable_lookup[has_curve == 1L, .(variable, curve_param_idx)]
    unknown <- setdiff(ad$variable, curve_lookup$variable)
    if (length(unknown)) stop("Sequential adstock transfer requires sampled/fixed curve variables: ", paste(unknown, collapse = ", "))
    numeric_cols <- setdiff(required, c("variable", "parent_id"))
    for (cc in numeric_cols) ad[, (cc) := suppressWarnings(as.numeric(get(cc)))]
    if (any(!is.finite(ad$parent_mean) | ad$parent_mean <= 0 | ad$parent_mean >= 1)) stop("Sequential adstock parent_mean must lie strictly between 0 and 1.")
    positive_cols <- c("parent_sd", "tau_prior_sd", "child_noise_sd")
    if (any(vapply(positive_cols, function(cc) any(!is.finite(ad[[cc]]) | ad[[cc]] <= 0), logical(1)))) {
      stop("Sequential adstock parent_sd, tau_prior_sd, and child_noise_sd must be positive.")
    }
    if (any(!is.finite(ad$tau_prior_mean) | ad$tau_prior_mean < 0)) {
      stop("Sequential adstock tau_prior_mean must be finite and nonnegative.")
    }
    validate_parent_constants(ad, c("parent_mean", "parent_sd"), "Sequential adstock transfer")
    ad[curve_lookup, on = "variable", curve_param_idx := i.curve_param_idx]
    ad[, derivative__ := 1 / pmax(parent_mean * (1 - parent_mean), 1e-6)]
    ad[, `:=`(
      parent_mu_logit = stats::qlogis(parent_mean),
      parent_sd_logit = pmax(parent_sd * derivative__, 0.05),
      tau_prior_mean_logit = pmax(tau_prior_mean * derivative__, 0),
      tau_prior_sd_logit = pmax(tau_prior_sd * derivative__, 0.05),
      child_noise_sd_logit = pmax(child_noise_sd * derivative__, 0.01)
    )]
    parents <- unique(ad[, .(
      parent_id, parent_mu_logit, parent_sd_logit
    )], by = "parent_id")
    parents[, parent_idx := .I]
    ad[parents, on = "parent_id", parent_idx := i.parent_idx]
    out$adstock <- list(
      audit = ad[, setdiff(names(ad), "derivative__"), with = FALSE],
      parent_audit = parents[], child_n = nrow(ad), parent_n = nrow(parents),
      curve_idx = as.integer(ad$curve_param_idx), parent_idx = as.integer(ad$parent_idx),
      parent_mu_logit = parents$parent_mu_logit, parent_sd_logit = parents$parent_sd_logit,
      tau_prior_mean_logit = stats::median(ad$tau_prior_mean_logit),
      tau_prior_sd_logit = stats::median(ad$tau_prior_sd_logit),
      child_noise_sd_logit = ad$child_noise_sd_logit
    )
  }
  out
}

# Internal contract for a sequential parent-to-children curve reconciliation.
# Unlike experiment calibration, one scenario can include several modeled media
# variables. We only allow explicit training-row selections so a parent fit
# cannot leak holdout support or media mix into the child likelihood.
build_collective_saturation_reconciliation_hier_mmm <- function(reconciliation_input,
                                                                 data,
                                                                 variable_lookup,
                                                                 group_col,
                                                                 time_col) {
  n <- nrow(data)
  j_n <- nrow(variable_lookup)
  empty <- function() list(
    audit = data.table(),
    weight = array(0, dim = c(0L, n, j_n)),
    observed = numeric(),
    observed_sd = numeric()
  )
  if (is.null(reconciliation_input)) return(empty())
  if (!is.list(reconciliation_input) || is.null(reconciliation_input$scenarios) || is.null(reconciliation_input$members)) {
    stop("collective_saturation_reconciliation_input must be a list with scenarios and members tables.", call. = FALSE)
  }
  scenarios <- as.data.table(copy(reconciliation_input$scenarios))
  members <- as.data.table(copy(reconciliation_input$members))
  required_scenarios <- c("reconciliation_id", "parent_response", "parent_response_sd")
  required_members <- c("reconciliation_id", "variable")
  miss <- setdiff(required_scenarios, names(scenarios))
  if (length(miss)) stop("collective reconciliation scenarios missing: ", paste(miss, collapse = ", "), call. = FALSE)
  miss <- setdiff(required_members, names(members))
  if (length(miss)) stop("collective reconciliation members missing: ", paste(miss, collapse = ", "), call. = FALSE)
  if (!nrow(scenarios)) return(empty())
  if (anyDuplicated(scenarios$reconciliation_id)) stop("collective reconciliation_id values must be unique.", call. = FALSE)
  scenarios[, reconciliation_id := as.character(reconciliation_id)]
  members[, `:=`(reconciliation_id = as.character(reconciliation_id), variable = as.character(variable))]
  unknown <- setdiff(unique(members$variable), variable_lookup$variable)
  if (length(unknown)) stop("collective reconciliation references unknown modeled variable(s): ", paste(unknown, collapse = ", "), call. = FALSE)
  if (!"time_value" %in% names(members)) stop("collective reconciliation members must include time_value.", call. = FALSE)
  if (!(time_col %in% names(data))) stop("collective reconciliation time_col is missing from model data: ", time_col, call. = FALSE)
  # Match on a stable character key to support Date, numeric, and period IDs.
  time_key <- as.character(data[[time_col]])
  members[, time_key__ := as.character(time_value)]
  scenario_ids <- scenarios$reconciliation_id
  weight <- array(0, dim = c(length(scenario_ids), n, j_n))
  audit_rows <- vector("list", length(scenario_ids))
  for (cc in seq_along(scenario_ids)) {
    sid <- scenario_ids[cc]
    sc <- scenarios[reconciliation_id == sid][1]
    if (!is.finite(as.numeric(sc$parent_response)) || !is.finite(as.numeric(sc$parent_response_sd)) || as.numeric(sc$parent_response_sd) <= 0) {
      stop("collective reconciliation scenario '", sid, "' needs finite parent_response and positive parent_response_sd.", call. = FALSE)
    }
    mm <- members[reconciliation_id == sid]
    if (!nrow(mm)) stop("collective reconciliation scenario '", sid, "' has no child members.", call. = FALSE)
    selected_n <- 0L
    for (rr in seq_len(nrow(mm))) {
      j <- variable_lookup$variable_idx[match(mm$variable[rr], variable_lookup$variable)]
      idx <- which(time_key == mm$time_key__[rr])
      if (!length(idx)) stop("collective reconciliation scenario '", sid, "' selects no model rows for time_value.", call. = FALSE)
      if (any(data$is_holdout__[idx])) stop("collective reconciliation scenario '", sid, "' selects holdout rows; use training-period scenarios only.", call. = FALSE)
      # The fit contribution is on model scale. This maps it back to the raw
      # KPI scale used by the parent posterior response target.
      weight[cc, idx, j] <- as.numeric(data$rescale_factor__[idx])
      selected_n <- selected_n + length(idx)
    }
    audit_rows[[cc]] <- data.table(
      reconciliation_id = sid,
      parent_node = as.character(sc$parent_node %||% NA_character_),
      scenario_label = as.character(sc$scenario_label %||% sid),
      parent_response = as.numeric(sc$parent_response),
      parent_response_sd = as.numeric(sc$parent_response_sd),
      parent_posterior_sd_component = as.numeric(sc$parent_posterior_sd_component %||% NA_real_),
      data_reuse_sd_component = as.numeric(sc$data_reuse_sd_component %||% NA_real_),
      heterogeneity_sd_component = as.numeric(sc$heterogeneity_sd_component %||% NA_real_),
      mix_instability_sd_component = as.numeric(sc$mix_instability_sd_component %||% NA_real_),
      approximation_sd_component = as.numeric(sc$approximation_sd_component %||% NA_real_),
      selected_member_n = nrow(mm),
      selected_row_variable_n = selected_n,
      reconciliation_likelihood = "normal_soft_collective_child_response"
    )
  }
  list(
    audit = rbindlist(audit_rows, fill = TRUE),
    weight = weight,
    observed = as.numeric(scenarios$parent_response),
    observed_sd = as.numeric(scenarios$parent_response_sd)
  )
}

# Shape-only sequential saturation contract. Each target compares a perturbed
# sibling mix with the same mix at its reference level. The target remains a
# shape ratio, while its covariance is transformed into response units for a
# stable cross-multiplied residual in Stan. Shared parent draws are retained.
build_collective_saturation_shape_reconciliation_hier_mmm <- function(reconciliation_input,
                                                                       data,
                                                                       variable_lookup,
                                                                       group_col,
                                                                       time_col) {
  n <- nrow(data); j_n <- nrow(variable_lookup)
  empty <- function() list(
    audit = data.table(),
    multiplier = array(1, dim = c(0L, n, j_n)),
    weight = array(0, dim = c(0L, n, j_n)),
    parent_shape = numeric(),
    parent_reference_response = numeric(),
    parent_shape_cov = matrix(0, 0, 0)
  )
  if (is.null(reconciliation_input)) return(empty())
  if (!is.list(reconciliation_input) || is.null(reconciliation_input$scenarios) || is.null(reconciliation_input$members) || is.null(reconciliation_input$parent_shape_cov)) {
    stop("collective_saturation_shape_reconciliation_input must contain scenarios, members, and parent_shape_cov.", call. = FALSE)
  }
  scenarios <- as.data.table(copy(reconciliation_input$scenarios))
  members <- as.data.table(copy(reconciliation_input$members))
  required_scenarios <- c("reconciliation_id", "parent_shape", "parent_reference_response")
  required_members <- c("reconciliation_id", "variable", "time_value", "multiplier")
  miss <- setdiff(required_scenarios, names(scenarios)); if (length(miss)) stop("collective shape scenarios missing: ", paste(miss, collapse = ", "), call. = FALSE)
  miss <- setdiff(required_members, names(members)); if (length(miss)) stop("collective shape members missing: ", paste(miss, collapse = ", "), call. = FALSE)
  if (!nrow(scenarios)) return(empty())
  if (anyDuplicated(scenarios$reconciliation_id)) stop("collective shape reconciliation_id values must be unique.", call. = FALSE)
  if (any(!is.finite(as.numeric(scenarios$parent_reference_response)) | as.numeric(scenarios$parent_reference_response) <= 1e-6)) {
    stop("collective shape scenarios must have finite, non-negligible parent_reference_response values.", call. = FALSE)
  }
  scenarios[, reconciliation_id := as.character(reconciliation_id)]
  members[, `:=`(reconciliation_id = as.character(reconciliation_id), variable = as.character(variable), time_key__ = as.character(time_value))]
  if (any(!is.finite(as.numeric(members$multiplier)) | as.numeric(members$multiplier) < 0)) stop("collective shape multipliers must be finite and non-negative.", call. = FALSE)
  unknown <- setdiff(unique(members$variable), variable_lookup$variable)
  if (length(unknown)) stop("collective shape reconciliation references unknown modeled variable(s): ", paste(unknown, collapse = ", "), call. = FALSE)
  cov <- as.matrix(reconciliation_input$parent_shape_cov)
  if (!identical(dim(cov), c(nrow(scenarios), nrow(scenarios)))) stop("parent_shape_cov must be a square matrix aligned to scenarios.", call. = FALSE)
  if (any(!is.finite(cov))) stop("parent_shape_cov must be finite.", call. = FALSE)
  cov <- (cov + t(cov)) / 2
  if (any(diag(cov) <= 0)) stop("parent_shape_cov must have positive diagonal entries.", call. = FALSE)
  # A small ridge handles finite-draw covariance rank deficiency without
  # pretending shape targets from one parent posterior are independent.
  eigen_min <- min(eigen(cov, symmetric = TRUE, only.values = TRUE)$values)
  if (!is.finite(eigen_min)) stop("parent_shape_cov is invalid.", call. = FALSE)
  if (eigen_min <= 0) cov <- cov + diag(abs(eigen_min) + 1e-8, nrow(cov))
  multiplier <- array(1, dim = c(nrow(scenarios), n, j_n))
  weight <- array(0, dim = c(nrow(scenarios), n, j_n))
  time_key <- as.character(data[[time_col]])
  time_levels <- unique(time_key)
  audit <- vector("list", nrow(scenarios))
  for (cc in seq_len(nrow(scenarios))) {
    sid <- scenarios$reconciliation_id[cc]
    mm <- members[reconciliation_id == sid]
    if (!nrow(mm)) stop("collective shape scenario '", sid, "' has no members.", call. = FALSE)
    selected <- 0L
    for (rr in seq_len(nrow(mm))) {
      j <- variable_lookup$variable_idx[match(mm$variable[rr], variable_lookup$variable)]
      idx <- which(time_key == mm$time_key__[rr])
      if (!length(idx)) stop("collective shape scenario '", sid, "' selects no model rows.", call. = FALSE)
      if (any(data$is_holdout__[idx])) stop("collective shape scenario '", sid, "' selects holdout rows; use training rows only.", call. = FALSE)
      # Scale the complete pre-scenario support history. This preserves the
      # current-to-carryover balance and makes the shape term about saturation,
      # not an accidental perturbation of the adstock state.
      target_period <- match(mm$time_key__[rr], time_levels)
      history_idx <- which(match(time_key, time_levels) <= target_period)
      multiplier[cc, history_idx, j] <- as.numeric(mm$multiplier[rr])
      weight[cc, idx, j] <- as.numeric(data$rescale_factor__[idx])
      selected <- selected + length(idx)
    }
    audit[[cc]] <- data.table(
      reconciliation_id = sid,
      parent_node = as.character(scenarios$parent_node[cc] %||% NA_character_),
      mix_id = as.character(scenarios$mix_id[cc] %||% NA_character_),
      support_multiplier = as.numeric(scenarios$support_multiplier[cc] %||% NA_real_),
      parent_shape = as.numeric(scenarios$parent_shape[cc]),
      parent_shape_sd = sqrt(cov[cc, cc]),
      selected_member_n = nrow(mm),
      selected_row_variable_n = selected,
      reconciliation_likelihood = "multivariate_normal_soft_cross_multiplied_shape_residual"
    )
  }
  list(audit = rbindlist(audit, fill = TRUE), multiplier = multiplier, weight = weight,
       parent_shape = as.numeric(scenarios$parent_shape),
       parent_reference_response = as.numeric(scenarios$parent_reference_response),
       parent_shape_cov = cov)
}

prepare_stan_data_hier_mmm <- function(data,
                                       metadata_input,
                                       dep_var_col,
                                       group_col,
                                       time_col,
                                       entity_col,
                                       extra_control_cols = NULL,
                                       holiday_config = NULL,
                                       mean_index = TRUE,
                                       dep_mean_index_scope = c("group", "global"),
                                       x_mean_index_scope = c("group", "global"),
                                       dep_scale_col = NULL,
                                       holdout_col = NULL,
                                       holdout_value = TRUE,
                                       holdout_last_n = 0L,
                                       estimate_dvalue = FALSE,
                                       curve_prior_relax = 2,
                                       coef_prior_relax = 1.5,
                                       min_coef_sd_abs = 0.001,
                                       min_coef_sd_frac = 0.05,
                                       hard_prior_precision_threshold = 1e6,
                                       bound_one_sided_coef_defaults = TRUE,
                                       default_positive_coef_upper = 3,
                                       default_negative_coef_lower = -3,
                                       default_one_sided_coef_span = 6,
                                       curve_type_default = c("hill", "weibull"),
                                       coef_override_input = NULL,
                                       calibration_input = NULL,
                                       sequential_transfer_input = NULL,
                                       collective_saturation_reconciliation_input = NULL,
                                       collective_saturation_shape_reconciliation_input = NULL,
                                       context_effects = NULL,
                                       context_log_multiplier_bound = 2,
                                       allow_time_context = FALSE,
                                       coef_hierarchy_part_indices = NULL,
                                       coef_hierarchy_index_base = c("one", "zero"),
                                       intercept_type = "fourier",
                                       ucm_spec = NULL,
                                       use_ucm_metadata = FALSE,
                                       normalize_curve_x = TRUE,
                                       curve_normalization_scope = c("active_train", "all_train"),
                                       sample_curve_parameters = c("always", "never"),
                                       sample_coef_hierarchy = c("auto", "always", "never"),
                                       coef_hierarchy_auto_min_groups = 5L,
                                       coef_hierarchy_auto_min_scale = 0.25,
                                       coef_hierarchy_auto_min_geo_variation_share = 0.20,
                                       coef_parameterization = c("noncentered", "centered", "auto"),
                                       alpha_parameterization = c("noncentered", "centered", "shared"),
                                       ucm_parameterization = c("noncentered", "centered"),
                                       center_predictors_for_sampling = FALSE,
                                       allow_negative_curve_inputs = FALSE,
                                       stop_on_zero_variance = TRUE,
                                       alpha_mu_prior_mean = 1,
                                       alpha_mu_prior_sd = 0.5,
                                       alpha_sd_prior_sd = 0.25,
                                       level0_mu_prior_mean = 1,
                                       level0_mu_prior_sd = 0.35,
                                       level0_sd_prior_sd = 0.15,
                                       sigma_level_prior_sd = 0.03,
                                       season_sd_prior_sd = 0.10,
                                       cycle_sd_prior_sd = 0.08,
                                       gamma_prior_sd = 0.25,
                                       sigma_y_prior_sd = 0.25,
                                       sigma_y_floor = 0.005,
                                       sigma_y_upper = 5,
                                       likelihood = c("student_t", "normal"),
                                       student_t_nu = 5,
                                       prior_only = FALSE) {
  likelihood <- match.arg(likelihood)
  curve_type_default <- match.arg(curve_type_default)
  curve_normalization_scope <- normalize_curve_normalization_scope_hier_mmm(match.arg(curve_normalization_scope))
  sample_curve_parameters <- match.arg(sample_curve_parameters)
  sample_coef_hierarchy <- match.arg(sample_coef_hierarchy)
  coef_hierarchy_index_base <- match.arg(coef_hierarchy_index_base)
  coef_parameterization <- match.arg(coef_parameterization)
  alpha_parameterization <- match.arg(alpha_parameterization)
  ucm_parameterization <- match.arg(ucm_parameterization)
  alpha_parameterization_code <- switch(alpha_parameterization, noncentered = 1L, centered = 2L, shared = 3L)
  ucm_parameterization_code <- switch(ucm_parameterization, noncentered = 1L, centered = 2L)
  dep_mean_index_scope <- match.arg(dep_mean_index_scope)
  x_mean_index_scope <- match.arg(x_mean_index_scope)
  center_predictors_for_sampling <- isTRUE(center_predictors_for_sampling)
  coef_hierarchy_auto_min_groups <- as.integer(coef_hierarchy_auto_min_groups %||% 5L)[1]
  if (!is.finite(coef_hierarchy_auto_min_groups) || is.na(coef_hierarchy_auto_min_groups) || coef_hierarchy_auto_min_groups < 2L) {
    stop("coef_hierarchy_auto_min_groups must be an integer >= 2.")
  }
  coef_hierarchy_auto_min_scale <- as.numeric(coef_hierarchy_auto_min_scale)[1]
  coef_hierarchy_auto_min_geo_variation_share <- as.numeric(coef_hierarchy_auto_min_geo_variation_share)[1]
  if (!is.finite(coef_hierarchy_auto_min_scale) || is.na(coef_hierarchy_auto_min_scale) || coef_hierarchy_auto_min_scale < 0) {
    stop("coef_hierarchy_auto_min_scale must be finite and non-negative.")
  }
  if (!is.finite(coef_hierarchy_auto_min_geo_variation_share) ||
      is.na(coef_hierarchy_auto_min_geo_variation_share) ||
      coef_hierarchy_auto_min_geo_variation_share < 0 ||
      coef_hierarchy_auto_min_geo_variation_share > 1) {
    stop("coef_hierarchy_auto_min_geo_variation_share must be finite and between 0 and 1.")
  }
  if (!is.finite(student_t_nu) || is.na(student_t_nu) || student_t_nu <= 2) {
    stop("student_t_nu must be finite and > 2.")
  }
  sigma_y_floor <- as.numeric(sigma_y_floor)[1]
  if (!is.finite(sigma_y_floor) || is.na(sigma_y_floor) || sigma_y_floor < 0) stop("sigma_y_floor must be finite and non-negative.")
  sigma_y_upper <- as.numeric(sigma_y_upper)[1]
  if (!is.finite(sigma_y_upper) || is.na(sigma_y_upper) || sigma_y_upper <= sigma_y_floor) {
    stop("sigma_y_upper must be finite and greater than sigma_y_floor.")
  }
  context_log_multiplier_bound <- as.numeric(context_log_multiplier_bound)[1]
  if (!is.finite(context_log_multiplier_bound) || is.na(context_log_multiplier_bound) || context_log_multiplier_bound <= 0) {
    stop("context_log_multiplier_bound must be finite and > 0.")
  }
  allow_time_context <- isTRUE(allow_time_context)
  likelihood_family <- if (likelihood == "student_t") 2L else 1L

  dt <- as.data.table(copy(data))
  raw_metadata <- read_input_table(metadata_input)
  ucm_cfg <- extract_ucm_config_from_metadata(
    raw_metadata,
    intercept_type = intercept_type,
    ucm_spec = ucm_spec,
    alpha_mu_prior_mean = alpha_mu_prior_mean,
    alpha_mu_prior_sd = alpha_mu_prior_sd,
    alpha_sd_prior_sd = alpha_sd_prior_sd,
    level0_mu_prior_mean = level0_mu_prior_mean,
    level0_mu_prior_sd = level0_mu_prior_sd,
    level0_sd_prior_sd = level0_sd_prior_sd,
    sigma_level_prior_sd = sigma_level_prior_sd,
    season_sd_prior_sd = season_sd_prior_sd,
    cycle_sd_prior_sd = cycle_sd_prior_sd,
    gamma_prior_sd = gamma_prior_sd,
    sigma_y_prior_sd = sigma_y_prior_sd
  )
  if (isTRUE(use_ucm_metadata) && nrow(ucm_cfg$ucm_metadata)) {
    intercept_type <- ucm_cfg$intercept_type
    ucm_spec <- ucm_cfg$ucm_spec
    alpha_mu_prior_mean <- ucm_cfg$alpha_mu_prior_mean
    alpha_mu_prior_sd <- ucm_cfg$alpha_mu_prior_sd
    alpha_sd_prior_sd <- ucm_cfg$alpha_sd_prior_sd
    level0_mu_prior_mean <- ucm_cfg$level0_mu_prior_mean
    level0_mu_prior_sd <- ucm_cfg$level0_mu_prior_sd
    level0_sd_prior_sd <- ucm_cfg$level0_sd_prior_sd
    sigma_level_prior_sd <- ucm_cfg$sigma_level_prior_sd
    season_sd_prior_sd <- ucm_cfg$season_sd_prior_sd
    cycle_sd_prior_sd <- ucm_cfg$cycle_sd_prior_sd
    gamma_prior_sd <- ucm_cfg$gamma_prior_sd
    sigma_y_prior_sd <- ucm_cfg$sigma_y_prior_sd
  }
  md <- clean_metadata(
    raw_metadata,
    bound_one_sided_coef_defaults = bound_one_sided_coef_defaults,
    default_positive_coef_upper = default_positive_coef_upper,
    default_negative_coef_lower = default_negative_coef_lower,
    default_one_sided_coef_span = default_one_sided_coef_span,
    curve_type_default = curve_type_default
  )
  rf_rows <- which(md$role %in% c("reach_frequency", "organic_reach_frequency"))
  if (length(rf_rows)) {
    for (ii in rf_rows) {
      vv <- md$variable[ii]
      rc <- md$reach_col[ii]
      fc <- md$frequency_col[ii]
      pc <- md$population_col[ii]
      if (!is.na(rc) && rc %in% names(dt) && !(vv %in% names(dt))) {
        dt[, (vv) := as.numeric(get(rc))]
      }
      missing_rf <- setdiff(c(rc, fc, if (!is.na(pc)) pc else character()), names(dt))
      if (length(missing_rf)) {
        stop("reach_frequency variable '", vv, "' is missing required data column(s): ", paste(missing_rf, collapse = ", "))
      }
    }
  }

  req_data <- c(dep_var_col, group_col, time_col, entity_col)
  if (!all(req_data %in% names(dt))) stop("Data is missing one of: ", paste(req_data, collapse = ", "))
  if (!all(md$variable %in% names(dt))) {
    stop("These metadata variables are missing from data: ", paste(setdiff(md$variable, names(dt)), collapse = ", "))
  }
  if (!is.null(dep_scale_col) && !(dep_scale_col %in% names(dt))) {
    stop("dep_scale_col not found in data: ", dep_scale_col)
  }
  if (!is.null(holdout_col) && !(holdout_col %in% names(dt))) {
    stop("holdout_col not found in data: ", holdout_col)
  }
  holiday_controls <- add_holiday_controls_hier_mmm(
    data = dt,
    time_col = time_col,
    holiday_config = holiday_config,
    existing_extra_cols = extra_control_cols
  )
  dt <- holiday_controls$data
  extra_control_cols <- holiday_controls$extra_control_cols
  context_effects_clean <- clean_context_effects_hier_mmm(
    context_effects = context_effects,
    metadata = md,
    allow_time_context = allow_time_context
  )
  if (nrow(context_effects_clean)) {
    missing_context_vars <- setdiff(context_effects_clean$variable, md$variable)
    if (length(missing_context_vars)) {
      stop("context_effects references modeled variables missing from metadata: ", paste(missing_context_vars, collapse = ", "))
    }
    column_contexts <- context_effects_clean[context_type == "column", unique(context_key)]
    missing_context_cols <- setdiff(column_contexts, names(dt))
    if (length(missing_context_cols)) {
      stop("context_effects references context columns missing from data: ", paste(missing_context_cols, collapse = ", "))
    }
  }
  holdout_last_n <- as.integer(holdout_last_n %||% 0L)
  if (!is.finite(holdout_last_n) || is.na(holdout_last_n) || holdout_last_n < 0L) {
    stop("holdout_last_n must be a non-negative integer.")
  }
  if (length(extra_control_cols) && !all(extra_control_cols %in% names(dt))) {
    stop("These extra_control_cols are missing from data: ", paste(setdiff(extra_control_cols, names(dt)), collapse = ", "))
  }
  overlap_extra <- intersect(extra_control_cols %||% character(), md$variable)
  if (length(overlap_extra)) {
    stop("extra_control_cols cannot overlap metadata variables because that would double-count them: ",
         paste(overlap_extra, collapse = ", "))
  }

  if (dt[, anyDuplicated(data.table::data.table(group_key__ = get(group_col), time_key__ = get(time_col))) > 0L]) {
    stop("Data contains duplicate group_col + time_col rows. Each panel-week must be unique.")
  }

  if (anyNA(dt[[group_col]])) stop("group_col contains NA values.")
  if (anyNA(dt[[time_col]])) stop("time_col contains NA values.")

  context_keep_cols <- if (nrow(context_effects_clean)) context_effects_clean[context_type == "column", unique(context_key)] else character()
  rf_source_cols <- if (length(rf_rows)) {
    z <- c(md$reach_col[rf_rows], md$frequency_col[rf_rows], md$population_col[rf_rows])
    unique(z[!is.na(z) & nzchar(z)])
  } else character()
  keep_cols <- unique(c(group_col, time_col, entity_col, dep_var_col, md$variable, rf_source_cols, extra_control_cols, context_keep_cols, dep_scale_col, holdout_col))
  ignored_data_cols <- setdiff(names(dt), keep_cols)
  dt <- dt[, ..keep_cols]
  md[, `:=`(rf_reach_internal_col = NA_character_, rf_frequency_internal_col = NA_character_, rf_population_internal_col = NA_character_)]
  md[, `:=`(
    reference_internal_col = NA_character_,
    reference_value_raw = NA_real_,
    reference_value_model_scale = NA_real_,
    reference_value_source = NA_character_,
    x_scale_center = 0,
    x_scale_sd = 1,
    x_scaling = "mean_index"
  )]
  reference_rows <- which(md$role %in% c("control", "non_media_treatment"))
  if (length(reference_rows)) {
    for (ii in reference_rows) {
      reference_internal <- paste0("reference_raw__", ii)
      dt[, (reference_internal) := suppressWarnings(as.numeric(get(md$variable[ii])))]
      md[ii, reference_internal_col := reference_internal]
    }
  }
  if (length(rf_rows)) {
    for (ii in rf_rows) {
      reach_internal <- paste0("rf_reach_raw__", ii)
      frequency_internal <- paste0("rf_frequency_raw__", ii)
      population_internal <- paste0("rf_population_raw__", ii)
      dt[, (reach_internal) := suppressWarnings(as.numeric(get(md$reach_col[ii])))]
      dt[, (frequency_internal) := suppressWarnings(as.numeric(get(md$frequency_col[ii])))]
      if (!is.na(md$population_col[ii])) {
        dt[, (population_internal) := suppressWarnings(as.numeric(get(md$population_col[ii])))]
      } else {
        dt[, (population_internal) := 1]
      }
      md[ii, `:=`(
        rf_reach_internal_col = reach_internal,
        rf_frequency_internal_col = frequency_internal,
        rf_population_internal_col = population_internal
      )]
    }
  }

  dt[, y_original__ := as.numeric(get(dep_var_col))]
  if (!is.null(dep_scale_col)) {
    dt[, rescale_factor__ := as.numeric(get(dep_scale_col))]
  } else {
    dt[, rescale_factor__ := NA_real_]
  }

  # Each group must map to exactly one target entity
  entity_check <- unique(dt[, .(group_value = get(group_col), target_entity = as.character(get(entity_col)))])
  if (entity_check[, .N, by = group_value][N > 1L, .N] > 0L) {
    stop("Each group must map to exactly one target entity in entity_col.")
  }

  setorderv(dt, c(group_col, time_col))

  # Holdout must be marked before mean-indexing so validation rows do not leak into
  # training-scale denominators.
  dt[, is_holdout__ := FALSE]
  if (!is.null(holdout_col)) {
    hv <- holdout_value
    if (is.logical(hv) && length(hv) == 1L && isTRUE(hv)) {
      hv_raw <- tolower(trimws(as.character(dt[[holdout_col]])))
      hv_raw[is.na(hv_raw)] <- ""
      dt[, is_holdout__ := hv_raw %in% c("true", "t", "yes", "y", "1", "on", "holdout", "test")]
    } else if (is.logical(hv) && length(hv) == 1L && isFALSE(hv)) {
      hv_raw <- tolower(trimws(as.character(dt[[holdout_col]])))
      hv_raw[is.na(hv_raw)] <- ""
      dt[, is_holdout__ := hv_raw %in% c("false", "f", "no", "n", "0", "off", "holdout", "test")]
    } else {
      dt[, is_holdout__ := as.character(get(holdout_col)) %in% as.character(hv)]
    }
  }
  if (holdout_last_n > 0L) {
    dt[, is_holdout__ := is_holdout__ | (seq_len(.N) > pmax(.N - holdout_last_n, 0L)), by = group_col]
  }
  if (!dt[, any(!is_holdout__)]) {
    stop("All rows are marked as holdout. At least one training row is required.")
  }
  no_train_raw <- dt[, .(n_train = sum(!is_holdout__)), by = group_col][n_train == 0L]
  if (nrow(no_train_raw)) {
    stop("Each group must have at least one training row before mean-indexing. Groups with zero training rows: ",
         paste(no_train_raw[[group_col]], collapse = ", "))
  }
  if (length(reference_rows)) {
    for (ii in reference_rows) {
      ref <- resolve_reference_value_hier_mmm(
        x = dt[[md$reference_internal_col[ii]]],
        spec = md$reference_value_spec[ii],
        train_mask = !dt$is_holdout__,
        label = paste0("reference value for variable '", md$variable[ii], "'")
      )
      md[ii, `:=`(reference_value_raw = ref$value, reference_value_source = ref$source)]
    }
  }

  if (mean_index) {
    dt[, is_train_tmp__ := as.integer(!is_holdout__)]
    if (identical(dep_mean_index_scope, "group")) {
      dt[, rescale_factor__ := {
        y_train <- get(dep_var_col)[!is_holdout__]
        m <- mean(y_train[is.finite(y_train)], na.rm = TRUE)
        if (!is.finite(m) || is.na(m) || abs(m) <= 1e-8) 1 else m
      }, by = group_col]
      dt <- mean_index_by_group(dt, cols = dep_var_col, by = group_col, train_col = "is_train_tmp__")
    } else {
      y_train <- dt[[dep_var_col]][!dt$is_holdout__]
      dep_den <- mean(y_train[is.finite(y_train)], na.rm = TRUE)
      if (!is.finite(dep_den) || is.na(dep_den) || abs(dep_den) <= 1e-8) dep_den <- 1
      dt[, rescale_factor__ := dep_den]
      dt <- mean_index_global_cols(dt, cols = dep_var_col, train_col = "is_train_tmp__")
    }
    zscore_cols <- unique(c(md[role %in% c("control", "non_media_treatment"), variable], extra_control_cols))
    x_cols_to_index <- setdiff(md$variable, zscore_cols)
    if (identical(x_mean_index_scope, "group")) {
      dt <- mean_index_by_group(dt, cols = x_cols_to_index, by = group_col, train_col = "is_train_tmp__")
    } else {
      dt <- mean_index_global_cols(dt, cols = x_cols_to_index, train_col = "is_train_tmp__")
    }
    zscaled <- zscore_global_cols_hier_mmm(dt, cols = zscore_cols, train_col = "is_train_tmp__")
    dt <- zscaled$data
    if (nrow(zscaled$audit)) {
      md[zscaled$audit, on = .(variable), `:=`(
        x_scale_center = i.x_scale_center,
        x_scale_sd = i.x_scale_sd,
        x_scaling = i.x_scaling
      )]
    }
    dt[, is_train_tmp__ := NULL]
  } else {
    dt[!is.finite(rescale_factor__) | is.na(rescale_factor__) | abs(rescale_factor__) <= 1e-8, rescale_factor__ := 1]
  }
  if (length(reference_rows)) {
    md[reference_rows, reference_value_model_scale := (reference_value_raw - x_scale_center) / x_scale_sd]
  }

  dt[, y_model__ := as.numeric(get(dep_var_col))]
  dt[, rescale_factor__ := fifelse(!is.finite(rescale_factor__) | is.na(rescale_factor__) | abs(rescale_factor__) <= 1e-8, 1, rescale_factor__)]

  validate_numeric_input_cols(dt, c(dep_var_col, md$variable, extra_control_cols), label = "model input", stop_on_zero_variance = FALSE)
  finite_or_stop(dt$y_model__, "Dependent variable on model scale")
  finite_or_stop(dt$rescale_factor__, "rescale_factor__")

  global_var_sd <- vapply(md$variable, function(cc) safe_sd(dt[[cc]]), numeric(1))
  if (isTRUE(stop_on_zero_variance) && any(global_var_sd <= 1e-8)) {
    bad <- md$variable[global_var_sd <= 1e-8]
    stop("Metadata variables with zero/nearly-zero global variance cannot be estimated: ", paste(bad, collapse = ", "))
  }

  curve_input_vars <- md[has_curve == 1L, variable]
  if (length(curve_input_vars) && !isTRUE(allow_negative_curve_inputs)) {
    neg_curve <- vapply(curve_input_vars, function(cc) any(dt[[cc]] < 0, na.rm = TRUE), logical(1))
    if (any(neg_curve)) {
      stop("Curved variables cannot contain negative values because adstock/saturation uses non-negative exposure. Bad variables: ",
           paste(curve_input_vars[neg_curve], collapse = ", "))
    }
  }
  anchor_rows <- which(md$has_curve == 1L & as.logical(md$cvalue_from_anchor) & is.finite(md$anchor_saturation))
  if (length(anchor_rows)) {
    for (ii in anchor_rows) {
      vv <- md$variable[ii]
      loc <- if (md$role[ii] %in% c("reach_frequency", "organic_reach_frequency")) {
        frequency_train <- dt[[md$rf_frequency_internal_col[ii]]][!dt$is_holdout__]
        frequency_anchor <- stats::median(frequency_train[is.finite(frequency_train) & frequency_train > 0], na.rm = TRUE)
        odds <- md$anchor_saturation[ii] / (1 - md$anchor_saturation[ii])
        if (is.finite(frequency_anchor) && frequency_anchor > 0) odds^(1 / md$dvalue[ii]) / frequency_anchor else NA_real_
      } else {
        curve_rate_from_anchor_hier_mmm(
          x = dt[[vv]],
          rrate = md$rrate[ii],
          dvalue = md$dvalue[ii],
          anchor_saturation = md$anchor_saturation[ii],
          curve_type = md$curve_type[ii],
          train_mask = !dt$is_holdout__,
          normalize_curve_x = isTRUE(normalize_curve_x),
          curve_normalization_scope = curve_normalization_scope
        )
      }
      if (!is.finite(loc) || loc <= 0) {
        stop("Could not derive internal curve_rate from anchor_saturation for variable '", vv,
             "'. Provide explicit curve_rate or check that the variable has positive training support.")
      }
      md$cvalue[ii] <- clip_to_open_interval(loc, md$cvalue_lower[ii], md$cvalue_upper[ii])
      anchor_sd <- suppressWarnings(as.numeric(md$anchor_saturation_sd[ii]))
      if (is.finite(anchor_sd) && anchor_sd > 0) {
        anchor <- md$anchor_saturation[ii]
        eps <- min(1e-4, anchor / 4, (1 - anchor) / 4)
        rate_low <- curve_rate_from_anchor_hier_mmm(
          x = dt[[vv]], rrate = md$rrate[ii], dvalue = md$dvalue[ii],
          anchor_saturation = anchor - eps, curve_type = md$curve_type[ii],
          train_mask = !dt$is_holdout__, normalize_curve_x = isTRUE(normalize_curve_x),
          curve_normalization_scope = curve_normalization_scope
        )
        rate_high <- curve_rate_from_anchor_hier_mmm(
          x = dt[[vv]], rrate = md$rrate[ii], dvalue = md$dvalue[ii],
          anchor_saturation = anchor + eps, curve_type = md$curve_type[ii],
          train_mask = !dt$is_holdout__, normalize_curve_x = isTRUE(normalize_curve_x),
          curve_normalization_scope = curve_normalization_scope
        )
        derivative <- abs(rate_high - rate_low) / (2 * eps)
        rate_sd <- derivative * anchor_sd
        if (is.finite(rate_sd) && rate_sd > 1e-8) {
          md$cvalue_precision[ii] <- 1 / rate_sd^2
          md$cvalue_precision_defaulted[ii] <- FALSE
        }
      }
      md$anchor_source[ii] <- ifelse(
        is.na(md$anchor_source[ii]) || !nzchar(md$anchor_source[ii]),
        "direct_metadata_anchor",
        md$anchor_source[ii]
      )
    }
  }

  group_lookup <- unique(dt[, .(group_value = get(group_col), target_entity = as.character(get(entity_col)))])
  group_lookup[, group_idx := .I]
  setkey(group_lookup, group_value)

  # Robust group index assignment. Avoid x.* join prefixes so this works across data.table versions.
  dt[group_lookup, group_idx := i.group_idx, on = setNames("group_value", group_col)]
  if (anyNA(dt$group_idx)) {
    stop("Internal error: failed to map every row to a group_idx. Check group_col values and group_lookup construction.")
  }
  setorderv(dt, c("group_idx", time_col))

  ranges <- dt[, .(start_idx = .I[1], end_idx = .I[.N]), by = group_idx][order(group_idx)]

  train_idx <- which(!dt$is_holdout__)
  holdout_idx <- which(dt$is_holdout__)
  if (!length(train_idx)) stop("All rows are marked as holdout. At least one training row is required.")
  no_train_groups <- dt[, .(n_train = sum(!is_holdout__)), by = group_idx][n_train == 0L, group_idx]
  if (length(no_train_groups)) {
    bad_groups <- group_lookup[group_idx %in% no_train_groups, group_value]
    stop("Each group must have at least one training row. Groups with zero training rows: ", paste(bad_groups, collapse = ", "))
  }
  if (length(train_idx) < max(10L, nrow(group_lookup))) {
    warning("Very few training rows remain after holdout selection; posterior may be weakly identified.")
  }

  variable_lookup <- copy(md)[, .(
    variable, source_entity, role, has_curve, coef_bound, bound_type, coef_lower, coef_upper,
    coef_hierarchy_scale, coef_hierarchy_scope, hierarchy_key, model_id_parts,
    hierarchy_part_indices, hierarchy_note,
    curve_type, curve_bound, rrate_bound, cvalue_bound, dvalue_bound,
    anchor_saturation, anchor_saturation_sd, anchor_saturation_precision, anchor_source, cvalue_from_anchor,
    non_media_baseline_values, control_reference_values, reference_value_spec,
    reference_value_raw, reference_value_model_scale, reference_value_source,
    x_scale_center, x_scale_sd, x_scaling,
    reach_col, frequency_col, population_col, rf_spend_col,
    rf_reach_internal_col, rf_frequency_internal_col, rf_population_internal_col
  )]
  variable_lookup[, variable_idx := .I]
  variable_lookup[, curve_param_idx := 0L]
  variable_lookup[has_curve == 1L, curve_param_idx := seq_len(.N)]

  context_effect_audit <- copy(context_effects_clean)
  X_context <- matrix(0, nrow = nrow(dt), ncol = nrow(context_effect_audit))
  if (nrow(context_effect_audit)) {
    context_effect_audit[, variable_idx := match(variable, variable_lookup$variable)]
    if (anyNA(context_effect_audit$variable_idx)) {
      stop("Internal error: failed to map context_effects variable to variable_lookup.")
    }
    for (h in seq_len(nrow(context_effect_audit))) {
      ck <- context_effect_audit$context_key[h]
      if (identical(context_effect_audit$context_type[h], "time")) {
        raw_vec <- dt[, seq_len(.N), by = group_col]$V1
      } else {
        raw_vec <- suppressWarnings(as.numeric(dt[[ck]]))
      }
      if (any(!is.finite(raw_vec) | is.na(raw_vec))) {
        stop("Context driver '", ck, "' for variable '", context_effect_audit$variable[h],
             "' contains NA/non-finite values. Clean or impute it before fitting.")
      }
      target_vec <- suppressWarnings(as.numeric(dt[[context_effect_audit$variable[h]]]))
      m <- mean(raw_vec[train_idx], na.rm = TRUE)
      s <- safe_sd(raw_vec[train_idx])
      if (!is.finite(s) || is.na(s) || s <= 1e-8) {
        stop("Context driver '", ck, "' for variable '", context_effect_audit$variable[h],
             "' has zero/nearly-zero training variance.")
      }
      X_context[, h] <- (raw_vec - m) / s
      z_train <- X_context[train_idx, h]
      z_min <- min(z_train, na.rm = TRUE)
      z_max <- max(z_train, na.rm = TRUE)
      coef_mu_h <- context_effect_audit$context_coef_mean[h]
      coef_sd_h <- context_effect_audit$context_coef_sd[h]
      coef_lo <- coef_mu_h - 2 * coef_sd_h
      coef_hi <- coef_mu_h + 2 * coef_sd_h
      log_candidates <- c(z_min * coef_lo, z_min * coef_hi, z_max * coef_lo, z_max * coef_hi)
      log_candidates <- clip_numeric(log_candidates, -context_log_multiplier_bound, context_log_multiplier_bound)
      prior_mult_min <- exp(min(log_candidates, na.rm = TRUE))
      prior_mult_max <- exp(max(log_candidates, na.rm = TRUE))
      target_corr <- safe_cor(raw_vec[train_idx], target_vec[train_idx])
      modeled_context <- identical(context_effect_audit$context_type[h], "column") && ck %in% variable_lookup$variable
      reasons <- character()
      if (identical(context_effect_audit$context_type[h], "time")) reasons <- c(reasons, "time_context_advanced_drift_risk")
      if (isTRUE(modeled_context)) reasons <- c(reasons, "context_is_modeled_variable_interaction")
      if (is.finite(target_corr) && abs(target_corr) >= 0.80) reasons <- c(reasons, "context_highly_correlated_with_target_support")
      if (is.finite(prior_mult_min) && prior_mult_min < 0.25) reasons <- c(reasons, "prior_allows_large_downward_multiplier")
      if (is.finite(prior_mult_max) && prior_mult_max > 4) reasons <- c(reasons, "prior_allows_large_upward_multiplier")
      risk_level <- if (
        identical(context_effect_audit$context_type[h], "time") ||
          (is.finite(target_corr) && abs(target_corr) >= 0.95) ||
          (is.finite(prior_mult_min) && prior_mult_min < 1 / 6) ||
          (is.finite(prior_mult_max) && prior_mult_max > 6)
      ) {
        "high_review"
      } else if (length(reasons)) {
        "review"
      } else {
        "standard"
      }
      context_effect_audit[h, `:=`(
        context_train_mean = m,
        context_train_sd = s,
        context_train_min_z = z_min,
        context_train_max_z = z_max,
        context_is_modeled_variable = modeled_context,
        context_train_corr_with_target_support = target_corr,
        prior_multiplier_min_train_range = prior_mult_min,
        prior_multiplier_max_train_range = prior_mult_max,
        context_risk_level = risk_level,
        context_risk_reasons = if (length(reasons)) paste(reasons, collapse = "; ") else NA_character_,
        context_note = fifelse(
          context_type == "time",
          "advanced time special key: generated as within-group row index, then standardized on training rows; use only for an explicit drift hypothesis and prefer real seasonality/trend controls when available",
          "named data column: standardized on training rows"
        )
      )]
    }
  }
  storage.mode(X_context) <- "double"

  curve_priors <- build_curve_priors(
    md,
    estimate_dvalue = estimate_dvalue,
    curve_prior_relax = curve_prior_relax
  )

  variable_lookup[curve_priors, on = "variable", `:=`(
    rrate_raw_mu = i.rrate_raw_mu, rrate_raw_sd = i.rrate_raw_sd,
    cvalue_raw_mu = i.cvalue_raw_mu, cvalue_raw_sd = i.cvalue_raw_sd,
    dvalue_raw_mu = i.dvalue_raw_mu, dvalue_raw_sd = i.dvalue_raw_sd,
    use_observed_cvalue_prior = i.use_observed_cvalue_prior,
    observed_cvalue_raw_mu = i.observed_cvalue_raw_mu,
    observed_cvalue_raw_sd = i.observed_cvalue_raw_sd,
    observed_cvalue_mu = i.observed_cvalue_mu,
    observed_cvalue_reliability = i.observed_cvalue_reliability,
    observed_cvalue_source = i.observed_cvalue_source,
    rrate_lower = i.rrate_lower, rrate_upper = i.rrate_upper,
    cvalue_lower = i.cvalue_lower, cvalue_upper = i.cvalue_upper,
    dvalue_lower = i.dvalue_lower, dvalue_upper = i.dvalue_upper
  )]

  model_var_cols <- variable_lookup$variable
  X <- as.matrix(dt[, ..model_var_cols]); storage.mode(X) <- "double"
  X_center_mean <- matrix(0, nrow = nrow(group_lookup), ncol = nrow(variable_lookup))
  if (isTRUE(center_predictors_for_sampling) && nrow(X_center_mean) && ncol(X_center_mean)) {
    for (g in seq_len(nrow(group_lookup))) {
      idx <- which(dt$group_idx == g & !dt$is_holdout__)
      if (!length(idx)) idx <- which(dt$group_idx == g)
      for (j in seq_len(ncol(X_center_mean))) {
        m <- mean(X[idx, j], na.rm = TRUE)
        X_center_mean[g, j] <- if (is.finite(m) && !is.na(m)) m else 0
      }
    }
  }
  storage.mode(X_center_mean) <- "double"
  Z_extra <- if (length(extra_control_cols)) as.matrix(dt[, ..extra_control_cols]) else matrix(0, nrow(dt), 0)
  storage.mode(Z_extra) <- "double"

  comp <- build_coef_prior_components(
    md,
    coef_prior_relax = coef_prior_relax,
    min_coef_sd_abs = min_coef_sd_abs,
    min_coef_sd_frac = min_coef_sd_frac,
    hard_prior_precision_threshold = hard_prior_precision_threshold
  )

  lookup_variable_indices <- function(vars, label) {
    vars <- as.character(vars %||% character())
    if (!length(vars)) return(integer())
    idx <- match(vars, variable_lookup$variable)
    if (anyNA(idx)) {
      stop("Internal error: ", label, " contains variables missing from variable_lookup: ",
           paste(vars[is.na(idx)], collapse = ", "))
    }
    as.integer(variable_lookup$variable_idx[idx])
  }

  pos_idx <- lookup_variable_indices(comp$pos$dt$variable, "positive coefficient block")
  neg_idx <- lookup_variable_indices(comp$neg$dt$variable, "negative coefficient block")
  lower_idx <- lookup_variable_indices(comp$lower$dt$variable, "lower-bounded coefficient block")
  upper_idx <- lookup_variable_indices(comp$upper$dt$variable, "upper-bounded coefficient block")
  bounded_idx <- lookup_variable_indices(comp$bounded$dt$variable, "fully bounded coefficient block")
  free_idx <- lookup_variable_indices(comp$free$dt$variable, "free coefficient block")
  block_sample_hierarchy <- function(vars) {
    vars <- as.character(vars %||% character())
    if (!length(vars)) return(integer())
    idx <- match(vars, variable_lookup$variable)
    as.integer(variable_lookup$sample_coef_hierarchy_flag[idx] %||% 0L)
  }
  block_hierarchy_mode <- function(vars) {
    vars <- as.character(vars %||% character())
    if (!length(vars)) return(integer())
    idx <- match(vars, variable_lookup$variable)
    mode <- as.integer(variable_lookup$coef_hierarchy_mode[idx] %||% 0L)
    sample_flag <- as.integer(variable_lookup$sample_coef_hierarchy_flag[idx] %||% 0L)
    mode[sample_flag != 1L] <- 0L
    mode
  }
  block_centered_hierarchy <- function(vars) {
    vars <- as.character(vars %||% character())
    if (!length(vars)) return(integer())
    idx <- match(vars, variable_lookup$variable)
    sample_flag <- as.integer(variable_lookup$sample_coef_hierarchy_flag[idx] %||% 0L)
    mode <- as.integer(variable_lookup$coef_hierarchy_mode[idx] %||% 0L)
    centered <- integer(length(vars))
    if (coef_parameterization == "centered") {
      centered <- sample_flag
    } else if (coef_parameterization == "auto") {
      # Stan's usual centered/non-centered tradeoff: centered can mix better
      # when each group coefficient is well informed and the group variation
      # prior is not tiny; non-centered is safer for sparse/weak group data.
      train_by_group <- as.numeric(dt[!is_holdout__, .N, by = group_idx][order(group_idx), N])
      min_group_train <- if (length(train_by_group)) min(train_by_group, na.rm = TRUE) else 0
      strong_group_signal <- variable_lookup$geo_variation_week_share[idx] >= max(coef_hierarchy_auto_min_geo_variation_share, 0.35) &
        variable_lookup$coef_hierarchy_scale[idx] >= max(coef_hierarchy_auto_min_scale, 0.50) &
        min_group_train >= 24L
      centered <- as.integer(sample_flag == 1L & strong_group_signal)
    }
    centered[mode == 2L] <- 0L
    as.integer(centered)
  }
  block_hier_positions <- function(vars) {
    flags <- block_sample_hierarchy(vars)
    as.integer(which(flags == 1L))
  }
  curve_sampled_pos <- variable_lookup[has_curve == 1L, which(rep(as.integer(sample_curve_parameters == "always"), .N) == 1L)]

  curve_idx <- variable_lookup[has_curve == 1L, variable_idx]
  linear_idx <- variable_lookup[has_curve == 0L, variable_idx]
  is_rf_curve <- variable_lookup[has_curve == 1L, as.integer(role %in% c("reach_frequency", "organic_reach_frequency"))]
  X_rf_reach <- matrix(0, nrow = nrow(dt), ncol = length(curve_idx))
  X_rf_frequency <- matrix(0, nrow = nrow(dt), ncol = length(curve_idx))
  variable_lookup[, rf_reach_train_scale := NA_real_]
  if (length(curve_idx)) {
    for (k in seq_along(curve_idx)) {
      if (is_rf_curve[k] != 1L) next
      j <- curve_idx[k]
      reach_raw <- suppressWarnings(as.numeric(dt[[variable_lookup$rf_reach_internal_col[j]]]))
      frequency_raw <- suppressWarnings(as.numeric(dt[[variable_lookup$rf_frequency_internal_col[j]]]))
      population_raw <- suppressWarnings(as.numeric(dt[[variable_lookup$rf_population_internal_col[j]]]))
      if (any(!is.finite(reach_raw) | reach_raw < 0)) stop("RF reach must be finite and non-negative for variable: ", variable_lookup$variable[j])
      if (any(!is.finite(frequency_raw) | frequency_raw < 0)) stop("RF frequency must be finite and non-negative for variable: ", variable_lookup$variable[j])
      if (any(!is.finite(population_raw) | population_raw <= 0)) stop("RF population must be finite and positive for variable: ", variable_lookup$variable[j])
      reach_per_capita <- reach_raw / population_raw
      scale_mask <- !dt$is_holdout__ & is.finite(reach_per_capita) & reach_per_capita > 0
      reach_scale <- stats::median(reach_per_capita[scale_mask], na.rm = TRUE)
      if (!is.finite(reach_scale) || reach_scale <= 1e-12) stop("RF reach has no positive training support for variable: ", variable_lookup$variable[j])
      X_rf_reach[, k] <- reach_per_capita / reach_scale
      X_rf_frequency[, k] <- frequency_raw
      variable_lookup[j, rf_reach_train_scale := reach_scale]
    }
  }
  storage.mode(X_rf_reach) <- "double"
  storage.mode(X_rf_frequency) <- "double"

  intercept_spec <- parse_model_intercept(intercept_type = intercept_type, ucm_spec = ucm_spec)
  if (isTRUE(center_predictors_for_sampling) && intercept_spec$intercept_mode == 0L) {
    warning("center_predictors_for_sampling was disabled because intercept_type = 'none' has no baseline term to absorb the centered predictor means.")
    center_predictors_for_sampling <- FALSE
  }

  X_curve_fixed <- matrix(0, nrow = nrow(dt), ncol = length(curve_idx))
  X_curve_fixed_center <- matrix(0, nrow = nrow(group_lookup), ncol = length(curve_idx))
  if (length(curve_idx)) {
    curve_raw_to_value <- function(raw, lower, upper) {
      lower + (upper - lower) * stats::plogis(raw)
    }
    for (k in seq_along(curve_idx)) {
      j <- curve_idx[k]
      rr <- curve_raw_to_value(variable_lookup$rrate_raw_mu[j], variable_lookup$rrate_lower[j], variable_lookup$rrate_upper[j])
      cv <- curve_raw_to_value(variable_lookup$cvalue_raw_mu[j], variable_lookup$cvalue_lower[j], variable_lookup$cvalue_upper[j])
      dv <- curve_raw_to_value(variable_lookup$dvalue_raw_mu[j], variable_lookup$dvalue_lower[j], variable_lookup$dvalue_upper[j])
      curve_type_k <- variable_lookup$curve_type[j] %||% curve_type_default
      for (g in seq_len(nrow(group_lookup))) {
        idx <- which(dt$group_idx == g)
        if (!length(idx)) next
        tr <- if (is_rf_curve[k] == 1L) {
          reach_frequency_transform_hier_mmm(
            reach_scaled = X_rf_reach[idx, k],
            frequency = X_rf_frequency[idx, k],
            rrate = rr,
            cvalue = cv,
            dvalue = dv,
            train_mask = !dt$is_holdout__[idx],
            normalize_curve_x = isTRUE(normalize_curve_x),
            curve_normalization_scope = curve_normalization_scope
          )
        } else {
          media_transform_hier_mmm(
            x = X[idx, j],
            rrate = rr,
            cvalue = cv,
            dvalue = dv,
            curve_type = curve_type_k,
            train_mask = !dt$is_holdout__[idx],
            normalize_curve_x = isTRUE(normalize_curve_x),
            curve_normalization_scope = curve_normalization_scope,
            multiplier = 1
          )
        }
        X_curve_fixed[idx, k] <- tr$transformed
        X_curve_fixed_center[g, k] <- tr$center_value
      }
    }
  }
  storage.mode(X_curve_fixed) <- "double"
  storage.mode(X_curve_fixed_center) <- "double"

  season_X <- matrix(0, nrow(dt), 0)
  if (intercept_spec$use_season == 1L) {
    season_X <- build_fourier_matrix(
      dt[[time_col]],
      period = intercept_spec$season_period,
      harmonics = intercept_spec$season_harmonics
    )
  }
  storage.mode(season_X) <- "double"

  cycle_X <- matrix(0, nrow(dt), 0)
  if (intercept_spec$use_cycle == 1L) {
    cycle_X <- build_fourier_matrix(
      dt[[time_col]],
      period = intercept_spec$cycle_period,
      harmonics = intercept_spec$cycle_harmonics
    )
    if (ncol(cycle_X)) colnames(cycle_X) <- sub("^season_", "cycle_", colnames(cycle_X))
  }
  storage.mode(cycle_X) <- "double"

  target_entities <- unique(as.character(dt[[entity_col]]))
  target_entities[is.na(target_entities)] <- ""
  variable_lookup[, possible_halo_somewhere := as.integer(source_entity[1] != "GLOBAL" && any(target_entities != source_entity[1])), by = variable]
  geo_variation <- assess_group_exposure_variation(
    dt = dt,
    variables = variable_lookup$variable,
    group_col = group_col,
    time_col = time_col
  )
  variable_lookup[geo_variation, on = "variable", `:=`(
    geo_variation_week_share = i.geo_variation_week_share,
    geo_variation_median_cv = i.geo_variation_median_cv
  )]
  variable_lookup[!is.finite(geo_variation_week_share) | is.na(geo_variation_week_share), geo_variation_week_share := 0]
  variable_lookup[!is.finite(geo_variation_median_cv) | is.na(geo_variation_median_cv), geo_variation_median_cv := 0]
  coef_hierarchy_key <- build_coef_hierarchy_key_map(
    group_lookup = group_lookup,
    variable_lookup = variable_lookup,
    hierarchy_part_indices = coef_hierarchy_part_indices,
    hierarchy_index_base = coef_hierarchy_index_base
  )
  group_lookup <- coef_hierarchy_key$group_lookup
  variable_lookup[coef_hierarchy_key$variable_key_audit, on = "variable", `:=`(
    keyed_family_count = i.keyed_family_count,
    hierarchy_part_indices_effective = i.hierarchy_part_indices_effective,
    keyed_single_family = i.keyed_single_family
  )]
  variable_lookup[is.na(keyed_single_family), keyed_single_family := FALSE]
  variable_lookup[, coef_hierarchy_mode := fifelse(
    coef_hierarchy_scope == "keyed" & !keyed_single_family, 2L,
    fifelse(coef_hierarchy_scope %in% c("auto", "global") | (coef_hierarchy_scope == "keyed" & keyed_single_family), 1L, 0L)
  )]
  variable_lookup[coef_hierarchy_scope == "keyed" & keyed_single_family == TRUE,
                  hierarchy_note := paste0(hierarchy_note, " Keyed mapping produced one family, so Stan collapses it to the regular global hierarchy to avoid an unnecessary extra latent layer.")]
  variable_lookup[, hierarchy_blocker_reason := NA_character_]
  variable_lookup[coef_hierarchy_scope == "none", hierarchy_blocker_reason := "coef_hierarchy_scope_none"]
  auto_hierarchy_roles <- auto_coef_hierarchy_roles_hier_mmm()
  variable_lookup[, sample_coef_hierarchy_flag := {
    eligible_scope <- coef_hierarchy_scope %in% c("auto", "global", "keyed") & coef_hierarchy_scale > 0
    if (sample_coef_hierarchy == "always") {
      explicit_scope <- coef_hierarchy_scope %in% c("global", "keyed")
      auto_scope <- coef_hierarchy_scope == "auto" & role %in% auto_hierarchy_roles
      as.integer(nrow(group_lookup) > 1L & eligible_scope & (explicit_scope | auto_scope))
    } else if (sample_coef_hierarchy == "never") {
      0L
    } else {
      global_flag <- coef_hierarchy_scope == "global" & nrow(group_lookup) > 1L & eligible_scope
      keyed_flag <- coef_hierarchy_scope == "keyed" & nrow(group_lookup) > 1L & eligible_scope
      auto_flag <- (
        nrow(group_lookup) > 1L &
          nrow(group_lookup) >= coef_hierarchy_auto_min_groups &
          coef_hierarchy_scale >= coef_hierarchy_auto_min_scale &
          geo_variation_week_share >= coef_hierarchy_auto_min_geo_variation_share &
          eligible_scope &
          coef_hierarchy_scope == "auto" &
          role %in% auto_hierarchy_roles
      )
      as.integer(global_flag | keyed_flag | auto_flag)
    }
  }]
  variable_lookup[sample_coef_hierarchy_flag == 0L & is.na(hierarchy_blocker_reason) &
                    coef_hierarchy_scope == "auto" & !(role %in% auto_hierarchy_roles),
                  hierarchy_blocker_reason := "auto_hierarchy_role_not_media_treatment"]
  variable_lookup[coef_hierarchy_scope == "keyed" & keyed_single_family == TRUE & sample_coef_hierarchy_flag == 1L,
                  hierarchy_blocker_reason := NA_character_]
  variable_lookup[sample_coef_hierarchy_flag == 0L & is.na(hierarchy_blocker_reason) & coef_hierarchy_scope == "keyed",
                  hierarchy_blocker_reason := "keyed_hierarchy_inactive_by_sample_coef_hierarchy_or_group_count"]
  variable_lookup[sample_coef_hierarchy_flag == 0L & is.na(hierarchy_blocker_reason) & coef_hierarchy_scale <= 0,
                  hierarchy_blocker_reason := "coef_hierarchy_scale_zero"]
  variable_lookup[sample_coef_hierarchy_flag == 0L & is.na(hierarchy_blocker_reason) &
                    geo_variation_week_share < coef_hierarchy_auto_min_geo_variation_share,
                  hierarchy_blocker_reason := "insufficient_geo_media_variation_for_auto_hierarchy"]
  variable_lookup[sample_coef_hierarchy_flag == 0L & is.na(hierarchy_blocker_reason) &
                    nrow(group_lookup) < coef_hierarchy_auto_min_groups & sample_coef_hierarchy == "auto",
                  hierarchy_blocker_reason := "insufficient_group_count_for_auto_hierarchy"]

  coef_overrides <- clean_coef_override_input(
    coef_override_input = coef_override_input,
    group_col = group_col,
    metadata = md,
    group_lookup = group_lookup
  )
  context_sign_code <- if (nrow(context_effect_audit)) as.integer(context_effect_audit$context_sign_code) else integer()
  context_pos_pos <- which(context_sign_code == 1L)
  context_neg_pos <- which(context_sign_code == -1L)
  context_free_pos <- which(context_sign_code == 0L)
  experiment_calibration <- build_experiment_calibration_hier_mmm(
    calibration_input = calibration_input,
    data = dt,
    variable_lookup = variable_lookup,
    group_col = group_col,
    time_col = time_col
  )
  sequential_transfer <- build_sequential_transfer_hier_mmm(
    transfer_input = sequential_transfer_input,
    data = dt,
    variable_lookup = variable_lookup
  )
  if (sequential_transfer$adstock$child_n > 0L && identical(sample_curve_parameters, "never")) {
    stop("Hierarchical sequential adstock transfer requires sample_curve_parameters = 'always'.")
  }
  collective_reconciliation <- build_collective_saturation_reconciliation_hier_mmm(
    reconciliation_input = collective_saturation_reconciliation_input,
    data = dt,
    variable_lookup = variable_lookup,
    group_col = group_col,
    time_col = time_col
  )
  collective_shape_reconciliation <- build_collective_saturation_shape_reconciliation_hier_mmm(
    reconciliation_input = collective_saturation_shape_reconciliation_input,
    data = dt,
    variable_lookup = variable_lookup,
    group_col = group_col,
    time_col = time_col
  )

  stan_data <- list(
    prior_only = as.integer(isTRUE(prior_only)),
    N = nrow(dt),
    J = nrow(variable_lookup),
    G = nrow(group_lookup),
    K_extra = ncol(Z_extra),

    y = as.numeric(dt[[dep_var_col]]),
    X = X,
    X_center_mean = X_center_mean,
    Z_extra = Z_extra,

    N_train = length(train_idx),
    train_idx = as.integer(train_idx),
    is_train = as.integer(!dt$is_holdout__),

    group_id = as.integer(dt$group_idx),
    start_idx = as.integer(ranges$start_idx),
    end_idx = as.integer(ranges$end_idx),
    K_coef_hierarchy_keys = nrow(coef_hierarchy_key$key_lookup),
    group_coef_hierarchy_key_id = matrix(as.integer(coef_hierarchy_key$group_key_id), nrow = nrow(group_lookup), ncol = nrow(variable_lookup)),
    N_state_innov = if (intercept_spec$use_level == 1L) nrow(dt) - nrow(ranges) else 0L,

    has_curve = as.integer(variable_lookup$has_curve),
    J_curve = length(curve_idx),
    J_linear = length(linear_idx),
    curve_idx = as.integer(curve_idx),
    linear_idx = as.integer(linear_idx),
    curve_type = variable_lookup[has_curve == 1L, as.integer(fifelse(curve_type == "hill", 2L, 1L))],
    is_rf_curve = as.integer(is_rf_curve),
    X_rf_reach = X_rf_reach,
    X_rf_frequency = X_rf_frequency,
    X_curve_fixed = X_curve_fixed,
    X_curve_fixed_center = X_curve_fixed_center,
    C_calibration = nrow(experiment_calibration$audit),
    calibration_variable_idx = experiment_calibration$variable_idx,
    calibration_weight = experiment_calibration$weight,
    calibration_observed_lift = experiment_calibration$observed_lift,
    calibration_observed_sd = experiment_calibration$observed_sd,
    S_seq_effect = sequential_transfer$effectiveness$child_n,
    P_seq_effect = sequential_transfer$effectiveness$parent_n,
    H_seq_effect = as.integer(sequential_transfer$effectiveness$parent_n > 0L),
    seq_effect_variable_idx = sequential_transfer$effectiveness$variable_idx,
    seq_effect_parent_idx = sequential_transfer$effectiveness$parent_idx,
    seq_effect_weight = sequential_transfer$effectiveness$weight,
    seq_effect_reference_spend = sequential_transfer$effectiveness$reference_spend,
    seq_effect_child_noise_sd = sequential_transfer$effectiveness$child_noise_sd,
    seq_effect_child_share = sequential_transfer$effectiveness$child_share,
    seq_effect_parent_mu = sequential_transfer$effectiveness$parent_mu,
    seq_effect_parent_sd = sequential_transfer$effectiveness$parent_sd,
    seq_effect_tau_prior_mean = sequential_transfer$effectiveness$tau_prior_mean,
    seq_effect_tau_prior_sd = sequential_transfer$effectiveness$tau_prior_sd,
    seq_effect_aggregate_sd = sequential_transfer$effectiveness$aggregate_sd,
    S_seq_adstock = sequential_transfer$adstock$child_n,
    P_seq_adstock = sequential_transfer$adstock$parent_n,
    H_seq_adstock = as.integer(sequential_transfer$adstock$parent_n > 0L),
    seq_adstock_curve_idx = sequential_transfer$adstock$curve_idx,
    seq_adstock_parent_idx = sequential_transfer$adstock$parent_idx,
    seq_adstock_parent_mu_logit = sequential_transfer$adstock$parent_mu_logit,
    seq_adstock_parent_sd_logit = sequential_transfer$adstock$parent_sd_logit,
    seq_adstock_tau_prior_mean_logit = sequential_transfer$adstock$tau_prior_mean_logit,
    seq_adstock_tau_prior_sd_logit = sequential_transfer$adstock$tau_prior_sd_logit,
    seq_adstock_child_noise_sd_logit = sequential_transfer$adstock$child_noise_sd_logit,
    C_collective_reconciliation = nrow(collective_reconciliation$audit),
    collective_reconciliation_weight = collective_reconciliation$weight,
    collective_parent_response = collective_reconciliation$observed,
    collective_parent_response_sd = collective_reconciliation$observed_sd,
    C_collective_shape = nrow(collective_shape_reconciliation$audit),
    collective_shape_multiplier = collective_shape_reconciliation$multiplier,
    collective_shape_weight = collective_shape_reconciliation$weight,
    collective_parent_shape = collective_shape_reconciliation$parent_shape,
    collective_parent_reference_response = collective_shape_reconciliation$parent_reference_response,
    collective_parent_shape_cov = collective_shape_reconciliation$parent_shape_cov,
    K_context = ncol(X_context),
    X_context = X_context,
    context_variable_idx = if (nrow(context_effect_audit)) as.integer(context_effect_audit$variable_idx) else integer(),
    context_coef_mu = if (nrow(context_effect_audit)) as.numeric(context_effect_audit$context_coef_mean) else numeric(),
    context_coef_sd = if (nrow(context_effect_audit)) as.numeric(context_effect_audit$context_coef_sd) else numeric(),
    context_sign = context_sign_code,
    K_context_pos = length(context_pos_pos),
    K_context_neg = length(context_neg_pos),
    K_context_free = length(context_free_pos),
    context_pos_pos = as.integer(context_pos_pos),
    context_neg_pos = as.integer(context_neg_pos),
    context_free_pos = as.integer(context_free_pos),
    context_log_multiplier_bound = as.numeric(context_log_multiplier_bound),

    intercept_mode = as.integer(intercept_spec$intercept_mode),
    intercept_use_level = as.integer(intercept_spec$use_level),
    intercept_use_season = as.integer(intercept_spec$use_season),
    intercept_use_cycle = as.integer(intercept_spec$use_cycle),
    K_season = ncol(season_X),
    X_season = season_X,
    K_cycle = ncol(cycle_X),
    X_cycle = cycle_X,

    J_pos = length(pos_idx),
    J_neg = length(neg_idx),
    J_lower = length(lower_idx),
    J_upper = length(upper_idx),
    J_bounded = length(bounded_idx),
    J_free = length(free_idx),

    pos_idx = as.integer(pos_idx),
    neg_idx = as.integer(neg_idx),
    lower_idx = as.integer(lower_idx),
    upper_idx = as.integer(upper_idx),
    bounded_idx = as.integer(bounded_idx),
    free_idx = as.integer(free_idx),

    bounded_lower = if (length(bounded_idx)) comp$bounded$dt$coef_lower else numeric(),
    bounded_upper = if (length(bounded_idx)) comp$bounded$dt$coef_upper else numeric(),
    lower_only_lower = if (length(lower_idx)) comp$lower$dt$coef_lower else numeric(),
    upper_only_upper = if (length(upper_idx)) comp$upper$dt$coef_upper else numeric(),

    rrate_raw_mu = variable_lookup[has_curve == 1L, rrate_raw_mu],
    rrate_raw_sd = variable_lookup[has_curve == 1L, rrate_raw_sd],
    cvalue_raw_mu = variable_lookup[has_curve == 1L, cvalue_raw_mu],
    cvalue_raw_sd = variable_lookup[has_curve == 1L, cvalue_raw_sd],
    dvalue_raw_mu = variable_lookup[has_curve == 1L, dvalue_raw_mu],
    dvalue_raw_sd = variable_lookup[has_curve == 1L, dvalue_raw_sd],
    use_observed_cvalue_prior = variable_lookup[has_curve == 1L, as.integer(use_observed_cvalue_prior %||% 0L)],
    sample_curve_parameter = variable_lookup[has_curve == 1L, rep(as.integer(sample_curve_parameters == "always"), .N)],
    J_curve_sampled = length(curve_sampled_pos),
    curve_sampled_pos = as.integer(curve_sampled_pos),
    observed_cvalue_raw_mu = variable_lookup[has_curve == 1L, fifelse(is.finite(observed_cvalue_raw_mu), observed_cvalue_raw_mu, 0)],
    observed_cvalue_raw_sd = variable_lookup[has_curve == 1L, pmax(fifelse(is.finite(observed_cvalue_raw_sd), observed_cvalue_raw_sd, 1), 1e-6)],

    rrate_lower = variable_lookup[has_curve == 1L, rrate_lower],
    rrate_upper = variable_lookup[has_curve == 1L, rrate_upper],
    cvalue_lower = variable_lookup[has_curve == 1L, cvalue_lower],
    cvalue_upper = variable_lookup[has_curve == 1L, cvalue_upper],
    dvalue_lower = variable_lookup[has_curve == 1L, dvalue_lower],
    dvalue_upper = variable_lookup[has_curve == 1L, dvalue_upper],
    estimate_dvalue = as.integer(estimate_dvalue),
    normalize_curve_x = as.integer(normalize_curve_x),
    curve_normalization_active = as.integer(identical(curve_normalization_scope, "active_train")),
    center_predictors_for_sampling = as.integer(center_predictors_for_sampling),
    alpha_parameterization = as.integer(alpha_parameterization_code),
    G_alpha = if (alpha_parameterization_code == 3L) 0L else nrow(group_lookup),
    ucm_parameterization = as.integer(ucm_parameterization_code),

    alpha_mu_prior_mean = as.numeric(alpha_mu_prior_mean),
    alpha_mu_prior_sd = as.numeric(alpha_mu_prior_sd),
    alpha_sd_prior_sd = as.numeric(alpha_sd_prior_sd),
    level0_mu_prior_mean = as.numeric(level0_mu_prior_mean),
    level0_mu_prior_sd = as.numeric(level0_mu_prior_sd),
    level0_sd_prior_sd = as.numeric(level0_sd_prior_sd),
    sigma_level_prior_sd = as.numeric(sigma_level_prior_sd),
    season_sd_prior_sd = as.numeric(season_sd_prior_sd),
    cycle_sd_prior_sd = as.numeric(cycle_sd_prior_sd),
    gamma_prior_sd = as.numeric(gamma_prior_sd),
    sigma_y_prior_sd = as.numeric(sigma_y_prior_sd),
    sigma_y_floor = as.numeric(sigma_y_floor),
    sigma_y_upper = as.numeric(sigma_y_upper),
    likelihood_family = as.integer(likelihood_family),
    student_t_nu = as.numeric(student_t_nu),

    coef_mu_pos_log = if (length(pos_idx)) comp$pos$meanlog else numeric(),
    coef_sd_pos_log = if (length(pos_idx)) pmax(comp$pos$sdlog, 0.05) else numeric(),
    tau_scale_pos = if (length(pos_idx)) comp$pos$tau_scale else numeric(),
    sample_pos_hierarchy = block_sample_hierarchy(comp$pos$dt$variable),
    coef_hierarchy_mode_pos = block_hierarchy_mode(comp$pos$dt$variable),
    coef_centered_pos = block_centered_hierarchy(comp$pos$dt$variable),
    J_pos_hier = length(block_hier_positions(comp$pos$dt$variable)),
    pos_hier_pos = block_hier_positions(comp$pos$dt$variable),

    coef_mu_neg_log = if (length(neg_idx)) comp$neg$meanlog else numeric(),
    coef_sd_neg_log = if (length(neg_idx)) pmax(comp$neg$sdlog, 0.05) else numeric(),
    tau_scale_neg = if (length(neg_idx)) comp$neg$tau_scale else numeric(),
    sample_neg_hierarchy = block_sample_hierarchy(comp$neg$dt$variable),
    coef_hierarchy_mode_neg = block_hierarchy_mode(comp$neg$dt$variable),
    coef_centered_neg = block_centered_hierarchy(comp$neg$dt$variable),
    J_neg_hier = length(block_hier_positions(comp$neg$dt$variable)),
    neg_hier_pos = block_hier_positions(comp$neg$dt$variable),

    coef_mu_lower_log = if (length(lower_idx)) comp$lower$meanlog else numeric(),
    coef_sd_lower_log = if (length(lower_idx)) pmax(comp$lower$sdlog, 0.05) else numeric(),
    tau_scale_lower = if (length(lower_idx)) comp$lower$tau_scale else numeric(),
    sample_lower_hierarchy = block_sample_hierarchy(comp$lower$dt$variable),
    coef_hierarchy_mode_lower = block_hierarchy_mode(comp$lower$dt$variable),
    coef_centered_lower = block_centered_hierarchy(comp$lower$dt$variable),
    J_lower_hier = length(block_hier_positions(comp$lower$dt$variable)),
    lower_hier_pos = block_hier_positions(comp$lower$dt$variable),

    coef_mu_upper_log = if (length(upper_idx)) comp$upper$meanlog else numeric(),
    coef_sd_upper_log = if (length(upper_idx)) pmax(comp$upper$sdlog, 0.05) else numeric(),
    tau_scale_upper = if (length(upper_idx)) comp$upper$tau_scale else numeric(),
    sample_upper_hierarchy = block_sample_hierarchy(comp$upper$dt$variable),
    coef_hierarchy_mode_upper = block_hierarchy_mode(comp$upper$dt$variable),
    coef_centered_upper = block_centered_hierarchy(comp$upper$dt$variable),
    J_upper_hier = length(block_hier_positions(comp$upper$dt$variable)),
    upper_hier_pos = block_hier_positions(comp$upper$dt$variable),

    coef_raw_mu_bounded = if (length(bounded_idx)) comp$bounded$raw_mu else numeric(),
    coef_raw_sd_bounded = if (length(bounded_idx)) pmax(comp$bounded$raw_sd, 0.05) else numeric(),
    tau_scale_bounded = if (length(bounded_idx)) comp$bounded$tau_scale else numeric(),
    sample_bounded_hierarchy = block_sample_hierarchy(comp$bounded$dt$variable),
    coef_hierarchy_mode_bounded = block_hierarchy_mode(comp$bounded$dt$variable),
    coef_centered_bounded = block_centered_hierarchy(comp$bounded$dt$variable),
    J_bounded_hier = length(block_hier_positions(comp$bounded$dt$variable)),
    bounded_hier_pos = block_hier_positions(comp$bounded$dt$variable),

    coef_mu_free = if (length(free_idx)) comp$free$mean else numeric(),
    coef_sd_free = if (length(free_idx)) pmax(comp$free$sd, 0.05) else numeric(),
    tau_scale_free = if (length(free_idx)) comp$free$tau_scale else numeric(),
    sample_free_hierarchy = block_sample_hierarchy(comp$free$dt$variable),
    coef_hierarchy_mode_free = block_hierarchy_mode(comp$free$dt$variable),
    coef_centered_free = block_centered_hierarchy(comp$free$dt$variable),
    J_free_hier = length(block_hier_positions(comp$free$dt$variable)),
    free_hier_pos = block_hier_positions(comp$free$dt$variable),

    use_coef_overrides = as.integer(coef_overrides$use),
    coef_override_mu = coef_overrides$mu,
    coef_override_sd = coef_overrides$sd
  )

  # Prep-level Stan data contract checks catch mapping/dimension failures before compile/sampling.
  if (length(stan_data$group_id) != stan_data$N) stop("Internal error: group_id length does not equal N.")
  if (length(stan_data$is_train) != stan_data$N) stop("Internal error: is_train length does not equal N.")
  if (nrow(stan_data$group_coef_hierarchy_key_id) != stan_data$G || ncol(stan_data$group_coef_hierarchy_key_id) != stan_data$J) {
    stop("Internal error: group_coef_hierarchy_key_id dimensions do not match G/J.")
  }
  if (anyNA(stan_data$group_coef_hierarchy_key_id) || any(stan_data$group_coef_hierarchy_key_id < 1L | stan_data$group_coef_hierarchy_key_id > stan_data$K_coef_hierarchy_keys)) {
    stop("Internal error: invalid group_coef_hierarchy_key_id mapping.")
  }
  if (nrow(stan_data$X) != stan_data$N || ncol(stan_data$X) != stan_data$J) stop("Internal error: X dimensions do not match N/J.")
  if (nrow(stan_data$X_center_mean) != stan_data$G || ncol(stan_data$X_center_mean) != stan_data$J) stop("Internal error: X_center_mean dimensions do not match G/J.")
  if (nrow(stan_data$Z_extra) != stan_data$N || ncol(stan_data$Z_extra) != stan_data$K_extra) stop("Internal error: Z_extra dimensions do not match N/K_extra.")
  if (length(stan_data$curve_idx) != stan_data$J_curve) stop("Internal error: curve_idx length does not match J_curve.")
  if (length(stan_data$linear_idx) != stan_data$J_linear) stop("Internal error: linear_idx length does not match J_linear.")
  if (length(stan_data$curve_type) != stan_data$J_curve) stop("Internal error: curve_type length does not match J_curve.")
  if (length(stan_data$is_rf_curve) != stan_data$J_curve) stop("Internal error: is_rf_curve length does not match J_curve.")
  if (nrow(stan_data$X_rf_reach) != stan_data$N || ncol(stan_data$X_rf_reach) != stan_data$J_curve) stop("Internal error: X_rf_reach dimensions do not match N/J_curve.")
  if (nrow(stan_data$X_rf_frequency) != stan_data$N || ncol(stan_data$X_rf_frequency) != stan_data$J_curve) stop("Internal error: X_rf_frequency dimensions do not match N/J_curve.")
  if (nrow(stan_data$X_curve_fixed) != stan_data$N || ncol(stan_data$X_curve_fixed) != stan_data$J_curve) stop("Internal error: X_curve_fixed dimensions do not match N/J_curve.")
  if (nrow(stan_data$X_curve_fixed_center) != stan_data$G || ncol(stan_data$X_curve_fixed_center) != stan_data$J_curve) stop("Internal error: X_curve_fixed_center dimensions do not match G/J_curve.")
  if (length(stan_data$calibration_variable_idx) != stan_data$C_calibration) stop("Internal error: calibration_variable_idx length does not match C_calibration.")
  if (nrow(stan_data$calibration_weight) != stan_data$N || ncol(stan_data$calibration_weight) != stan_data$C_calibration) stop("Internal error: calibration_weight dimensions do not match N/C_calibration.")
  if (length(stan_data$calibration_observed_lift) != stan_data$C_calibration || length(stan_data$calibration_observed_sd) != stan_data$C_calibration) stop("Internal error: calibration evidence lengths do not match C_calibration.")
  if (length(stan_data$seq_effect_variable_idx) != stan_data$S_seq_effect ||
      length(stan_data$seq_effect_parent_idx) != stan_data$S_seq_effect ||
      nrow(stan_data$seq_effect_weight) != stan_data$N || ncol(stan_data$seq_effect_weight) != stan_data$S_seq_effect ||
      nrow(stan_data$seq_effect_child_share) != stan_data$P_seq_effect || ncol(stan_data$seq_effect_child_share) != stan_data$S_seq_effect) {
    stop("Internal error: sequential effectiveness transfer dimensions are inconsistent.")
  }
  if (length(stan_data$seq_adstock_curve_idx) != stan_data$S_seq_adstock ||
      length(stan_data$seq_adstock_parent_idx) != stan_data$S_seq_adstock) {
    stop("Internal error: sequential adstock transfer dimensions are inconsistent.")
  }
  if (length(dim(stan_data$collective_reconciliation_weight)) != 3L ||
      any(dim(stan_data$collective_reconciliation_weight) != c(stan_data$C_collective_reconciliation, stan_data$N, stan_data$J))) stop("Internal error: collective reconciliation weights do not match C/N/J.")
  if (length(stan_data$collective_parent_response) != stan_data$C_collective_reconciliation || length(stan_data$collective_parent_response_sd) != stan_data$C_collective_reconciliation) stop("Internal error: collective reconciliation evidence lengths do not match C_collective_reconciliation.")
  if (length(dim(stan_data$collective_shape_multiplier)) != 3L || any(dim(stan_data$collective_shape_multiplier) != c(stan_data$C_collective_shape, stan_data$N, stan_data$J))) stop("Internal error: collective shape multipliers do not match C/N/J.")
  if (length(dim(stan_data$collective_shape_weight)) != 3L || any(dim(stan_data$collective_shape_weight) != c(stan_data$C_collective_shape, stan_data$N, stan_data$J))) stop("Internal error: collective shape weights do not match C/N/J.")
  if (length(stan_data$collective_parent_shape) != stan_data$C_collective_shape || length(stan_data$collective_parent_reference_response) != stan_data$C_collective_shape || !identical(dim(stan_data$collective_parent_shape_cov), c(stan_data$C_collective_shape, stan_data$C_collective_shape))) stop("Internal error: collective shape target dimensions do not match C_collective_shape.")
  if (nrow(stan_data$X_context) != stan_data$N || ncol(stan_data$X_context) != stan_data$K_context) stop("Internal error: X_context dimensions do not match N/K_context.")
  if (length(stan_data$context_variable_idx) != stan_data$K_context) stop("Internal error: context_variable_idx length does not match K_context.")
  if (length(stan_data$context_coef_mu) != stan_data$K_context || length(stan_data$context_coef_sd) != stan_data$K_context) stop("Internal error: context coefficient prior lengths do not match K_context.")
  if (length(stan_data$context_sign) != stan_data$K_context) stop("Internal error: context_sign length does not match K_context.")
  if (length(stan_data$context_pos_pos) != stan_data$K_context_pos) stop("Internal error: context_pos_pos length does not match K_context_pos.")
  if (length(stan_data$context_neg_pos) != stan_data$K_context_neg) stop("Internal error: context_neg_pos length does not match K_context_neg.")
  if (length(stan_data$context_free_pos) != stan_data$K_context_free) stop("Internal error: context_free_pos length does not match K_context_free.")
  if (stan_data$K_context && any(stan_data$context_variable_idx < 1L | stan_data$context_variable_idx > stan_data$J)) stop("Internal error: invalid context_variable_idx values.")
  if (length(stan_data$sample_curve_parameter) != stan_data$J_curve) stop("Internal error: sample_curve_parameter length does not match J_curve.")
  if (length(stan_data$curve_sampled_pos) != stan_data$J_curve_sampled) stop("Internal error: curve_sampled_pos length does not match J_curve_sampled.")
  if (stan_data$J_curve_sampled && any(stan_data$curve_sampled_pos < 1L | stan_data$curve_sampled_pos > stan_data$J_curve)) stop("Internal error: invalid curve_sampled_pos values.")
  if (length(stan_data$use_observed_cvalue_prior) != stan_data$J_curve) stop("Internal error: use_observed_cvalue_prior length does not match J_curve.")
  if (length(stan_data$coef_centered_pos) != stan_data$J_pos) stop("Internal error: coef_centered_pos length does not match J_pos.")
  if (length(stan_data$coef_centered_neg) != stan_data$J_neg) stop("Internal error: coef_centered_neg length does not match J_neg.")
  if (length(stan_data$coef_centered_lower) != stan_data$J_lower) stop("Internal error: coef_centered_lower length does not match J_lower.")
  if (length(stan_data$coef_centered_upper) != stan_data$J_upper) stop("Internal error: coef_centered_upper length does not match J_upper.")
  if (length(stan_data$coef_centered_bounded) != stan_data$J_bounded) stop("Internal error: coef_centered_bounded length does not match J_bounded.")
  if (length(stan_data$coef_centered_free) != stan_data$J_free) stop("Internal error: coef_centered_free length does not match J_free.")
  if (length(stan_data$coef_hierarchy_mode_pos) != stan_data$J_pos) stop("Internal error: coef_hierarchy_mode_pos length does not match J_pos.")
  if (length(stan_data$coef_hierarchy_mode_neg) != stan_data$J_neg) stop("Internal error: coef_hierarchy_mode_neg length does not match J_neg.")
  if (length(stan_data$coef_hierarchy_mode_lower) != stan_data$J_lower) stop("Internal error: coef_hierarchy_mode_lower length does not match J_lower.")
  if (length(stan_data$coef_hierarchy_mode_upper) != stan_data$J_upper) stop("Internal error: coef_hierarchy_mode_upper length does not match J_upper.")
  if (length(stan_data$coef_hierarchy_mode_bounded) != stan_data$J_bounded) stop("Internal error: coef_hierarchy_mode_bounded length does not match J_bounded.")
  if (length(stan_data$coef_hierarchy_mode_free) != stan_data$J_free) stop("Internal error: coef_hierarchy_mode_free length does not match J_free.")
  if (length(stan_data$pos_hier_pos) != stan_data$J_pos_hier) stop("Internal error: pos_hier_pos length does not match J_pos_hier.")
  if (length(stan_data$neg_hier_pos) != stan_data$J_neg_hier) stop("Internal error: neg_hier_pos length does not match J_neg_hier.")
  if (length(stan_data$lower_hier_pos) != stan_data$J_lower_hier) stop("Internal error: lower_hier_pos length does not match J_lower_hier.")
  if (length(stan_data$upper_hier_pos) != stan_data$J_upper_hier) stop("Internal error: upper_hier_pos length does not match J_upper_hier.")
  if (length(stan_data$bounded_hier_pos) != stan_data$J_bounded_hier) stop("Internal error: bounded_hier_pos length does not match J_bounded_hier.")
  if (length(stan_data$free_hier_pos) != stan_data$J_free_hier) stop("Internal error: free_hier_pos length does not match J_free_hier.")
  if (stan_data$alpha_parameterization == 3L && stan_data$G_alpha != 0L) stop("Internal error: shared alpha mode must set G_alpha to 0.")
  if (stan_data$alpha_parameterization != 3L && stan_data$G_alpha != stan_data$G) stop("Internal error: centered/non-centered alpha mode must set G_alpha to G.")
  if (stan_data$J_curve + stan_data$J_linear != stan_data$J) stop("Internal error: J_curve + J_linear must equal J.")
  if (anyNA(stan_data$group_id) || any(stan_data$group_id < 1L | stan_data$group_id > stan_data$G)) stop("Internal error: invalid group_id mapping.")
  if (anyNA(stan_data$train_idx) || any(stan_data$train_idx < 1L | stan_data$train_idx > stan_data$N)) stop("Internal error: invalid train_idx mapping.")

  list(
    stan_data = stan_data,
    data = dt,
    metadata = md,
    curve_priors = variable_lookup[, .(
      variable, source_entity, role, has_curve, curve_type, curve_param_idx,
      rrate_raw_mu, rrate_raw_sd, cvalue_raw_mu, cvalue_raw_sd,
      use_observed_cvalue_prior, observed_cvalue_raw_mu, observed_cvalue_raw_sd,
      observed_cvalue_mu, observed_cvalue_reliability, observed_cvalue_source,
      anchor_saturation, anchor_saturation_sd, anchor_saturation_precision, anchor_source, cvalue_from_anchor,
      reach_col, frequency_col, population_col, rf_spend_col, rf_reach_train_scale,
